const conditionsExpanded = [{"id": "bleeding", "name": "Bleeding", "category": "Damage", "roles": ["Damage", "Tiered", "Physical"], "elements": ["Blood"], "mechanics": ["Constitution Save", "Healing Interaction", "Ends on Damage"], "duration": "1 minute", "intro": "A creature suffering from grievous wounds may begin to bleed profusely.", "summary": "A tiered wound condition that deals additional Blood damage the next time the creature takes damage.", "rules": ["When a creature gains Bleeding, it is assigned a Tier determined by the effect that caused it.", "When a creature takes damage while Bleeding, it suffers additional Blood damage based on its Bleeding Tier. After taking this damage, the condition ends.", "Bleeding lasts for 1 minute or until the creature uses its action to roll a Constitution saving throw against the Tier's DC. On a success, the condition ends.", "If the creature receives healing while Bleeding, it immediately makes the same Constitution saving throw. On a success, the condition ends.", "If Bleeding is reapplied while already active, its Tier increases by an amount equal to the Tier applied by the triggering attack.", "Creatures without blood are immune to Bleeding at the DM’s discretion."], "table": [["I", "5", "10"], ["II", "10", "12"], ["III", "15", "14"], ["IV", "20", "16"], ["V", "25", "18"], ["VI", "30", "20"], ["VII", "35", "22"], ["VIII", "40", "24"]], "tableHeaders": ["Tier", "Additional Damage", "Save DC"]}, {"id": "feebleminded", "name": "Feebleminded", "category": "Mental", "roles": ["Debuff", "Control", "Mental"], "elements": [], "mechanics": ["Intelligence Save", "No Reactions", "Spellcasting Disruption"], "duration": "1 minute", "intro": "A creature whose mind has been dulled or partially suppressed becomes Feebleminded.", "summary": "Suppresses speech, reactions, verbal components, and mental ability checks and saves.", "rules": ["The creature cannot speak clearly or perform verbal spell components.", "The creature cannot take reactions.", "The creature takes a –2 penalty to Intelligence, Wisdom, and Charisma ability checks and saving throws.", "A Feebleminded creature makes an Intelligence saving throw at the end of each of its turns, ending the condition on a success."]}, {"id": "soaked", "name": "Soaked", "category": "Elemental", "roles": ["Elemental", "Debuff", "Defense"], "elements": ["Water", "Cold", "Lightning", "Fire"], "mechanics": ["Vulnerability Setup", "Resistance", "Ends on Damage"], "duration": "1 minute", "intro": "A creature drenched in water becomes Soaked.", "summary": "Makes Cold and Lightning more dangerous, grants Fire resistance, and blocks Burning.", "rules": ["Creatures have disadvantage on saving throws against spells and effects that deal Cold or Lightning damage, and spell attack rolls of those types have advantage against Soaked creatures.", "When a creature takes Cold or Lightning damage, any damage die that rolls a 1 or 2 is rerolled once.", "The creature has resistance to Fire damage and is immune to the Burning condition.", "Soaked ends early if the creature is hit with Fire, Cold, or Lightning damage."]}, {"id": "chilled", "name": "Chilled", "category": "Elemental", "roles": ["Control", "Elemental", "Debuff"], "elements": ["Cold", "Fire"], "mechanics": ["Movement Reduction", "Strength Save", "Dexterity Save"], "duration": "Until ended", "intro": "A creature exposed to Cold or frost magic may become Chilled.", "summary": "Reduces speed and weakens Strength and Dexterity checks and saves.", "rules": ["If a creature takes Cold damage while Soaked, it becomes Chilled.", "The Chilled condition ends immediately if the creature is Burning or takes Fire damage.", "Creatures with immunity to Cold damage cannot be Chilled.", "While Chilled, a creature’s speed is reduced by 10 feet and it has disadvantage on Strength and Dexterity ability checks and saving throws."]}, {"id": "frozen", "name": "Frozen", "category": "Elemental", "roles": ["Control", "Elemental", "Defense"], "elements": ["Cold", "Fire", "Thunder", "Bludgeoning"], "mechanics": ["Speed 0", "Auto-Fail Dexterity Saves", "Vulnerability", "Immunity"], "duration": "Until ended", "intro": "Spells with extreme Cold magic may inflict the Frozen condition.", "summary": "Locks movement, causes failed Dexterity saves, and changes key damage interactions.", "rules": ["Creatures have their speed reduced to 0 and automatically fail Dexterity saving throws.", "Creatures have vulnerability to Thunder and Bludgeoning damage.", "Creatures have immunity to Fire damage."]}, {"id": "corroded", "name": "Corroded", "category": "Armor", "roles": ["Defense", "Debuff", "Elemental"], "elements": ["Acid"], "mechanics": ["AC Penalty", "Constitution Save"], "duration": "Until removed", "intro": "A creature covered by Acid might have its armor Corroded.", "summary": "Weakens metal armor or natural armor defenses.", "rules": ["Creatures wearing metal armor have their AC reduced by 2.", "Creatures with natural armor have a –2 penalty on Constitution saving throws."]}, {"id": "sapped", "name": "Sapped", "category": "Vitality", "roles": ["Debuff", "Healing"], "elements": [], "mechanics": ["Reduced Healing"], "duration": "1 minute", "intro": "A creature whose vitality is drained becomes Sapped.", "summary": "Reduces healing received by half.", "rules": ["A Sapped creature regains half the normal amount of hit points from any healing effect, rounded down."]}, {"id": "burning", "name": "Burning", "category": "Elemental", "roles": ["Damage", "Tiered", "Elemental"], "elements": ["Fire", "Water"], "mechanics": ["Concentration Penalty", "End of Turn Damage", "Action to End"], "duration": "1 minute", "intro": "A creature engulfed in flames may suffer the Burning condition.", "summary": "A tiered Fire condition that damages creatures at the end of their turns and disrupts concentration.", "rules": ["Burning lasts for 1 minute or until the creature becomes Soaked or uses an action to put out the fire.", "A Burning creature has disadvantage on Concentration saving throws and takes Fire damage at the end of its turns.", "Creatures with immunity to Fire damage cannot be Burned."], "table": [["I", "4"], ["II", "6"], ["III", "8"], ["IV", "10"]], "tableHeaders": ["Tier", "Damage"]}];

