function loadFavorites() {
  try {
    favorites = JSON.parse(localStorage.getItem(FAVORITES_KEY)) || {};
  } catch {
    favorites = {};
  }
}

function saveFavorites() {
  localStorage.setItem(FAVORITES_KEY, JSON.stringify(favorites));
}

function favoriteKey(type, id) {
  return `${type}:${id}`;
}

function isFavorite(type, id) {
  return Boolean(favorites[favoriteKey(type, id)]);
}

function createFavoriteButton(type, id, label) {
  const key = favoriteKey(type, id);
  const active = isFavorite(type, id);
  return `<button class="favorite-button ${active ? "is-favorite" : ""}" type="button" data-favorite-type="${escapeHTML(type)}" data-favorite-id="${escapeHTML(id)}" data-favorite-label="${escapeHTML(label || id)}" data-favorite-key="${escapeHTML(key)}" aria-label="${active ? "Remove from favorites" : "Add to favorites"}" title="${active ? "Remove from favorites" : "Add to favorites"}">★</button>`;
}

function updateFavoriteButtons(key) {
  document.querySelectorAll(".favorite-button").forEach(button => {
    if (button.dataset.favoriteKey !== key) return;
    const active = Boolean(favorites[key]);
    button.classList.toggle("is-favorite", active);
    button.setAttribute("aria-label", active ? "Remove from favorites" : "Add to favorites");
    button.title = active ? "Remove from favorites" : "Add to favorites";
  });
}

function bindFavoriteButtons(scope = document) {
  scope.querySelectorAll(".favorite-button").forEach(button => {
    if (button.dataset.favoriteBound) return;
    button.dataset.favoriteBound = "true";
    button.addEventListener("click", event => {
      event.preventDefault();
      event.stopPropagation();
      const type = button.dataset.favoriteType;
      const id = button.dataset.favoriteId;
      const label = button.dataset.favoriteLabel || id;
      const key = favoriteKey(type, id);

      if (favorites[key]) delete favorites[key];
      else favorites[key] = { type, id, label, savedAt: new Date().toISOString() };

      saveFavorites();
      updateFavoriteButtons(key);
      button.classList.remove("just-favorited");
      void button.offsetWidth;
      button.classList.add("just-favorited");
      window.setTimeout(() => button.classList.remove("just-favorited"), 520);

      renderHomeSearch();
      if (type === "tactic" && tacticFavoritesOnly) renderTree();
      if (type === "spell" && spellFavoritesOnly) renderSpells();
      if (type === "gear" && gearFavoritesOnly) renderGear();
      if (type === "weapon" && weaponFavoritesOnly) renderWeapons();
      if (type === "condition" && conditionFavoritesOnly) renderConditions();

      showToast(favorites[key] ? `${label} added to favorites.` : `${label} removed from favorites.`);
    });
  });
}

const DAMAGE_KEYWORDS = ["acid", "bludgeoning", "cold", "fire", "force", "lightning", "necrotic", "piercing", "poison", "psychic", "radiant", "slashing", "thunder", "blood"];

function spellRuleTypesFor(spellName) {
  return spellRuleNotes
    .filter(note => (note.spells || []).some(name => normalizeSearchText(name) === normalizeSearchText(spellName)))
    .flatMap(note => [note.type, note.title, note.description, `${note.levelLabel || note.level} rule change`])
    .filter(Boolean);
}

function extractDamageKeywords(text) {
  const normalized = normalizeSearchText(text || "");
  return DAMAGE_KEYWORDS.filter(type => normalized.includes(type));
}

function getSpellSearchKeywords(spell) {
  const ruleTypes = spellRuleTypesFor(spell.name);
  const damageTypes = extractDamageKeywords([spell.description, spell.summary, spell.tags?.join(" ")].join(" "));
  const casting = normalizeSearchText(spell.casting || "");
  const duration = normalizeSearchText(spell.duration || "");
  const description = normalizeSearchText(spell.description || "");

  const keywords = new Set([
    "spell",
    `level ${spell.level}`,
    `${spell.level} level`,
    `${spell.levelLabel || ""} level`,
    spell.school,
    `school ${spell.school}`,
    spell.casting,
    spell.range,
    spell.duration,
    ...(spell.classLists || []),
    ...(spell.tags || []),
    ...ruleTypes,
    ...damageTypes,
    ...damageTypes.map(type => `${type} damage`),
    ...damageTypes.map(type => `damage type ${type}`)
  ].filter(Boolean));

  if (casting.includes("bonus")) keywords.add("bonus action");
  if (casting.includes("reaction")) keywords.add("reaction");
  if (casting.includes("action")) keywords.add("action");
  if (duration.includes("concentration") || description.includes("concentration")) keywords.add("concentration");
  if (ruleTypes.some(type => normalizeSearchText(type).includes("no concentration"))) {
    keywords.add("no concentration");
    keywords.add("concentration");
  }
  if (ruleTypes.some(type => normalizeSearchText(type).includes("ritual")) || description.includes("ritual")) {
    keywords.add("ritual");
  }
  if (description.includes("saving throw")) keywords.add("saving throw");
  if (description.includes("attack roll")) keywords.add("attack roll");
  if (description.includes("area") || description.includes("cone") || description.includes("sphere") || description.includes("cube")) keywords.add("area");

  return [...keywords].join(" ");
}

function getGearSearchKeywords(upgrade) {
  const tierRoman = romanTier(Number(upgrade.tier));
  return [
    "gear",
    "upgrade",
    upgrade.type,
    `type ${upgrade.type}`,
    `gear type ${upgrade.type}`,
    `tier ${upgrade.tier}`,
    `tier ${tierRoman}`,
    `upgrade tier ${upgrade.tier}`,
    `upgrade tier ${tierRoman}`,
    ...(upgrade.tags || [])
  ].join(" ");
}

function getWeaponSearchKeywords(weapon) {
  const damageTypes = extractDamageKeywords([weapon.damage, weapon.damageType, weapon.abilityText].join(" "));
  const categoryText = normalizeSearchText(weapon.category || "");
  const keywords = new Set([
    "weapon",
    weapon.collection,
    weapon.category,
    weapon.mode,
    weapon.weaponType,
    `weapon type ${weapon.weaponType}`,
    `type ${weapon.weaponType}`,
    weapon.damageType,
    `damage type ${weapon.damageType}`,
    weapon.damage,
    ...damageTypes,
    ...damageTypes.map(type => `${type} damage`),
    ...damageTypes.map(type => `damage type ${type}`),
    ...(weapon.properties || []),
    ...(weapon.traits || []),
    ...getWeaponRoleTags(weapon)
  ].filter(Boolean));

  if (categoryText.includes("simple")) keywords.add("simple");
  if (categoryText.includes("martial")) keywords.add("martial");
  if (categoryText.includes("melee")) keywords.add("melee");
  if (categoryText.includes("ranged")) keywords.add("ranged");
  if (categoryText.includes("simple melee")) keywords.add("simple melee");
  if (categoryText.includes("martial melee")) keywords.add("martial melee");
  if (categoryText.includes("martial ranged")) keywords.add("martial ranged");

  return [...keywords].join(" ");
}

function getConditionSearchKeywords(condition) {
  return [
    "condition",
    condition.category,
    `condition type ${condition.category}`,
    ...(condition.roles || []),
    ...(condition.elements || []),
    ...(condition.mechanics || []),
    ...getConditionTypeFilters(condition),
    ...getConditionTypeFilters(condition).map(type => `condition type ${type}`),
    ...getConditionMechanicFilters(condition)
  ].join(" ");
}

function getTacticSearchKeywords(tactic) {
  const categoriesForTactic = tacticCategories[tactic.id] || [];
  const labels = categoriesForTactic.map(id => categories.find(category => category.id === id)?.label || id);
  const actionTags = tacticActionTags[tactic.id] || [];
  return [
    "war tactic",
    "martial tactic",
    tierInfo[tactic.tier]?.label,
    `tier ${tactic.tier}`,
    `tier ${romanTier ? romanTier(tactic.tier) : tactic.tier}`,
    ...categoriesForTactic,
    ...labels,
    ...labels.map(label => `category ${label}`),
    ...actionTags,
    ...(tactic.aliases || [])
  ].join(" ");
}

function getGlobalSearchItems() {
  const tacticItems = tactics.map(tactic => ({
    type: "tactic",
    id: tactic.id,
    page: "war",
    title: tactic.name,
    meta: `War Tactic · ${tierInfo[tactic.tier]?.label || `Tier ${tactic.tier}`}`,
    text: `${tactic.summary || ""} ${stripHTML(tactic.text || "")} ${(tacticActionTags[tactic.id] || []).join(" ")} ${(tacticCategories[tactic.id] || []).join(" ")} ${getTacticSearchKeywords(tactic)}`
  }));

  const spellItems = spellsRebalanced.map(spell => ({
    type: "spell",
    id: spell.id,
    page: "spells",
    title: spell.name,
    meta: `Spell · Level ${spell.level} · ${spell.school}`,
    text: `${spell.casting || ""} ${spell.range || ""} ${spell.duration || ""} ${spell.description || ""} ${(spell.classLists || []).join(" ")} ${(spell.tags || []).join(" ")} ${getSpellSearchKeywords(spell)}`
  }));

  const gearItems = gearUpgrades.map(item => ({
    type: "gear",
    id: item.id,
    page: "gear",
    title: item.name,
    meta: `Gear Upgrade · ${item.type} · Tier ${romanTier(item.tier)}`,
    text: `${item.summary || ""} ${item.text || ""} ${(item.tags || []).join(" ")} ${getGearSearchKeywords(item)}`
  }));

  const weaponItems = weaponsExpanded.map(weapon => ({
    type: "weapon",
    id: weapon.id,
    page: "weapons",
    title: weapon.name,
    meta: `Weapon · ${weapon.category} · ${weapon.damage}`,
    text: `${weapon.weaponType || ""} ${weapon.mode || ""} ${weapon.damageType || ""} ${weapon.abilityName || ""} ${weapon.abilityText || ""} ${(weapon.properties || []).join(" ")} ${getWeaponRoleTags(weapon).join(" ")} ${getWeaponSearchKeywords(weapon)}`
  }));

  const conditionItems = conditionsExpanded.map(condition => ({
    type: "condition",
    id: condition.id,
    page: "conditions",
    title: condition.name,
    meta: `Condition · ${condition.category} · ${condition.duration}`,
    text: `${condition.intro || ""} ${condition.summary || ""} ${(condition.rules || []).join(" ")} ${(condition.elements || []).join(" ")} ${getConditionTypeFilters(condition).join(" ")} ${getConditionMechanicFilters(condition).join(" ")} ${getConditionSearchKeywords(condition)}`
  }));

  const characterItems = [{
    type: "character",
    id: "character-creator",
    page: "character",
    title: "Character Creator",
    meta: "Character Sheet · 2024-style builder",
    text: `${characterState.name || ""} ${characterState.className || ""} ${characterState.species || ""} ${characterState.background || ""} abilities saving throws skills AC HP initiative spells equipment features`
  }];

  return [...tacticItems, ...spellItems, ...conditionItems, ...gearItems, ...weaponItems, ...characterItems];
}

function renderHomeSearch() {
  if (!els.homeSearchResults) return;

  const query = normalizeSearchText(els.homeGlobalSearchInput?.value || "");
  if (els.homeFavoritesToggle) els.homeFavoritesToggle.classList.toggle("is-active", homeFavoritesOnly);
  renderHomeActiveFilters();

  let items = getGlobalSearchItems().filter(item => {
    if (homeFavoritesOnly && !isFavorite(item.type, item.id)) return false;
    if (!query) return homeFavoritesOnly;
    const searchable = `${item.title} ${item.meta} ${item.text}`;
    return normalizeSearchText(searchable).includes(query) || fuzzyTitleMatch(item.title, query);
  });

  items = items.slice(0, 36);
  els.homeSearchResults.innerHTML = "";

  if (!query && !homeFavoritesOnly) {
    els.homeSearchResults.innerHTML = `<p class="home-search-empty">Search anything in the compendium, or press ★ Favorites to show your pinned rules.</p>`;
    return;
  }

  if (!items.length) {
    els.homeSearchResults.innerHTML = `<p class="home-search-empty">No matching ${homeFavoritesOnly ? "favorite " : ""}entries found.</p>`;
    return;
  }

  items.forEach(item => {
    const card = document.createElement("article");
    card.className = `home-result-card home-result-card--${item.type}`;
    card.innerHTML = `
      <div>
        <span>${escapeHTML(item.meta)}</span>
        <strong>${escapeHTML(item.title)}</strong>
        <p>${escapeHTML(String(item.text || "").slice(0, 170))}${String(item.text || "").length > 170 ? "…" : ""}</p>
      </div>
      <div class="home-result-actions">
        ${createFavoriteButton(item.type, item.id, item.title)}
        <button class="button button--ghost home-result-open" type="button">Open</button>
      </div>
    `;
    card.querySelector(".home-result-open").addEventListener("click", () => setActivePage(item.page));
    bindFavoriteButtons(card);
    els.homeSearchResults.append(card);
  });
}

function openSpotlightSearch() {
  if (!els.spotlightOverlay || !els.spotlightSearchInput) return;
  closeAllMultiPickers();
  els.spotlightOverlay.classList.remove("hidden");
  document.body.classList.add("is-spotlight-open");
  els.spotlightSearchInput.value = "";
  renderSpotlightResults();
  window.setTimeout(() => els.spotlightSearchInput.focus(), 30);
}

function closeSpotlightSearch() {
  if (!els.spotlightOverlay) return;
  els.spotlightOverlay.classList.add("hidden");
  document.body.classList.remove("is-spotlight-open");
}

function renderSpotlightResults() {
  if (!els.spotlightResults) return;
  const query = normalizeSearchText(els.spotlightSearchInput?.value || "");
  els.spotlightResults.innerHTML = "";

  if (!query) {
    els.spotlightResults.innerHTML = `
      <div class="spotlight-empty">
        <strong>Search the whole compendium</strong>
        <p>Try “fire damage”, “bonus action”, “tier II”, “melee”, “condition type damage”, “concentration”, or a specific rule name.</p>
      </div>
    `;
    return;
  }

  const items = getGlobalSearchItems()
    .filter(item => {
      const searchable = `${item.title} ${item.meta} ${item.text}`;
      return normalizeSearchText(searchable).includes(query) || fuzzyTitleMatch(item.title, query);
    })
    .slice(0, 18);

  if (!items.length) {
    els.spotlightResults.innerHTML = `
      <div class="spotlight-empty">
        <strong>No results found</strong>
        <p>Try a broader term, damage type, action type, tier, condition type, or weapon category.</p>
      </div>
    `;
    return;
  }

  items.forEach((item, index) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = `spotlight-result spotlight-result--${item.type}`;
    button.innerHTML = `
      <span class="spotlight-result__type">${escapeHTML(item.meta)}</span>
      <strong>${escapeHTML(item.title)}</strong>
      <small>${escapeHTML(String(item.text || "").slice(0, 150))}${String(item.text || "").length > 150 ? "…" : ""}</small>
      <em>${index === 0 ? "↵" : ""}</em>
    `;
    button.addEventListener("click", () => openSpotlightResult(item));
    els.spotlightResults.append(button);
  });
}

function openSpotlightResult(item) {
  closeSpotlightSearch();
  setActivePage(item.page);

  window.setTimeout(() => {
    if (item.page === "war" && els.searchInput) {
      els.searchInput.value = item.title;
      renderTree();
    } else if (item.page === "spells" && els.spellSearchInput) {
      els.spellSearchInput.value = item.title;
      renderSpells();
    } else if (item.page === "gear" && els.gearSearchInput) {
      els.gearSearchInput.value = item.title;
      renderGear();
    } else if (item.page === "weapons") {
      const input = document.getElementById("weaponSearchInput");
      if (input) {
        input.value = item.title;
        renderWeapons();
      }
    } else if (item.page === "conditions") {
      const input = document.getElementById("conditionSearchInput");
      if (input) {
        input.value = item.title;
        renderConditions();
      }
    }
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, 0);
}

function toggleCollapsibleSet(section, collapsedSet, key, renderFn) {
  const content = section?.querySelector(
    ".spell-card-grid, .gear-card-grid, .weapon-card-grid, .condition-card-grid"
  );

  const willCollapse = !collapsedSet.has(key);

  if (!content) {
    if (willCollapse) collapsedSet.add(key);
    else collapsedSet.delete(key);
    section?.classList.toggle("is-collapsed", willCollapse);
    return;
  }

  const button = section.querySelector(".category-toggle");
  if (button) button.setAttribute("aria-expanded", String(!willCollapse));

  const currentHeight = content.scrollHeight;
  section.classList.add("is-collapsing-now");
  content.style.overflow = "hidden";
  content.style.maxHeight = `${currentHeight}px`;
  content.style.opacity = "1";
  content.style.transform = "translateY(0)";

  if (willCollapse) {
    collapsedSet.add(key);
    requestAnimationFrame(() => {
      section.classList.add("is-collapsed");
      content.style.maxHeight = "0px";
      content.style.opacity = "0";
      content.style.transform = "translateY(-4px)";
    });
  } else {
    collapsedSet.delete(key);
    section.classList.remove("is-collapsed");
    content.style.maxHeight = "0px";
    content.style.opacity = "0";
    content.style.transform = "translateY(-4px)";
    requestAnimationFrame(() => {
      content.style.maxHeight = `${content.scrollHeight}px`;
      content.style.opacity = "1";
      content.style.transform = "translateY(0)";
    });
  }

  window.setTimeout(() => {
    section.classList.remove("is-collapsing-now");
    content.style.removeProperty("overflow");
    content.style.removeProperty("max-height");
    content.style.removeProperty("opacity");
    content.style.removeProperty("transform");
  }, 260);
}

function refreshFavoriteFilterButtons() {
  if (els.spellFavoritesToggle) els.spellFavoritesToggle.classList.toggle("is-active", spellFavoritesOnly);
  if (els.gearFavoritesToggle) els.gearFavoritesToggle.classList.toggle("is-active", gearFavoritesOnly);
  if (els.weaponFavoritesToggle) els.weaponFavoritesToggle.classList.toggle("is-active", weaponFavoritesOnly);
  if (els.conditionFavoritesToggle) els.conditionFavoritesToggle.classList.toggle("is-active", conditionFavoritesOnly);
}

const pageNavigationOptions = [
  { id: "war", label: "War Tactics", icon: "⚔" },
  { id: "spells", label: "Spells Rebalanced", icon: "✦" },
  { id: "conditions", label: "Conditions Expanded", icon: "◈" },
  { id: "gear", label: "Upgraded Gear", icon: "◆" },
  { id: "weapons", label: "Weapons Expanded", icon: "🗡" },
  { id: "character", label: "Character Creator", icon: "◎" }
];

function getCurrentPageLabel() {
  const current = pageNavigationOptions.find(item => item.id === activePage);
  return current ? current.label : "Choose Page";
}

function renderTopPagePicker() {
  if (!els.topPagePicker || !els.topPageMenu || !els.topPageLabel) return;

  const isHome = activePage === "home";
  els.topPagePicker.classList.toggle("hidden", isHome);
  els.topPageLabel.textContent = getCurrentPageLabel();
  els.topPageMenu.innerHTML = "";

  pageNavigationOptions.forEach(page => {
    const selected = page.id === activePage;
    const button = document.createElement("button");
    button.type = "button";
    button.className = `multi-picker__option top-page-picker__option ${selected ? "is-selected" : ""}`;
    button.innerHTML = `<span><i class="top-page-picker__icon" aria-hidden="true">${page.icon}</i>${escapeHTML(page.label)}</span><em>${selected ? "✓" : ""}</em>`;
    button.addEventListener("click", event => {
      event.stopPropagation();
      closeAllMultiPickers();
      setActivePage(page.id);
    });
    els.topPageMenu.append(button);
  });
}

function isCurrentPageDmModeActive() {
  if (activePage === "war") return dmEditMode;
  if (activePage === "spells") return spellDmEditMode;
  if (activePage === "gear") return gearDmEditMode;
  if (activePage === "weapons") return weaponDmEditMode;
  if (activePage === "conditions") return conditionDmEditMode;
  return false;
}

function refreshGlobalDmButton() {
  if (!els.pageDmModeButton) return;
  const isHome = activePage === "home";
  const active = isCurrentPageDmModeActive();
  els.pageDmModeButton.classList.toggle("hidden", isHome);
  els.pageDmModeButton.classList.toggle("is-active", active);
  els.pageDmModeButton.textContent = active ? "Exit DM Mode" : "DM Mode";
}

function toggleCurrentPageDmMode() {
  if (activePage === "war") return toggleDmEditMode();
  if (activePage === "spells") return toggleSpellDmEditMode();
  if (activePage === "gear") return toggleGearDmEditMode();
  if (activePage === "weapons") return toggleWeaponDmEditMode();
  if (activePage === "conditions") return toggleConditionDmEditMode();
}

function setActivePage(page) {
  activePage = ["home", "war", "spells", "gear", "weapons", "conditions", "character"].includes(page) ? page : "home";
  renderMasterPage();
}

function renderMasterPage() {
  const isHome = activePage === "home";
  const isWar = activePage === "war";
  const isSpells = activePage === "spells";
  const isGear = activePage === "gear";
  const isWeapons = activePage === "weapons";
  const isConditions = activePage === "conditions";
  const isCharacter = activePage === "character";

  document.body.classList.toggle("is-home-page", isHome);

  els.warTacticsPage.classList.toggle("is-active", isWar);
  els.spellsPage.classList.toggle("is-active", isSpells);
  els.gearPage.classList.toggle("is-active", isGear);

  const weaponsPage = document.getElementById("weaponsPage");
  if (weaponsPage) weaponsPage.classList.toggle("is-active", isWeapons);

  const conditionsPage = document.getElementById("conditionsPage");
  if (conditionsPage) conditionsPage.classList.toggle("is-active", isConditions);
  if (els.characterPage) els.characterPage.classList.toggle("is-active", isCharacter);

  els.navWarTactics.classList.toggle("is-active", isWar);
  els.navSpells.classList.toggle("is-active", isSpells);
  els.navGear.classList.toggle("is-active", isGear);

  const navWeapons = document.getElementById("navWeapons");
  if (navWeapons) navWeapons.classList.toggle("is-active", isWeapons);

  const navConditions = document.getElementById("navConditions");
  if (navConditions) navConditions.classList.toggle("is-active", isConditions);
  if (els.navCharacter) els.navCharacter.classList.toggle("is-active", isCharacter);

  if (els.homeButton) {
    els.homeButton.classList.toggle("is-active", isHome);
    els.homeButton.classList.toggle("hidden", isHome);
  }

  els.pageTitle.textContent = isHome ? "Homebrew Compendium" : isGear ? "Upgraded Gear" : isSpells ? "Spells Rebalanced" : isWeapons ? "Weapons Expanded" : isConditions ? "Conditions Expanded" : isCharacter ? "Character Creator" : "War Tactics";
  if (els.heroText) {
    els.heroText.textContent = isHome
      ? "A master home for your campaign rules, martial tactics, spell revisions, gear upgrades, expanded weapons, and custom conditions."
      : isGear
        ? "Browse upgrade options, open crafting rules, and use the upgrade calculator."
        : isSpells
          ? "Browse rebalanced spells by level, school, class list, and rule-change notes."
          : isWeapons
            ? "Browse expanded weapon options by category, combat role, and damage type."
            : isConditions
              ? "Browse expanded combat states, tiered effects, elements, and rule hooks."
              : isCharacter
                ? "Build a 2024-style character sheet with origin, abilities, saves, skills, combat, spells, equipment, and notes."
                : "Track martial paths, standalone tactics, prerequisites, and character choices.";
  }

  if (isHome) renderHomeSearch();
  if (isSpells) renderSpells();
  if (isGear) renderGear();
  if (isWeapons) renderWeapons();
  if (isConditions) renderConditions();
  if (isCharacter) renderCharacterCreator();
  renderTopPagePicker();
  refreshGlobalDmButton();
}

function bindDialogDismissals() {
  document.querySelectorAll("[data-close-dialog]").forEach(button => {
    button.addEventListener("click", () => {
      const dialog = document.getElementById(button.dataset.closeDialog);
      if (dialog) dialog.close();
    });
  });

  document.querySelectorAll("dialog").forEach(dialog => {
    dialog.addEventListener("mousedown", event => {
      if (event.target === dialog) dialog.close();
    });
  });
}

