function renderGearRuleCategoryOption(value, label) {
  const selected = activeGearRuleCategory === value;
  return `
    <button type="button" class="multi-picker__option ${selected ? "is-selected" : ""}" data-rule-category="${value}">
      <span><i class="multi-picker__dot" aria-hidden="true"></i>${escapeHTML(label)}</span>
      <em>${selected ? "✓" : ""}</em>
    </button>
  `;
}

function getGearRuleCategory(category) {
  const categories = {
    cost: {
      number: "01",
      label: "Cost",
      description: "Final Cost = Upgrade Cost + Gear Rarity Cost.",
      tables: [
        { title: "Upgrade Cost", rows: gearRules.upgradeCosts },
        { title: "Gear Rarity Cost", rows: gearRules.rarityCosts }
      ]
    },
    dc: {
      number: "02",
      label: "Crafting DC",
      description: "Crafting DC = Item Rarity DC + Upgrade Tier DC.",
      tables: [
        { title: "Rarity DC", rows: gearRules.rarityDC },
        { title: "Tier DC", rows: gearRules.tierDC }
      ]
    },
    time: {
      number: "03",
      label: "Crafting Time",
      description: "Crafting Time = Item Rarity Time + Upgrade Tier Time.",
      tables: [
        { title: "Tier Time", rows: gearRules.tierTime },
        { title: "Rarity Time", rows: gearRules.rarityTime }
      ]
    }
  };

  return categories[category] || categories.cost;
}

function bindGearRuleCategoryPicker() {
  const picker = document.getElementById("gearRuleCategoryPicker");
  const button = document.getElementById("gearRuleCategoryButton");
  const menu = document.getElementById("gearRuleCategoryMenu");
  if (!picker || !button || !menu) return;

  button.addEventListener("click", event => {
    event.stopPropagation();
    const wasOpen = picker.classList.contains("is-open");
    closeAllMultiPickers();
    picker.classList.toggle("is-open", !wasOpen);
    button.setAttribute("aria-expanded", String(!wasOpen));
  });

  menu.querySelectorAll("[data-rule-category]").forEach(option => {
    option.addEventListener("click", event => {
      event.stopPropagation();
      activeGearRuleCategory = option.dataset.ruleCategory || "cost";
      picker.classList.remove("is-open");
      button.setAttribute("aria-expanded", "false");
      renderGearRulesDialogContent();
    });
  });

  document.addEventListener("click", event => {
    if (!picker.contains(event.target)) {
      picker.classList.remove("is-open");
      button.setAttribute("aria-expanded", "false");
    }
  }, { once: true });
}

