function gearMatchesFilters(upgrade) {
  if (gearFavoritesOnly && !isFavorite("gear", upgrade.id)) return false;
  const query = normalizeSearchText(els.gearSearchInput.value || "");
  if (query) {
    const searchable = [
      upgrade.name,
      upgrade.type,
      `tier ${upgrade.tier}`,
      ...(upgrade.tags || []),
      upgrade.summary,
      upgrade.text,
      getGearSearchKeywords(upgrade)
    ].join(" ");
    if (!normalizeSearchText(searchable).includes(query) && !fuzzyTitleMatch(upgrade.name, query)) return false;
  }

  if (gearActiveTypes.size > 0 && !gearActiveTypes.has(upgrade.type)) return false;
  if (gearActiveTiers.size > 0 && !gearActiveTiers.has(String(upgrade.tier))) return false;
  return true;
}

function renderGearUpgrades() {
  const filtered = gearUpgrades.filter(gearMatchesFilters);
  els.gearResultsInfo.textContent = `${filtered.length} of ${gearUpgrades.length} upgrades shown`;

  els.gearCards.innerHTML = "";
  const types = ["Armor", "Weapon"];
  types.forEach(type => {
    const typeItems = filtered.filter(item => item.type === type);
    if (!typeItems.length) return;

    const section = document.createElement("section");
    section.className = "gear-type-section";
    section.innerHTML = `<h3>${type === "Armor" ? "Armor Reinforcements" : "Weapon Refinements"}</h3>`;

    [1, 2, 3].forEach(tier => {
      const tierItems = typeItems.filter(item => item.tier === tier);
      if (!tierItems.length) return;

      const tierKey = `${type}-${tier}`;
      const isCollapsed = collapsedGearTiers.has(tierKey);
      const tierSection = document.createElement("section");
      tierSection.className = `gear-tier-section ${isCollapsed ? "is-collapsed" : ""}`;
      tierSection.innerHTML = `
        <div class="gear-tier-heading">
          <div class="collapsible-heading-title">
            <button class="category-toggle" type="button" aria-expanded="${String(!isCollapsed)}" aria-label="${isCollapsed ? "Expand" : "Collapse"} ${type} Tier ${romanTier(tier)} upgrades">
              <span class="category-toggle__arrow" aria-hidden="true">▾</span>
            </button>
            <h4>Tier ${romanTier(tier)}</h4>
          </div>
          <span>${tierItems.length} ${tierItems.length === 1 ? "upgrade" : "upgrades"}</span>
        </div>
        <div class="gear-card-grid"></div>
      `;

      const toggleButton = tierSection.querySelector(".category-toggle");
      toggleButton.addEventListener("click", () => {
        toggleCollapsibleSet(tierSection, collapsedGearTiers, tierKey, renderGearUpgrades);
      });

      const grid = tierSection.querySelector(".gear-card-grid");
      tierItems.forEach(item => grid.append(renderGearCard(item)));
      section.append(tierSection);
    });

    els.gearCards.append(section);
  });

  if (!filtered.length) {
    els.gearCards.innerHTML = `<div class="empty-state panel"><h3>No upgrades found</h3><p>Try another search, type, or tier filter.</p></div>`;
  }
}

function renderGearCard(item) {
  const card = document.createElement("article");
  card.className = `gear-card gear-card--${item.type.toLowerCase()}`;
  card.innerHTML = `
    <header>
      <div>
        <h4>${escapeHTML(item.name)}</h4>
        <div class="gear-tag-row">
          <span class="gear-tag gear-tag--type">${escapeHTML(item.type)}</span>
          <span class="gear-tag gear-tag--tier">Tier ${romanTier(item.tier)}</span>
          ${(item.tags || []).map(tag => `<span class="gear-tag">${escapeHTML(tag)}</span>`).join("")}
        </div>
      </div>
      ${createFavoriteButton("gear", item.id, item.name)}
    </header>
    <div class="card-hierarchy-row">
      <span>${escapeHTML(item.type)}</span>
      <span>Tier ${romanTier(item.tier)}</span>
      ${(item.tags || []).slice(0, 3).map(tag => `<span>${escapeHTML(tag)}</span>`).join("")}
    </div>
    <p class="gear-summary">${highlightGameTerms(item.summary || "")}</p>
    <div class="gear-text">${gearTextToHTML(item.text)}</div>
    ${gearDmEditMode ? `<div class="dm-card-actions"><button class="button button--ghost gear-edit-button" type="button">Edit Upgrade</button></div>` : ""}
  `;

  const editButton = card.querySelector(".gear-edit-button");
  if (editButton) editButton.addEventListener("click", () => openGearEditDialog(item.id));

  bindFavoriteButtons(card);
  return card;
}

function romanTier(tier) {
  return tier === 1 ? "I" : tier === 2 ? "II" : "III";
}

function gearTextToHTML(text) {
  return String(text || "")
    .split(/\n\s*\n/)
    .map(part => `<p>${highlightGameTermsHTML(escapeHTML(part.trim()).replace(/\n/g, "<br>"))}</p>`)
    .join("");
}


