function renderCalculatorPicker({ menu, label, values, labels, selectedValue, onSelect }) {
  if (!menu || !label) return;

  menu.innerHTML = "";
  const picker = menu.closest(".multi-picker");
  if (picker) picker.classList.add("is-filtered");

  label.textContent = labels[selectedValue] || selectedValue;

  values.forEach(value => {
    const selected = value === selectedValue;
    const button = document.createElement("button");
    button.type = "button";
    button.className = `multi-picker__option ${selected ? "is-selected" : ""}`;
    button.innerHTML = `<span><i class="multi-picker__dot" aria-hidden="true"></i>${escapeHTML(labels[value] || value)}</span><em>${selected ? "✓" : ""}</em>`;
    button.addEventListener("click", event => {
      event.stopPropagation();
      onSelect(value);
      closeAllMultiPickers();
      initGearCalculator();
      updateGearCalculator();
    });
    menu.append(button);
  });
}

function initGearCalculator() {
  renderCalculatorPicker({
    menu: els.gearCalcRarityMenu,
    label: els.gearCalcRarityLabel,
    values: ["Simple", "Common", "Uncommon", "Rare", "Very Rare", "Legendary"],
    labels: {
      "Simple": "Simple",
      "Common": "Common",
      "Uncommon": "Uncommon",
      "Rare": "Rare",
      "Very Rare": "Very Rare",
      "Legendary": "Legendary"
    },
    selectedValue: gearCalcRarity,
    onSelect: value => { gearCalcRarity = value; }
  });

  renderCalculatorPicker({
    menu: els.gearCalcTierMenu,
    label: els.gearCalcTierLabel,
    values: ["1", "2", "3"],
    labels: { "1": "Tier I", "2": "Tier II", "3": "Tier III" },
    selectedValue: gearCalcTier,
    onSelect: value => { gearCalcTier = value; }
  });

  renderCalculatorPicker({
    menu: els.gearCalcCountMenu,
    label: els.gearCalcCountLabel,
    values: ["1", "2", "3"],
    labels: { "1": "1 Upgrade", "2": "2 Upgrades", "3": "3 Upgrades" },
    selectedValue: gearCalcCount,
    onSelect: value => { gearCalcCount = value; }
  });

  updateGearCalculator();
}

function updateGearCalculator() {
  const rarity = gearCalcRarity || "Common";
  const tier = Number(gearCalcTier || 1);
  const count = Number(gearCalcCount || 1);

  const rarityCostMap = { "Simple": 100, "Common": 100, "Uncommon": 200, "Rare": 1000, "Very Rare": 2000, "Legendary": 5000 };
  const rarityDcMap = { "Simple": 4, "Common": 6, "Uncommon": 8, "Rare": 10, "Very Rare": 14, "Legendary": 18 };
  const rarityTimeMap = { "Simple": 0, "Common": 0, "Uncommon": 1, "Rare": 2, "Very Rare": 4, "Legendary": 6 };
  const tierCostMap = { 1: 200, 2: 600, 3: 1500 };
  const tierDcMap = { 1: 3, 2: 5, 3: 8 };
  const tierTimeMap = { 1: 1, 2: 2, 3: 3 };

  const totalPerUpgrade = (rarityCostMap[rarity] || 0) + (tierCostMap[tier] || 0);
  const totalCost = totalPerUpgrade * count;
  const craftingDc = (rarityDcMap[rarity] || 0) + (tierDcMap[tier] || 0);
  const totalDays = ((rarityTimeMap[rarity] || 0) + (tierTimeMap[tier] || 0)) * count;

  const costEl = document.getElementById("gearCalcCostResult");
  const dcEl = document.getElementById("gearCalcDcResult");
  const timeEl = document.getElementById("gearCalcTimeResult");
  if (costEl) costEl.textContent = `${totalCost.toLocaleString()} gp`;
  if (dcEl) dcEl.textContent = `DC ${craftingDc}`;
  if (timeEl) timeEl.textContent = `${totalDays} ${totalDays === 1 ? "day" : "days"}`;
}

function openGearCalculatorDialog() {
  initGearCalculator();
  if (els.gearCalculatorDialog) els.gearCalculatorDialog.showModal();
}


function getWeaponRoleTags(weapon) {
  const text = normalizeSearchText([
    weapon.name,
    weapon.abilityName,
    weapon.abilityText,
    ...(weapon.properties || []),
    ...(weapon.traits || [])
  ].join(" "));

  const roles = new Set();

  if (/(damage|critical|bleed|cleave|sweep|scatter|dualshot|follow-up|extra die|bonus to.*damage|brutal|cut|farshot|flowing assault|gaping wound|reap|concuss|2d4|1d8|1d10|1d12|2d8|2d10)/.test(text)) {
    roles.add("Offense");
  }
  if (/(ac|block|deflect|retaliate|shield|armor|opportunity attacks? against you|reaction.*ac)/.test(text)) {
    roles.add("Defense");
  }
  if (/(speed|reduced|speed to 0|pin|slow|move it|closer|prone|push|pushed|forced|lunge|reach|cone)/.test(text)) {
    roles.add("Control");
  }
  if (/(finesse|hidden weapon|quick equip|light|versatile|thrown|don|unaware|combo|staff|cane|utility)/.test(text)) {
    roles.add("Utility");
  }
  if (/(advantage|attack rolls?|\\+2 to your attack|\\+1 bonus to attack|farshot)/.test(text)) {
    roles.add("Accuracy");
  }
  if (/(cone|all creatures|two enemies|sweeping|cleave|scatter|sweep|dualshot)/.test(text)) {
    roles.add("Area");
  }
  if (/(hidden weapon|unaware|do not consider|stealth)/.test(text)) {
    roles.add("Stealth");
  }
  if (/(massive|two-handed|heavy|colossal|strength to wield)/.test(text)) {
    roles.add("Heavy");
  }

  if (roles.size === 0) roles.add("Utility");
  return [...roles];
}

