function weaponMatchesFilters(weapon) {
  if (weaponFavoritesOnly && !isFavorite("weapon", weapon.id)) return false;
  const query = normalizeSearchText(document.getElementById("weaponSearchInput")?.value || "");
  if (query) {
    const searchable = [
      weapon.name, weapon.collection, weapon.category, weapon.weaponType, weapon.cost, weapon.damage,
      weapon.damageType, weapon.weight, weapon.range, ...(weapon.properties || []), ...(weapon.traits || []),
      ...getWeaponRoleTags(weapon), weapon.abilityName, weapon.abilityText,
      getWeaponSearchKeywords(weapon)
    ].join(" ");
    if (!normalizeSearchText(searchable).includes(query) && !fuzzyTitleMatch(weapon.name, query)) return false;
  }

  if (weaponActiveCategories.size > 0 && !weaponActiveCategories.has(weapon.category)) return false;
  if (weaponActiveTraits.size > 0 && !getWeaponRoleTags(weapon).some(role => weaponActiveTraits.has(role))) return false;
  if (weaponActiveDamageTypes.size > 0 && !weaponActiveDamageTypes.has(weapon.damageType)) return false;
  return true;
}



function renderWeapons() {
  refreshFavoriteFilterButtons();
  if (els.weaponDmEditToggle) {
    els.weaponDmEditToggle.classList.toggle("is-active", weaponDmEditMode);
    els.weaponDmEditToggle.textContent = weaponDmEditMode ? "Exit DM Mode" : "DM Mode";
  }
  const cardsWrap = document.getElementById("weaponCards");
  const statsEl = document.getElementById("weaponStats");
  const resultsInfo = document.getElementById("weaponResultsInfo");
  if (!cardsWrap || !statsEl || !resultsInfo) return;

  renderWeaponActiveFilters();
  const filtered = weaponsExpanded.filter(weaponMatchesFilters);
  statsEl.textContent = `${filtered.length} of ${weaponsExpanded.length} weapons shown`;
  resultsInfo.textContent = `${filtered.length} of ${weaponsExpanded.length} weapon entries shown`;
  cardsWrap.innerHTML = "";

  ["Specialized Weapons", "Regular Weapons"].forEach(collection => {
    const collectionItems = filtered.filter(item => item.collection === collection);
    if (!collectionItems.length) return;

    const collectionSection = document.createElement("section");
    collectionSection.className = "weapon-collection-section";
    collectionSection.innerHTML = `<div class="weapon-collection-heading"><h3>${escapeHTML(collection)}</h3><span>${collectionItems.length} ${collectionItems.length === 1 ? "weapon" : "weapons"}</span></div>`;

    const categoryOrder = ["Simple Melee Weapons", "Martial Melee Weapons", "Martial Ranged Weapons"];
    categoryOrder.forEach(category => {
      const items = collectionItems.filter(item => item.category === category);
      if (!items.length) return;
      const key = `${collection}|${category}`;
      const isCollapsed = collapsedWeaponCategories.has(key);

      const categorySection = document.createElement("section");
      categorySection.className = `weapon-category-section ${isCollapsed ? "is-collapsed" : ""}`;
      categorySection.innerHTML = `
        <div class="weapon-category-heading">
          <div class="collapsible-heading-title">
            <button class="category-toggle" type="button" aria-expanded="${String(!isCollapsed)}" aria-label="${isCollapsed ? "Expand" : "Collapse"} ${category}">
              <span class="category-toggle__arrow" aria-hidden="true">▾</span>
            </button>
            <h4>${escapeHTML(category)}</h4>
          </div>
          <span>${items.length} ${items.length === 1 ? "weapon" : "weapons"}</span>
        </div>
        <div class="weapon-card-grid"></div>
      `;
      categorySection.querySelector(".category-toggle").addEventListener("click", () => {
        toggleCollapsibleSet(categorySection, collapsedWeaponCategories, key, renderWeapons);
      });
      const grid = categorySection.querySelector(".weapon-card-grid");
      items.sort((a,b)=>a.name.localeCompare(b.name)).forEach(item => grid.append(renderWeaponCard(item)));
      collectionSection.append(categorySection);
    });

    cardsWrap.append(collectionSection);
  });

  if (!filtered.length) {
    cardsWrap.innerHTML = `<div class="empty-state panel"><h3>No weapons found</h3><p>Try another category, ability, damage type, combat mode, or search term.</p></div>`;
  }
}

function renderWeaponCard(weapon) {
  const card = document.createElement("article");
  card.className = `weapon-card weapon-card--${weapon.mode.toLowerCase()}`;
  card.innerHTML = `
    <header class="weapon-card__header">
      <div>
        <h4>${escapeHTML(weapon.name)}</h4>
        <p>${escapeHTML(weapon.weaponType)} · ${escapeHTML(weapon.mode)}</p>
      </div>
      <div class="weapon-card__header-actions">
        ${createFavoriteButton("weapon", weapon.id, weapon.name)}
        <div class="weapon-tag-row">
          <span class="gear-tag gear-tag--type">${escapeHTML(weapon.damageType)}</span>
          <span class="gear-tag gear-tag--tier">${escapeHTML(weapon.mode)}</span>
        </div>
      </div>
    </header>
    <div class="card-hierarchy-row">
      <span>${escapeHTML(weapon.mode)}</span>
      <span>${escapeHTML(weapon.weaponType)}</span>
      <span>${escapeHTML(weapon.damageType)}</span>
      ${getWeaponRoleTags(weapon).slice(0, 2).map(role => `<span>${escapeHTML(role)}</span>`).join("")}
    </div>
    <div class="weapon-stats-grid">
      <p><span>Cost</span><strong>${escapeHTML(weapon.cost)}</strong></p>
      <p><span>Damage</span><strong>${highlightGameTerms(weapon.damage)}</strong></p>
      <p><span>Range</span><strong>${escapeHTML(weapon.range || "—")}</strong></p>
      <p><span>Weight</span><strong>${escapeHTML(weapon.weight)}</strong></p>
    </div>
    <div class="weapon-tag-row weapon-tag-row--roles">
      ${getWeaponRoleTags(weapon).map(item => `<span class="gear-tag gear-tag--role">${escapeHTML(item)}</span>`).join("")}
    </div>
    <div class="weapon-tag-row weapon-tag-row--traits">
      ${(weapon.properties || []).map(item => `<span class="gear-tag">${escapeHTML(item)}</span>`).join("")}
    </div>
    <p class="weapon-summary"><strong>${escapeHTML(weapon.abilityName)}:</strong> ${highlightGameTerms(weapon.abilityText)}</p>
    ${weaponDmEditMode ? `<div class="dm-card-actions"><button class="button button--ghost weapon-edit-button" type="button">Edit Weapon</button></div>` : ""}
  `;

  const editButton = card.querySelector(".weapon-edit-button");
  if (editButton) editButton.addEventListener("click", () => openWeaponEditDialog(weapon.id));

  bindFavoriteButtons(card);
  return card;
}

function getConditionTypeFilters(condition) {
  const text = normalizeSearchText([
    condition.name,
    condition.category,
    condition.summary,
    condition.intro,
    ...(condition.roles || []),
    ...(condition.elements || []),
    ...(condition.mechanics || []),
    ...(condition.rules || [])
  ].join(" "));

  const tags = new Set();

  if (/(blood|bleeding|burning|damage|fire damage|additional damage|end of its turns|vulnerability)/.test(text)) tags.add("Damage");
  if (/(speed|reduced to 0|reduced by 10|cannot take reactions|frozen|chilled|control|action to)/.test(text)) tags.add("Control");
  if (/(penalty|disadvantage|half the normal|cannot|reduced|corroded|sapped|feebleminded|debuff)/.test(text)) tags.add("Debuff");
  if (/(resistance|immune|immunity|ac|armor|defense|vulnerability)/.test(text)) tags.add("Defense");
  if (/(healing|hit points|regains|receives healing)/.test(text)) tags.add("Healing");
  if (/(speed|movement|move|reduced to 0|reduced by 10)/.test(text)) tags.add("Movement");
  if (/(spell|verbal|components|concentration)/.test(text)) tags.add("Spellcasting");
  if (/(intelligence|wisdom|charisma|mind|mental|feebleminded)/.test(text)) tags.add("Mental");
  if ((condition.elements || []).length || /(fire|cold|lightning|acid|water|soaked|chilled|frozen|burning|corroded)/.test(text)) tags.add("Elemental");
  if ((condition.table || []).length || /tier/.test(text)) tags.add("Tiered");

  if (tags.size === 0) tags.add("Debuff");
  return [...tags];
}

function getConditionMechanicFilters(condition) {
  const text = normalizeSearchText([
    condition.name,
    condition.summary,
    condition.intro,
    ...(condition.mechanics || []),
    ...(condition.rules || [])
  ].join(" "));

  const tags = new Set();

  if (/(saving throw|save dc|save|constitution|intelligence|dexterity|strength)/.test(text)) tags.add("Saving Throws");
  if (/(healing|hit points|regains|receives healing)/.test(text)) tags.add("Healing");
  if (/(speed|movement|move|reduced to 0|reduced by 10)/.test(text)) tags.add("Movement");
  if (/concentration/.test(text)) tags.add("Concentration");
  if (/reaction/.test(text)) tags.add("Reactions");
  if (/(spell|verbal|components)/.test(text)) tags.add("Spellcasting");
  if (/(takes damage|when.*damage|end of.*turn|additional.*damage|damage at the end)/.test(text)) tags.add("Damage Trigger");
  if (/(action to|uses its action|action)/.test(text)) tags.add("Action to End");
  if (/(ac|armor)/.test(text)) tags.add("AC / Armor");
  if (/(resistance|immune|immunity|vulnerability)/.test(text)) tags.add("Resistance / Immunity");

  if (tags.size === 0) tags.add("General Rule");
  return [...tags];
}

function renderConditionFilters() {
  const typeOptions = ["Damage", "Control", "Debuff", "Defense", "Healing", "Movement", "Spellcasting", "Mental", "Elemental", "Tiered"];
  renderMultiPickerMenu({
    menu: document.getElementById("conditionRoleMenu"),
    label: document.getElementById("conditionRoleLabel"),
    values: typeOptions,
    labels: Object.fromEntries(typeOptions.map(item => [item, item])),
    activeSet: conditionActiveRoles,
    allLabel: "All Types",
    onChange: renderConditions
  });

  const elementOptions = [...new Set(conditionsExpanded.flatMap(condition => condition.elements || []))].sort((a, b) => a.localeCompare(b));
  renderMultiPickerMenu({
    menu: document.getElementById("conditionElementMenu"),
    label: document.getElementById("conditionElementLabel"),
    values: elementOptions,
    labels: Object.fromEntries(elementOptions.map(item => [item, item])),
    activeSet: conditionActiveElements,
    allLabel: "All Elements",
    onChange: renderConditions
  });

  const mechanicOptions = ["Saving Throws", "Healing", "Movement", "Concentration", "Reactions", "Spellcasting", "Damage Trigger", "Action to End", "AC / Armor", "Resistance / Immunity"];
  renderMultiPickerMenu({
    menu: document.getElementById("conditionMechanicMenu"),
    label: document.getElementById("conditionMechanicLabel"),
    values: mechanicOptions,
    labels: Object.fromEntries(mechanicOptions.map(item => [item, item])),
    activeSet: conditionActiveMechanics,
    allLabel: "All Rule Hooks",
    onChange: renderConditions
  });
}

function conditionMatchesFilters(condition) {
  if (conditionFavoritesOnly && !isFavorite("condition", condition.id)) return false;
  const query = normalizeSearchText(document.getElementById("conditionSearchInput")?.value || "");
  if (query) {
    const searchable = [
      condition.name,
      condition.category,
      condition.duration,
      condition.intro,
      condition.summary,
      ...(condition.roles || []),
      ...(condition.elements || []),
      ...(condition.mechanics || []),
      ...getConditionTypeFilters(condition),
      ...getConditionMechanicFilters(condition),
      ...(condition.rules || []),
      getConditionSearchKeywords(condition)
    ].join(" ");
    if (!normalizeSearchText(searchable).includes(query) && !fuzzyTitleMatch(condition.name, query)) return false;
  }

  if (conditionActiveRoles.size > 0 && !getConditionTypeFilters(condition).some(role => conditionActiveRoles.has(role))) return false;
  if (conditionActiveElements.size > 0 && !(condition.elements || []).some(element => conditionActiveElements.has(element))) return false;
  if (conditionActiveMechanics.size > 0 && !getConditionMechanicFilters(condition).some(mechanic => conditionActiveMechanics.has(mechanic))) return false;
  return true;
}

function renderConditions() {
  refreshFavoriteFilterButtons();
  if (els.conditionDmEditToggle) {
    els.conditionDmEditToggle.classList.toggle("is-active", conditionDmEditMode);
    els.conditionDmEditToggle.textContent = conditionDmEditMode ? "Exit DM Mode" : "DM Mode";
  }
  const cardsWrap = document.getElementById("conditionCards");
  const resultsInfo = document.getElementById("conditionResultsInfo");
  if (!cardsWrap || !resultsInfo) return;

  renderConditionActiveFilters();
  const filtered = conditionsExpanded.filter(conditionMatchesFilters);
  resultsInfo.textContent = `${filtered.length} of ${conditionsExpanded.length} conditions shown`;
  cardsWrap.innerHTML = "";

  const categoryOrder = ["Damage", "Mental", "Elemental", "Armor", "Vitality"];
  categoryOrder.forEach(category => {
    const items = filtered.filter(condition => condition.category === category);
    if (!items.length) return;

    const key = category;
    const isCollapsed = collapsedConditionCategories.has(key);
    const section = document.createElement("section");
    section.className = `condition-category-section ${isCollapsed ? "is-collapsed" : ""}`;
    section.innerHTML = `
      <div class="condition-category-heading">
        <div class="collapsible-heading-title">
          <button class="category-toggle" type="button" aria-expanded="${String(!isCollapsed)}" aria-label="${isCollapsed ? "Expand" : "Collapse"} ${category} conditions">
            <span class="category-toggle__arrow" aria-hidden="true">▾</span>
          </button>
          <h3>${escapeHTML(category)} Conditions</h3>
        </div>
        <span>${items.length} ${items.length === 1 ? "condition" : "conditions"}</span>
      </div>
      <div class="condition-card-grid"></div>
    `;

    section.querySelector(".category-toggle").addEventListener("click", () => {
      toggleCollapsibleSet(section, collapsedConditionCategories, key, renderConditions);
    });

    const grid = section.querySelector(".condition-card-grid");
    items.sort((a, b) => a.name.localeCompare(b.name)).forEach(condition => grid.append(renderConditionCard(condition)));
    cardsWrap.append(section);
  });

  if (!filtered.length) {
    cardsWrap.innerHTML = `<div class="empty-state panel"><h3>No conditions found</h3><p>Try another role, element, mechanic, or search term.</p></div>`;
  }
}

function renderConditionCard(condition) {
  const card = document.createElement("article");
  const conditionTone = condition.id || normalizeSearchText(condition.name).replace(/\s+/g, "-");
  card.className = `condition-card condition-card--${conditionTone} condition-card--${normalizeSearchText(condition.category).replace(/\s+/g, "-")}`;
  card.innerHTML = `
    <header class="condition-card__header">
      <div>
        <h4>${escapeHTML(condition.name)}</h4>
        <p>${highlightGameTerms(condition.intro || "")}</p>
      </div>
      <div class="condition-card__header-actions">
        ${createFavoriteButton("condition", condition.id, condition.name)}
        <span class="spell-school">${escapeHTML(condition.duration || "—")}</span>
      </div>
    </header>

    <div class="card-hierarchy-row">
      <span>${escapeHTML(condition.category)}</span>
      <span>${escapeHTML(condition.duration || "—")}</span>
      ${getConditionTypeFilters(condition).slice(0, 3).map(type => `<span>${escapeHTML(type)}</span>`).join("")}
    </div>

    <div class="condition-tag-row">
      ${getConditionTypeFilters(condition).map(role => `<span class="gear-tag gear-tag--role condition-tag condition-tag--${normalizeSearchText(role).replace(/\s+/g, "-")}">${escapeHTML(role)}</span>`).join("")}
      ${(condition.elements || []).map(element => `<span class="gear-tag condition-tag condition-tag--element condition-tag--${normalizeSearchText(element).replace(/\s+/g, "-")}">${escapeHTML(element)}</span>`).join("")}
      ${getConditionMechanicFilters(condition).map(mechanic => `<span class="gear-tag condition-tag condition-tag--mechanic condition-tag--${normalizeSearchText(mechanic).replace(/\s+/g, "-")}">${escapeHTML(mechanic)}</span>`).join("")}
    </div>

    <p class="condition-summary">${highlightGameTerms(condition.summary || "")}</p>

    ${condition.table ? renderConditionTable(condition.tableHeaders, condition.table) : ""}

    <ul class="condition-rule-list">
      ${(condition.rules || []).map(rule => `<li>${highlightGameTerms(rule)}</li>`).join("")}
    </ul>
    ${conditionDmEditMode ? `<div class="dm-card-actions"><button class="button button--ghost condition-edit-button" type="button">Edit Condition</button></div>` : ""}
  `;

  const editButton = card.querySelector(".condition-edit-button");
  if (editButton) editButton.addEventListener("click", () => openConditionEditDialog(condition.id));

  bindFavoriteButtons(card);
  return card;
}

function renderConditionTable(headers, rows) {
  return `
    <div class="condition-table-wrap">
      <table class="condition-table">
        <thead>
          <tr>${headers.map(header => `<th>${escapeHTML(header)}</th>`).join("")}</tr>
        </thead>
        <tbody>
          ${rows.map(row => `<tr>${row.map(cell => `<td>${highlightGameTerms(cell)}</td>`).join("")}</tr>`).join("")}
        </tbody>
      </table>
    </div>
  `;
}


