function normalizeCharacter(raw = {}) {
  const fallback = createDefaultCharacter();
  const merged = { ...fallback, ...(raw || {}) };
  merged.level = Math.max(1, Math.min(20, Number(merged.level) || 1));
  merged.abilities = { ...fallback.abilities, ...(raw.abilities || {}) };
  CHARACTER_ABILITIES.forEach(ability => {
    merged.abilities[ability.key] = Math.max(1, Math.min(30, Number(merged.abilities[ability.key]) || 10));
  });
  merged.saveProficiencies = Array.isArray(raw.saveProficiencies) ? raw.saveProficiencies.filter(key => CHARACTER_ABILITIES.some(ability => ability.key === key)) : [];
  merged.skills = { ...fallback.skills, ...(raw.skills || {}) };
  CHARACTER_SKILLS.forEach(skill => {
    merged.skills[skill.name] = {
      proficient: Boolean(merged.skills[skill.name]?.proficient),
      expertise: Boolean(merged.skills[skill.name]?.expertise),
      bonus: Number(merged.skills[skill.name]?.bonus) || 0
    };
  });
  merged.spellSlots = { ...fallback.spellSlots, ...(raw.spellSlots || {}) };
  merged.currencyCoins = { ...fallback.currencyCoins, ...(raw.currencyCoins || {}) };
  CHARACTER_CURRENCY_KEYS.forEach(coin => {
    merged.currencyCoins[coin.key] = String(merged.currencyCoins[coin.key] ?? "");
  });
  delete merged.campaign;

  merged.multiclasses = Array.isArray(raw.multiclasses) ? raw.multiclasses.map(entry => ({
    className: String(entry?.className || ""),
    subclass: String(entry?.subclass || ""),
    level: Math.max(1, Math.min(20, Number(entry?.level) || 1))
  })).filter(entry => entry.className || entry.subclass) : [];
  const normalizedBackground = getCharacterOptionByValue(CHARACTER_BACKGROUND_OPTIONS, merged.background);
  if (normalizedBackground?.feat && normalizedBackground.feat !== "Custom" && !String(merged.originFeat || "").trim()) {
    merged.originFeat = normalizedBackground.feat;
  }
  merged.hpRollLog = String(raw.hpRollLog || "");
  merged.statRollConfig = {
    stats: Math.max(1, Math.min(12, Number(raw.statRollConfig?.stats) || fallback.statRollConfig.stats)),
    dice: Math.max(3, Math.min(10, Number(raw.statRollConfig?.dice) || fallback.statRollConfig.dice))
  };
  merged.lastStatRolls = Array.isArray(raw.lastStatRolls) ? raw.lastStatRolls : [];
  merged.selectedSpellLevel = CHARACTER_SPELL_LEVEL_OPTIONS.some(option => option.value === String(raw.selectedSpellLevel)) ? String(raw.selectedSpellLevel) : fallback.selectedSpellLevel;
  merged.selectedSpellsByLevel = { ...fallback.selectedSpellsByLevel, ...(raw.selectedSpellsByLevel || {}) };
  CHARACTER_SPELL_LEVEL_OPTIONS.forEach(option => {
    merged.selectedSpellsByLevel[option.value] = String(merged.selectedSpellsByLevel[option.value] || "");
  });
  return merged;
}

function loadCharacterState() {
  try {
    characterState = normalizeCharacter(JSON.parse(localStorage.getItem(CHARACTER_STORAGE_KEY)));
  } catch {
    characterState = createDefaultCharacter();
  }
}

function saveCharacterState() {
  if (!characterState) characterState = createDefaultCharacter();
  localStorage.setItem(CHARACTER_STORAGE_KEY, JSON.stringify(characterState));
}

function getCharacterProficiencyBonus(level = characterState.level) {
  return Math.floor((Math.max(1, Math.min(20, Number(level) || 1)) - 1) / 4) + 2;
}

function getAbilityModifier(score) {
  return Math.floor((Number(score || 10) - 10) / 2);
}

function formatSigned(value) {
  const number = Number(value) || 0;
  return number >= 0 ? `+${number}` : String(number);
}

