function exportAllSavedChoices() {
  try {
    if (!characterState) characterState = createDefaultCharacter();
    collectCharacterForm();
    syncActiveBuild();
    saveState();
    saveCharacterState();

    const payload = {
      app: "D&D Homebrew Compendium",
      type: "global-export",
      version: 2,
      exportedAt: new Date().toISOString(),
      activePage,
      warTactics: {
        activeSlot: builds.activeSlot,
        currentBuild: state,
        slots: builds.slots
      },
      favorites,
      dmEdits: {
        tactics: tacticEdits,
        spells: spellEdits,
        gear: gearEdits,
        weapons: weaponEdits,
        conditions: conditionEdits
      },
      character: characterState,
      rawLocalStorage: {
        warBuilds: localStorage.getItem(STORAGE_KEY),
        favorites: localStorage.getItem(FAVORITES_KEY),
        tacticEdits: localStorage.getItem(TACTIC_EDITS_KEY),
        spellEdits: localStorage.getItem(SPELL_EDITS_KEY),
        gearEdits: localStorage.getItem(GEAR_EDITS_KEY),
        weaponEdits: localStorage.getItem(WEAPON_EDITS_KEY),
        conditionEdits: localStorage.getItem(CONDITION_EDITS_KEY),
        character: localStorage.getItem(CHARACTER_STORAGE_KEY),
        all: (() => {
          const snapshot = {};
          for (let i = 0; i < localStorage.length; i += 1) {
            const key = localStorage.key(i);
            if (key) snapshot[key] = localStorage.getItem(key);
          }
          return snapshot;
        })()
      }
    };

    downloadJsonFile(`homebrew-compendium-global-export-${new Date().toISOString().slice(0, 10)}.json`, payload);
    showToast("All saved choices exported.");
  } catch (error) {
    console.error(error);
    showToast("Could not export all saved choices.");
  }
}



function importAllSavedChoices(file) {
  if (!file) return;
  const reader = new FileReader();
  reader.addEventListener("load", () => {
    try {
      const payload = JSON.parse(String(reader.result || "{}"));
      if (payload.type === "global-export") {
        if (payload.rawLocalStorage && typeof payload.rawLocalStorage === "object") {
          if (payload.rawLocalStorage.all && typeof payload.rawLocalStorage.all === "object") {
            Object.entries(payload.rawLocalStorage.all).forEach(([key, value]) => {
              if (typeof key === "string" && typeof value === "string") localStorage.setItem(key, value);
            });
          } else {
            const storageMap = [
              [STORAGE_KEY, payload.rawLocalStorage.warBuilds],
              [FAVORITES_KEY, payload.rawLocalStorage.favorites],
              [TACTIC_EDITS_KEY, payload.rawLocalStorage.tacticEdits],
              [SPELL_EDITS_KEY, payload.rawLocalStorage.spellEdits],
              [GEAR_EDITS_KEY, payload.rawLocalStorage.gearEdits],
              [WEAPON_EDITS_KEY, payload.rawLocalStorage.weaponEdits],
              [CONDITION_EDITS_KEY, payload.rawLocalStorage.conditionEdits],
              [CHARACTER_STORAGE_KEY, payload.rawLocalStorage.character]
            ];
            storageMap.forEach(([key, value]) => {
              if (typeof value === "string") localStorage.setItem(key, value);
            });
          }
        } else {
          if (payload.warTactics?.slots) localStorage.setItem(STORAGE_KEY, JSON.stringify({ activeSlot: payload.warTactics.activeSlot || "1", slots: payload.warTactics.slots }));
          if (payload.favorites) localStorage.setItem(FAVORITES_KEY, JSON.stringify(payload.favorites));
          if (payload.dmEdits?.tactics) localStorage.setItem(TACTIC_EDITS_KEY, JSON.stringify(payload.dmEdits.tactics));
          if (payload.dmEdits?.spells) localStorage.setItem(SPELL_EDITS_KEY, JSON.stringify(payload.dmEdits.spells));
          if (payload.dmEdits?.gear) localStorage.setItem(GEAR_EDITS_KEY, JSON.stringify(payload.dmEdits.gear));
          if (payload.dmEdits?.weapons) localStorage.setItem(WEAPON_EDITS_KEY, JSON.stringify(payload.dmEdits.weapons));
          if (payload.dmEdits?.conditions) localStorage.setItem(CONDITION_EDITS_KEY, JSON.stringify(payload.dmEdits.conditions));
          if (payload.character) localStorage.setItem(CHARACTER_STORAGE_KEY, JSON.stringify(payload.character));
        }
        showToast("Import complete. Reloading saved data...");
        window.setTimeout(() => window.location.reload(), 450);
        return;
      }

      if (payload.type === "character" && payload.character) {
        localStorage.setItem(CHARACTER_STORAGE_KEY, JSON.stringify(payload.character));
        showToast("Character imported. Reloading saved data...");
        window.setTimeout(() => window.location.reload(), 450);
        return;
      }

      showToast("Unsupported import file.");
    } catch (error) {
      console.error(error);
      showToast("Could not import this file.");
    } finally {
      if (els.globalImportInput) els.globalImportInput.value = "";
    }
  });
  reader.readAsText(file);
}


