function withSource(options, sourceEdition, source, iconKeyMap = {}) {
  return options.map(option => {
    const base = typeof option === "string" ? { value: option, label: option } : { ...option };
    return { ...base, sourceEdition, source: base.source || source, iconKey: base.iconKey || iconKeyMap[base.value] || base.iconKey };
  });
}

