function getCharacterRulesVersion() {
  return characterState?.rulesVersion === "2014" ? "2014" : "2024";
}
function getVersionedOptions(options2014, options2024, expanded = false) {
  if (expanded) return [...options2014, ...options2024];
  return getCharacterRulesVersion() === "2014" ? options2014 : options2024;
}
function getCharacterClassOptions() {
  return getVersionedOptions(CHARACTER_CLASS_OPTIONS_2014, CHARACTER_CLASS_OPTIONS_2024, false);
}
function getCharacterSpeciesOptions() {
  return getVersionedOptions(CHARACTER_SPECIES_OPTIONS_2014, CHARACTER_SPECIES_OPTIONS_2024, false);
}
function getCharacterBackgroundOptions() {
  return getVersionedOptions(CHARACTER_BACKGROUND_OPTIONS_2014, CHARACTER_BACKGROUND_OPTIONS_2024, false);
}
function getCharacterLanguageOptions() {
  return getVersionedOptions(CHARACTER_LANGUAGE_OPTIONS_2014, CHARACTER_LANGUAGE_OPTIONS_2024, Boolean(characterState?.expandedLanguages));
}
function getCharacterSubclassOptions(className) {
  const klass = String(className || "");
  const list2014 = CHARACTER_SUBCLASS_OPTIONS_2014[klass] || [];
  const list2024 = CHARACTER_SUBCLASS_OPTIONS_2024[klass] || [];
  let subclasses = getVersionedOptions(list2014, list2024, Boolean(characterState?.expandedSubclasses));
  const seen = new Set();
  subclasses = subclasses.filter(option => {
    const dedupeKey = `${option.sourceEdition}|${option.value}`;
    if (seen.has(dedupeKey)) return false;
    seen.add(dedupeKey);
    return true;
  });
  if (!subclasses.length) return [{ value: "Custom / Other", label: "Custom / Other", sourceEdition: "Table", source: "Custom", iconKey: "sigil-custom" }];
  return subclasses.concat([{ value: "Custom / Other", label: "Custom / Other", sourceEdition: "Table", source: "Custom", iconKey: "sigil-custom" }]);
}
function getCurrentBackgroundOption() {
  return getCharacterOptionByValue(getCharacterBackgroundOptions(), characterState.background) || getCharacterOptionByValue([...CHARACTER_BACKGROUND_OPTIONS_2014, ...CHARACTER_BACKGROUND_OPTIONS_2024], characterState.background);
}
function getCurrentClassOptionsForExport() {
  return [...CHARACTER_CLASS_OPTIONS_2014, ...CHARACTER_CLASS_OPTIONS_2024];
}
function getCurrentSpeciesOptionsForExport() {
  return [...CHARACTER_SPECIES_OPTIONS_2014, ...CHARACTER_SPECIES_OPTIONS_2024];
}
function getCurrentBackgroundOptionsForExport() {
  return [...CHARACTER_BACKGROUND_OPTIONS_2014, ...CHARACTER_BACKGROUND_OPTIONS_2024];
}

function createDefaultCharacter() {
  const skills = Object.fromEntries(CHARACTER_SKILLS.map(skill => [skill.name, { proficient: false, expertise: false, bonus: 0 }]));
  return {
    name: "", player: "", className: "", subclass: "", multiclasses: [], level: 1, species: "", size: "Medium", background: "", originFeat: "", alignment: "", xp: "",
    rulesVersion: "2024", expandedSubclasses: false, expandedLanguages: false,
    abilities: { str: 10, dex: 10, con: 10, int: 10, wis: 10, cha: 10 }, saveProficiencies: [], skills,
    armorClass: 10, speed: 30, initiativeBonus: 0, maxHp: 0, currentHp: 0, tempHp: 0, hitDice: "", deathSaveSuccesses: 0, deathSaveFailures: 0, heroicInspiration: false,
    senses: "", languages: "", armorTraining: "", weaponTraining: "", toolTraining: "", features: "", attacks: "", equipment: "",
    currency: "", currencyCoins: { pp: "", ep: "", gp: "", sp: "", cp: "" }, treasure: "",
    spellcastingAbility: "", spellSlots: { "1": "", "2": "", "3": "", "4": "", "5": "", "6": "", "7": "", "8": "", "9": "" },
    selectedSpellLevel: "0", selectedSpellsByLevel: createDefaultSelectedSpellsByLevel(), cantrips: "", preparedSpells: "", spellbook: "", notes: "", backstory: "",
    hpRollLog: "", statRollConfig: { stats: 6, dice: 4 }, lastStatRolls: []
  };
}
function normalizeCharacter(raw = {}) {
  const fallback = createDefaultCharacter();
  const merged = { ...fallback, ...(raw || {}) };
  merged.rulesVersion = raw.rulesVersion === "2014" ? "2014" : "2024";
  merged.expandedSubclasses = Boolean(raw.expandedSubclasses);
  merged.expandedLanguages = Boolean(raw.expandedLanguages);
  merged.level = Math.max(1, Math.min(20, Number(merged.level) || 1));
  merged.abilities = { ...fallback.abilities, ...(raw.abilities || {}) };
  CHARACTER_ABILITIES.forEach(ability => { merged.abilities[ability.key] = Math.max(1, Math.min(30, Number(merged.abilities[ability.key]) || 10)); });
  merged.saveProficiencies = Array.isArray(raw.saveProficiencies) ? raw.saveProficiencies.filter(key => CHARACTER_ABILITIES.some(ability => ability.key === key)) : [];
  merged.skills = { ...fallback.skills, ...(raw.skills || {}) };
  CHARACTER_SKILLS.forEach(skill => { merged.skills[skill.name] = { proficient: Boolean(merged.skills[skill.name]?.proficient), expertise: Boolean(merged.skills[skill.name]?.expertise), bonus: Number(merged.skills[skill.name]?.bonus) || 0 }; });
  merged.spellSlots = { ...fallback.spellSlots, ...(raw.spellSlots || {}) };
  merged.currencyCoins = { ...fallback.currencyCoins, ...(raw.currencyCoins || {}) };
  CHARACTER_CURRENCY_KEYS.forEach(coin => { merged.currencyCoins[coin.key] = String(merged.currencyCoins[coin.key] ?? ""); });
  delete merged.campaign;
  merged.multiclasses = Array.isArray(raw.multiclasses) ? raw.multiclasses.map(entry => ({ className: String(entry?.className || ""), subclass: String(entry?.subclass || ""), level: Math.max(1, Math.min(20, Number(entry?.level) || 1)) })).filter(entry => entry.className || entry.subclass) : [];
  const normalizedBackground = getCharacterOptionByValue([...CHARACTER_BACKGROUND_OPTIONS_2014, ...CHARACTER_BACKGROUND_OPTIONS_2024], merged.background);
  if (normalizedBackground?.feat && normalizedBackground.feat !== "Custom" && normalizedBackground.feat !== "None" && !String(merged.originFeat || "").trim()) merged.originFeat = normalizedBackground.feat;
  if (merged.rulesVersion === "2014" && (!merged.originFeat || merged.originFeat === "Custom")) merged.originFeat = "None";
  merged.hpRollLog = String(raw.hpRollLog || "");
  merged.statRollConfig = { stats: Math.max(1, Math.min(12, Number(raw.statRollConfig?.stats) || fallback.statRollConfig.stats)), dice: Math.max(3, Math.min(10, Number(raw.statRollConfig?.dice) || fallback.statRollConfig.dice)) };
  merged.lastStatRolls = Array.isArray(raw.lastStatRolls) ? raw.lastStatRolls : [];
  merged.selectedSpellLevel = CHARACTER_SPELL_LEVEL_OPTIONS.some(option => option.value === String(raw.selectedSpellLevel)) ? String(raw.selectedSpellLevel) : fallback.selectedSpellLevel;
  merged.selectedSpellsByLevel = { ...fallback.selectedSpellsByLevel, ...(raw.selectedSpellsByLevel || {}) };
  CHARACTER_SPELL_LEVEL_OPTIONS.forEach(option => { merged.selectedSpellsByLevel[option.value] = String(merged.selectedSpellsByLevel[option.value] || ""); });
  return merged;
}

function renderCharacterRulesPanel() {
  const modeText = getCharacterRulesVersion() === "2014" ? "5e / 2014 mode uses pre-2024 character material." : "5.5e / 2024 mode uses updated 2024 character material.";
  return `
    <section class="character-rules-panel">
      <div class="character-rules-panel__head">
        <strong>Rules Source</strong>
        <small>${escapeHTML(modeText)} Expanded ticks merge both eras and show source badges.</small>
      </div>
      <div class="character-rules-grid">
        ${characterSelectField("rulesVersion", "Rules Version", CHARACTER_RULE_VERSION_OPTIONS, null)}
        ${characterToggleField("expandedSubclasses", "Expanded Subclasses", "Show 5e + 5.5e subclass material")}
        ${characterToggleField("expandedLanguages", "Expanded Languages", "Show 5e + 5.5e language material")}
      </div>
    </section>
  `;
}
function characterToggleField(key, label, hint = "") {
  return `
    <label class="character-checkbox character-material-toggle">
      <input type="checkbox" data-character-field="${escapeHTML(key)}" ${characterState[key] ? "checked" : ""}>
      <span>${escapeHTML(label)}${hint ? `<small>${escapeHTML(hint)}</small>` : ""}</span>
    </label>
  `;
}
function renderSubclassField() {
  return `
    <div class="character-subclass-field-wrap">
      ${characterSelectField("subclass", "Subclass", getCharacterSubclassOptions(characterState.className), characterState.className ? "Choose subclass" : "Choose class first")}
      <div class="character-inline-toggle-row">${characterToggleField("expandedSubclasses", "Expanded Material", "5e + 5.5e subclasses")}</div>
    </div>
  `;
}

function renderCharacterCreator() {
  if (!els.characterSheet) return;
  if (!characterState) characterState = createDefaultCharacter();
  const pb = getCharacterProficiencyBonus();
  const initiative = getAbilityModifier(characterState.abilities.dex) + (Number(characterState.initiativeBonus) || 0);
  const passivePerception = 10 + getSkillModifier({ name: "Perception", ability: "wis" });
  els.characterSheet.innerHTML = `
    ${renderCharacterRulesPanel()}
    <section class="character-panel character-panel--identity">
      <div class="character-panel__heading"><h3>Identity & Origin</h3><span>PB ${formatSigned(pb)}</span></div>
      <div class="character-grid character-grid--identity character-grid--identity-four">
        <div class="character-identity-column">
          ${characterField("name", "Character Name", "text", "Name")}
          ${characterSelectField("level", "Level", CHARACTER_LEVEL_OPTIONS, null)}
          ${characterSelectField("species", "Species", getCharacterSpeciesOptions(), "Choose species")}
        </div>
        <div class="character-identity-column">
          ${characterField("player", "Player", "text", "Player")}
          ${characterSelectField("className", "Class", getCharacterClassOptions(), "Choose class")}
          ${renderSubclassField()}
        </div>
        <div class="character-identity-column">
          ${characterSelectField("background", "Background", getCharacterBackgroundOptions(), "Choose background")}
          <div class="character-background-grant-row">
            ${characterOriginFeatGrantField()}
            <label class="character-field character-field--detail-button"><span>Background Grants</span><button id="characterBackgroundDetailsButton" class="button button--ghost character-background-grants-button" type="button">+ Show Grants</button></label>
          </div>
        </div>
        <div class="character-identity-column">
          ${characterField("xp", "XP / Milestone", "text", "XP")}
          ${characterSelectField("size", "Size", CHARACTER_SIZE_OPTIONS, null)}
          ${characterSelectField("alignment", "Alignment", CHARACTER_ALIGNMENT_OPTIONS, "Choose alignment")}
        </div>
      </div>
      ${renderCharacterBackgroundNote()}
      ${renderCharacterMulticlassSection()}
    </section>

    <section class="character-panel">
      <div class="character-panel__heading character-panel__heading--actions"><h3>Ability Scores & Saving Throws</h3><div class="character-heading-actions"><button id="characterStatRollerButton" class="button button--ghost" type="button">Roll Stats</button><button id="characterApplyClassSaves" class="button button--ghost" type="button">Apply Class Saves</button></div></div>
      <div class="ability-grid">${CHARACTER_ABILITIES.map(ability => abilityCard(ability)).join("")}</div>
    </section>
    <section class="character-panel"><div class="character-panel__heading"><h3>Skills</h3><span>Passive Perception ${passivePerception}</span></div><div class="skill-grid">${CHARACTER_SKILLS.map(skill => skillRow(skill)).join("")}</div></section>
    <section class="character-panel">
      <div class="character-panel__heading character-panel__heading--actions"><h3>Combat & Health</h3><div class="character-heading-actions"><span>Initiative ${formatSigned(initiative)}</span><button id="characterHpRollerButton" class="button button--ghost" type="button">Roll HP</button></div></div>
      <div class="character-stat-strip"><div><span>AC</span><strong>${escapeHTML(characterState.armorClass || "10")}</strong></div><div><span>Initiative</span><strong>${formatSigned(initiative)}</strong></div><div><span>Speed</span><strong>${escapeHTML(characterState.speed || "30")} ft.</strong></div><div><span>HP</span><strong>${escapeHTML(characterState.currentHp || 0)} / ${escapeHTML(characterState.maxHp || 0)}</strong></div><div><span>Temp HP</span><strong>${escapeHTML(characterState.tempHp || 0)}</strong></div></div>
      <div class="character-grid">${characterField("armorClass", "Armor Class", "number", "10")}${characterField("speed", "Speed", "number", "30")}${characterField("initiativeBonus", "Initiative Bonus", "number", "0")}${characterField("maxHp", "Max HP", "number", "0")}${characterField("currentHp", "Current HP", "number", "0")}${characterField("tempHp", "Temp HP", "number", "0")}${characterField("hitDice", "Hit Dice", "text", "e.g. 3d10")}${characterField("deathSaveSuccesses", "Death Save Successes", "number", "0", null, 0, 3)}${characterField("deathSaveFailures", "Death Save Failures", "number", "0", null, 0, 3)}</div>
      <label class="character-checkbox character-checkbox--heroic"><input type="checkbox" data-character-field="heroicInspiration" ${characterState.heroicInspiration ? "checked" : ""}><span>Heroic Inspiration</span></label>${renderCharacterHpRollSummary()}
    </section>
    <section class="character-panel">
      <div class="character-panel__heading"><h3>Spellcasting</h3><span>Save DC ${getSpellSaveDc()} · Attack ${getSpellAttackBonus()}</span></div>
      <div class="character-grid">${characterSelectField("spellcastingAbility", "Spellcasting Ability", [{ value: "", label: "None" }, ...CHARACTER_ABILITIES.map(ability => ({ value: ability.key, label: ability.label }))], null)}<label class="character-field character-derived"><span>Spell Save DC</span><strong>${getSpellSaveDc()}</strong></label><label class="character-field character-derived"><span>Spell Attack Bonus</span><strong>${getSpellAttackBonus()}</strong></label></div>
      <div class="spell-slot-grid">${Object.keys(characterState.spellSlots).map(level => `<label class="character-field"><span>Level ${level} Slots</span><input type="text" data-spell-slot="${level}" value="${escapeHTML(characterState.spellSlots[level] || "")}" placeholder="e.g. 4 / 4"></label>`).join("")}</div>
      <div class="character-spell-filter-row">${characterSelectField("selectedSpellLevel", "Selected Spell Level", CHARACTER_SPELL_LEVEL_OPTIONS, null)}<div class="character-selected-spells-summary"><span>Filter the selected spell notes by level so the sheet stays usable during play.</span><strong>${getSelectedSpellSummary()}</strong></div></div>
      ${renderSelectedSpellLevelEditor()}
      <div class="character-grid character-grid--textareas character-grid--spell-notes">${characterTextarea("cantrips", "Cantrips / Always Prepared")}${characterTextarea("preparedSpells", "Prepared Spells Notes")}${characterTextarea("spellbook", "Spellbook / Known Spells Notes")}</div>
    </section>
    <section class="character-panel">
      <div class="character-panel__heading"><h3>Proficiencies, Features & Equipment</h3></div>
      <div class="character-grid character-grid--textareas">
        ${characterTextarea("senses", "Senses")}
        ${characterAddableTextarea("languages", "Languages", getCharacterLanguageOptions(), "Add language")}
        ${characterAddableTextarea("armorTraining", "Armor Proficiencies", CHARACTER_ARMOR_PROFICIENCY_OPTIONS, "Add armor")}
        ${characterAddableTextarea("weaponTraining", "Weapon Proficiencies", CHARACTER_WEAPON_PROFICIENCY_OPTIONS, "Add weapon")}
        ${characterAddableTextarea("toolTraining", "Tool Proficiencies", CHARACTER_TOOL_PROFICIENCY_OPTIONS, "Add tool")}
        ${characterTextarea("features", "Features & Traits")}${characterTextarea("attacks", "Attacks / Actions")}${characterTextarea("equipment", "Equipment")}${renderCharacterCurrencyFields()}${characterTextarea("treasure", "Treasure")}${characterTextarea("backstory", "Backstory")}${characterTextarea("notes", "Notes")}
      </div>
    </section>`;
  bindCharacterCreatorEvents();
}

function characterOriginFeatGrantField() {
  const background = getCurrentBackgroundOption();
  const value = characterState.originFeat || background?.feat || "";
  return `<label class="character-field character-origin-grant-display"><span>Origin Feat Granted</span><input type="text" data-character-field="originFeat" value="${escapeHTML(value)}" placeholder="${getCharacterRulesVersion() === "2014" ? "None in 2014 backgrounds" : "Choose background"}"></label>`;
}
function characterAddableTextarea(key, label, options, placeholder = "Add") {
  const value = characterState[key] || "";
  const normalized = normalizeCharacterSelectOptions(options);
  const listOptions = [{ value: "", label: placeholder, iconKey: "sigil-custom" }, ...normalized];
  const languageToggle = key === "languages" ? `<div class="character-inline-toggle-row">${characterToggleField("expandedLanguages", "Expanded Material", "5e + 5.5e languages")}</div>` : "";
  return `<div class="character-proficiency-field ${key === "languages" ? "character-language-field-wrap" : ""}">${languageToggle}<div class="character-proficiency-add-row">${characterSelectField(`add-${key}`, `${label} List`, listOptions, null, { customData: `data-proficiency-select="${escapeHTML(key)}"`, value: "" })}<button class="button button--ghost character-add-button" type="button" data-proficiency-add-button="${escapeHTML(key)}" aria-label="Add ${escapeHTML(label)}">+</button></div><label class="character-field character-field--textarea"><span>${escapeHTML(label)}</span><textarea data-character-field="${escapeHTML(key)}" rows="4" placeholder="${escapeHTML(label)}">${escapeHTML(value)}</textarea></label></div>`;
}
function getCharacterSelectLabel(option) { return option.label ?? option.value; }
function getCharacterOptionSourceBadge(option) {
  const edition = option?.sourceEdition || "";
  if (!edition || edition === "Table") return "";
  const cls = edition === "5e" ? "character-source-badge--5e" : "character-source-badge--55e";
  return `<span class="character-source-badge ${cls}" title="${escapeHTML(option.source || edition)}">${escapeHTML(edition)}</span>`;
}
function getCharacterOptionNote(option) {
  const note = option?.note || option?.source || "";
  return note ? `<small>${escapeHTML(note)}</small>` : "";
}
function characterSelectField(key, label, values, placeholder = "Choose", config = {}) {
  const value = String(config.value ?? characterState[key] ?? "");
  const options = normalizeCharacterSelectOptions(values);
  const useCustom = options.some(option => option.iconKey || option.sourceEdition || option.note) || key === "rulesVersion";
  const dataAttrs = config.customData ? config.customData : config.multiclassIndex !== undefined ? `data-multiclass-field="${escapeHTML(key)}" data-multiclass-index="${escapeHTML(String(config.multiclassIndex))}"` : `data-character-field="${escapeHTML(key)}"`;
  if (useCustom) return characterCustomSelectField(key, label, options, placeholder, value, dataAttrs);
  const placeholderMarkup = placeholder !== null ? `<option value="">${escapeHTML(placeholder)}</option>` : "";
  return `<label class="character-field character-field--select"><span>${escapeHTML(label)}</span><div class="character-select-wrap"><select ${dataAttrs}>${placeholderMarkup}${options.map(option => `<option value="${escapeHTML(String(option.value))}" ${String(option.value) === value ? "selected" : ""}>${escapeHTML(getCharacterSelectLabel(option))}</option>`).join("")}</select></div></label>`;
}
function characterCustomSelectField(key, label, options, placeholder, value, dataAttrs) {
  const selectedOption = getCharacterOptionByValue(options, value);
  const fallbackIcon = selectedOption?.iconKey || (selectedOption?.sourceEdition === "5e" ? "source-5e" : selectedOption?.sourceEdition === "5.5e" ? "source-5-5" : "sigil-custom");
  const displayLabel = selectedOption ? getCharacterSelectLabel(selectedOption) : (placeholder || "Choose");
  const placeholderOption = placeholder !== null ? [{ value: "", label: placeholder || "Choose", iconKey: "sigil-custom", placeholder: true }] : [];
  const menuOptions = [...placeholderOption, ...options];
  return `<label class="character-field character-field--select character-field--select-icon"><span>${escapeHTML(label)}</span><div class="character-custom-select" data-character-select><input type="hidden" ${dataAttrs} value="${escapeHTML(value)}"><button class="character-custom-select__button" type="button" data-character-select-toggle aria-haspopup="listbox" aria-expanded="false" ${getCharacterIconStyle(fallbackIcon)}><span class="character-custom-select__icon" ${getCharacterIconStyle(fallbackIcon)}>${getCharacterIconSvg(fallbackIcon, selectedOption?.label || label)}</span><span class="character-custom-select__label-wrap"><span class="character-custom-select__label">${escapeHTML(displayLabel)}</span>${selectedOption ? getCharacterOptionNote(selectedOption) : ""}</span>${getCharacterOptionSourceBadge(selectedOption)}<span class="character-custom-select__chevron">⌄</span></button><div class="character-custom-select__menu hidden" data-character-select-menu role="listbox">${menuOptions.map(option => { const optionValue = String(option.value ?? ""); const iconKey = option.iconKey || (option.sourceEdition === "5e" ? "source-5e" : option.sourceEdition === "5.5e" ? "source-5-5" : "sigil-custom"); return `<button class="character-custom-select__option ${option.placeholder ? "is-placeholder" : ""} ${optionValue === value ? "is-selected" : ""}" type="button" role="option" aria-selected="${optionValue === value ? "true" : "false"}" data-character-select-option data-value="${escapeHTML(optionValue)}" ${getCharacterIconStyle(iconKey)}><span class="character-custom-select__option-icon" ${getCharacterIconStyle(iconKey)}>${getCharacterIconSvg(iconKey, option.label || label)}</span><span class="character-custom-select__option-label-wrap"><span class="character-custom-select__option-label">${escapeHTML(getCharacterSelectLabel(option))}</span>${getCharacterOptionNote(option)}</span>${getCharacterOptionSourceBadge(option)}</button>`; }).join("")}</div></div></label>`;
}

function autoFillCharacterOriginFeatFromBackground() {
  const background = getCurrentBackgroundOption();
  if (getCharacterRulesVersion() === "2014") {
    if (!characterState.originFeat || characterState.originFeat === "Custom") characterState.originFeat = "None";
    return;
  }
  if (background?.feat && background.feat !== "Custom" && background.feat !== "None") characterState.originFeat = background.feat;
}
function renderCharacterBackgroundNote() {
  const background = getCurrentBackgroundOption();
  if (!background || !characterState.background) return `<div class="character-origin-note character-background-note"><strong>${getCharacterRulesVersion() === "2014" ? "2014 reminder:" : "2024 reminder:"}</strong> ${getCharacterRulesVersion() === "2014" ? "Backgrounds usually grant skills, tools/languages, equipment, and a feature. They do not grant Origin Feats." : "Background tracks ability score increases, skill/tool proficiencies, equipment, and the Origin Feat."}</div>`;
  return `<div class="character-origin-note character-background-note"><strong>${characterInlineIcon(background.iconKey, background.label)}${escapeHTML(background.label)} Background ${getCharacterOptionSourceBadge(background)}</strong><div class="character-origin-note__chips"><span>Origin Feat: ${escapeHTML(background.feat || "None")}</span><span>ASI: ${escapeHTML(background.abilities || "None")}</span><span>Skills: ${escapeHTML(background.skills || "Custom")}</span><span>Tool: ${escapeHTML(background.tools || "Custom")}</span></div><small>${escapeHTML(getCharacterRulesVersion() === "2014" ? "2014 backgrounds do not automatically grant Origin Feats. Use Custom if your table adds one." : getCharacterOriginFeatDetail(background.feat))}</small></div>`;
}
function openCharacterBackgroundDetailsDialog() {
  const background = getCurrentBackgroundOption();
  if (!background || !characterState.background) { showToast("Choose a background first."); return; }
  const is2014 = getCharacterRulesVersion() === "2014";
  const dialog = document.createElement("dialog");
  dialog.className = "dialog character-background-dialog";
  dialog.innerHTML = `<form method="dialog"><div class="dialog-title-row"><h2><span class="character-dialog-title-icon" ${getCharacterIconStyle(background.iconKey)}>${getCharacterIconSvg(background.iconKey, background.label)}</span>${escapeHTML(background.label)} Background ${getCharacterOptionSourceBadge(background)}</h2><button class="dialog-x-button" value="cancel" aria-label="Close">×</button></div><p>${is2014 ? "These are pre-2024 background grants. Origin Feat is normally none unless your table adds one." : "These are the 2024 background grants applied to this character sheet."}</p><div class="character-background-detail-grid">${renderCharacterBackgroundDetailCard(is2014 ? "Ability Scores" : "Ability Score Options", background.abilities, is2014 ? "2014 backgrounds normally do not grant ability score increases." : "Choose +2/+1 or +1/+1/+1 among these abilities.")}${renderCharacterBackgroundDetailCard("Skill Proficiencies", background.skills)}${renderCharacterBackgroundDetailCard("Tool / Language Proficiency", background.tools)}${renderCharacterBackgroundDetailCard("Origin Feat", background.feat, is2014 ? "No Origin Feat by default in 2014 rules." : getCharacterOriginFeatDetail(background.feat))}<div class="character-background-detail-card character-background-detail-card--wide"><span>Background Summary</span><strong>${escapeHTML(background.label)}</strong><p>${escapeHTML(`Source: ${background.source || background.sourceEdition || "Custom"}. ASI: ${background.abilities || "None"}. Skills: ${background.skills || "Custom"}. Tool/Language: ${background.tools || "Custom"}. Origin Feat: ${background.feat || "None"}. ${is2014 ? "2014 background features/equipment vary by book; add table-specific details in Features & Traits." : getCharacterOriginFeatDetail(background.feat)}`)}</p></div></div><div class="dialog-actions"><button class="button" value="default">Close</button></div></form>`;
  document.body.append(dialog);
  dialog.addEventListener("close", () => dialog.remove());
  dialog.addEventListener("click", event => { if (event.target === dialog) dialog.close(); });
  dialog.showModal();
}

function renderCharacterMulticlassSection() {
  const entries = Array.isArray(characterState.multiclasses) ? characterState.multiclasses : [];
  return `<div class="character-multiclass-panel"><div class="character-multiclass-panel__head"><div><strong>Multiclassing</strong><div class="character-multiclass-summary">${renderCharacterMulticlassSummary()}</div></div><button id="characterAddMulticlass" class="button button--ghost" type="button">+ Add Multiclass</button></div>${entries.length ? `<div class="character-multiclass-list">${entries.map((entry, index) => `<div class="character-multiclass-row" data-multiclass-row="${index}">${characterSelectField("className", "Class", getCharacterClassOptions(), "Choose class", { multiclassIndex: index, value: entry.className })}${characterSelectField("subclass", "Subclass", getCharacterSubclassOptions(entry.className), entry.className ? "Choose subclass" : "Choose class first", { multiclassIndex: index, value: entry.subclass })}<label class="character-field"><span>Levels</span><input type="number" data-multiclass-field="level" data-multiclass-index="${index}" min="1" max="20" value="${escapeHTML(String(entry.level || 1))}" placeholder="1"></label><button class="button button--ghost character-multiclass-remove" type="button" data-remove-multiclass="${index}">Remove</button></div>`).join("")}</div>` : ""}</div>`;
}

function setCharacterFieldFromInput(input) {
  const key = input.dataset.characterField;
  if (input.type === "checkbox") characterState[key] = input.checked;
  else if (input.type === "number" || key === "level") characterState[key] = Number(input.value) || 0;
  else characterState[key] = input.value;
  if (key === "rulesVersion") {
    characterState.rulesVersion = characterState.rulesVersion === "2014" ? "2014" : "2024";
    if (characterState.rulesVersion === "2014" && (!characterState.originFeat || characterState.originFeat !== "Custom / Other")) characterState.originFeat = "None";
  }
  if (key === "background") autoFillCharacterOriginFeatFromBackground();
  if (key === "className" && !isSubclassValidForClass(characterState.className, characterState.subclass)) characterState.subclass = "";
}
function isSubclassValidForClass(className, subclass) {
  if (!subclass || subclass === "Custom / Other") return true;
  return getCharacterSubclassOptions(className).some(option => String(option.value) === String(subclass));
}

function getCharacterExportSummary() {
  if (!characterState) characterState = createDefaultCharacter();
  const pb = getCharacterProficiencyBonus();
  const initiative = getAbilityModifier(characterState.abilities.dex) + (Number(characterState.initiativeBonus) || 0);
  const passivePerception = 10 + getSkillModifier({ name: "Perception", ability: "wis" });
  const bg = getCurrentBackgroundOption();
  return { name: getCharacterDisplayValue(characterState.name, "Unnamed Character"), player: getCharacterDisplayValue(characterState.player), className: getCharacterOptionLabel(getCurrentClassOptionsForExport(), characterState.className), subclass: getCharacterDisplayValue(characterState.subclass), level: `Level ${characterState.level || 1}`, species: getCharacterOptionLabel(getCurrentSpeciesOptionsForExport(), characterState.species), size: getCharacterDisplayValue(characterState.size), background: getCharacterOptionLabel(getCurrentBackgroundOptionsForExport(), characterState.background), backgroundTools: getCharacterDisplayValue(bg?.tools), backgroundSkills: getCharacterDisplayValue(bg?.skills), backgroundAbilities: getCharacterDisplayValue(bg?.abilities), originFeat: getCharacterDisplayValue(characterState.originFeat), originFeatDetail: getCharacterOriginFeatDetail(characterState.originFeat), multiclass: getCharacterMulticlassExportText(), alignment: getCharacterDisplayValue(characterState.alignment), pb: formatSigned(pb), initiative: formatSigned(initiative), passivePerception, spellDc: getSpellSaveDc(), spellAttack: getSpellAttackBonus(), rulesVersion: getCharacterRulesVersion() === "2014" ? "5e / 2014" : "5.5e / 2024" };
}
function createCharacterExportSvg() {
  createCharacterExportPayload();
  const summary = getCharacterExportSummary();
  const width = 1400, height = 1900;
  const abilityCards = CHARACTER_ABILITIES.map((ability, index) => { const x = 70 + index * 205; const y = 430; const score = Number(characterState.abilities[ability.key]) || 10; return `<rect x="${x}" y="${y}" width="170" height="128" rx="18" fill="#201f35" stroke="#514c84"/><text x="${x + 18}" y="${y + 35}" fill="#bbb7ff" font-size="17" font-weight="900">${escapeXML(ability.short)}</text><text x="${x + 18}" y="${y + 78}" fill="#ffffff" font-size="42" font-weight="900">${score}</text><text x="${x + 96}" y="${y + 76}" fill="#fff0c9" font-size="28" font-weight="900">${formatSigned(getAbilityModifier(score))}</text><text x="${x + 18}" y="${y + 105}" fill="#c7c2b6" font-size="16">Save ${formatSigned(getSaveModifier(ability))}</text>`; }).join("");
  const combatMarkup = [["AC", characterState.armorClass || 10], ["Initiative", summary.initiative], ["Speed", `${characterState.speed || 30} ft.`], ["HP", `${characterState.currentHp || 0} / ${characterState.maxHp || 0}`], ["Temp HP", characterState.tempHp || 0], ["Hit Dice", characterState.hitDice || "—"]].map((item, index) => { const col = index % 3, row = Math.floor(index / 3), x = 90 + col * 200, y = 665 + row * 78; return `<text x="${x}" y="${y}" fill="#b9a7ff" font-size="15" font-weight="900">${escapeXML(item[0])}</text><text x="${x}" y="${y + 30}" fill="#ffffff" font-size="28" font-weight="900">${escapeXML(item[1])}</text>`; }).join("");
  const skills = CHARACTER_SKILLS.map(skill => `${skill.name} ${formatSigned(getSkillModifier(skill))}`).join(" · ");
  const spellSlots = Object.keys(characterState.spellSlots).map(level => `L${level}: ${characterState.spellSlots[level] || "—"}`).join("   ");
  const spellText = `DC ${summary.spellDc} · Attack ${summary.spellAttack} · ${spellSlots} · Selected: ${getSelectedSpellExportText()}`;
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}"><defs><linearGradient id="charBg" x1="0" x2="1" y1="0" y2="1"><stop offset="0" stop-color="#0b0d15"/><stop offset="0.52" stop-color="#151827"/><stop offset="1" stop-color="#080a10"/></linearGradient><radialGradient id="charGlow" cx="28%" cy="4%" r="88%"><stop offset="0" stop-color="#b9a7ff" stop-opacity="0.32"/><stop offset="0.42" stop-color="#7ed7ff" stop-opacity="0.12"/><stop offset="1" stop-color="#000000" stop-opacity="0"/></radialGradient></defs><rect width="100%" height="100%" rx="34" fill="url(#charBg)"/><rect width="100%" height="100%" rx="34" fill="url(#charGlow)"/><rect x="38" y="38" width="${width - 76}" height="${height - 76}" rx="30" fill="#121520" stroke="#5c4c2e"/><text x="70" y="105" fill="#fff0c9" font-size="18" font-weight="900" letter-spacing="3">D&D HOMEBREW COMPENDIUM · ${escapeXML(summary.rulesVersion)} CHARACTER SHEET</text><text x="70" y="168" fill="#ffffff" font-size="58" font-weight="900">${escapeXML(summary.name)}</text><text x="72" y="212" fill="#c8c2e8" font-size="24" font-weight="750">${escapeXML(`${summary.className} · ${summary.subclass} · ${summary.level}`)}</text><text x="72" y="248" fill="#bbb7aa" font-size="20">${escapeXML(`${summary.species} · ${summary.background} · ${summary.alignment} · Player: ${summary.player}`)}</text>${svgPanel(60,300,1280,100,"ORIGIN",svgTextBlock(wrapTextLines(`Size ${summary.size} · Origin Feat ${summary.originFeat} · BG Skills ${summary.backgroundSkills} · Tools ${summary.backgroundTools} · Multiclass ${summary.multiclass} · PB ${summary.pb} · Passive Perception ${summary.passivePerception}`,112,2),88,358,{size:22,fill:"#f2efe7",weight:700}))}${svgPanel(60,405,1280,180,"ABILITY SCORES & SAVES",abilityCards)}${svgPanel(60,610,630,230,"COMBAT",combatMarkup)}${svgPanel(710,610,630,230,"SKILLS",svgTextBlock(wrapTextLines(skills,72,7),738,668,{size:18,fill:"#f2efe7",weight:650,gap:25}))}${svgPanel(60,870,1280,245,"SPELLCASTING",svgTextBlock(wrapTextLines(spellText,120,7),88,928,{size:19,fill:"#f2efe7",weight:650,gap:28}))}${svgPanel(60,1145,625,250,"FEATURES & TRAITS",svgTextBlock(wrapTextLines(getCharacterTextSection("features"),58,7),88,1204,{size:18,fill:"#f2efe7",weight:650,gap:27}))}${svgPanel(715,1145,625,250,"ATTACKS / ACTIONS",svgTextBlock(wrapTextLines(getCharacterTextSection("attacks"),58,7),743,1204,{size:18,fill:"#f2efe7",weight:650,gap:27}))}${svgPanel(60,1425,625,250,"EQUIPMENT & TREASURE",svgTextBlock(wrapTextLines(`${getCharacterTextSection("equipment")} · Currency: ${getCharacterCurrencyText()} · Treasure: ${getCharacterTextSection("treasure")}`,58,7),88,1484,{size:18,fill:"#f2efe7",weight:650,gap:27}))}${svgPanel(715,1425,625,250,"NOTES",svgTextBlock(wrapTextLines(getCharacterTextSection("notes"),58,7),743,1484,{size:18,fill:"#f2efe7",weight:650,gap:27}))}<text x="70" y="1810" fill="#8f8ca0" font-size="16">Exported ${escapeXML(new Date().toLocaleString())}</text></svg>`;
}
function exportCharacterImage() {
  const svg = createCharacterExportSvg();
  const filename = `character-${getCharacterExportSlug()}.png`;
  const svgBlob = new Blob([svg], { type: "image/svg+xml;charset=utf-8" });
  const url = URL.createObjectURL(svgBlob);
  const image = new Image();
  image.onload = () => {
    try {
      const canvas = document.createElement("canvas");
      canvas.width = image.width || 1400;
      canvas.height = image.height || 1900;
      const ctx = canvas.getContext("2d");
      ctx.drawImage(image, 0, 0);
      canvas.toBlob(blob => {
        URL.revokeObjectURL(url);
        if (!blob) { downloadBlob(svg, `character-${getCharacterExportSlug()}.svg`, "image/svg+xml"); showToast("PNG failed; exported SVG fallback."); return; }
        downloadBlob(blob, filename, "image/png");
        showToast("Character image exported as PNG.");
      }, "image/png");
    } catch (error) {
      console.error(error);
      URL.revokeObjectURL(url);
      downloadBlob(svg, `character-${getCharacterExportSlug()}.svg`, "image/svg+xml");
      showToast("PNG failed; exported SVG fallback.");
    }
  };
  image.onerror = () => { URL.revokeObjectURL(url); downloadBlob(svg, `character-${getCharacterExportSlug()}.svg`, "image/svg+xml"); showToast("PNG failed; exported SVG fallback."); };
  image.src = url;
}



/* v5.69: themed dropdown override + multiclass level dropdown + centered background details */
function getCharacterLevelDropdownOptions() {
  return Array.from({ length: 20 }, (_, index) => ({
    value: String(index + 1),
    label: `Level ${index + 1}`,
    iconKey: "source-5-5"
  }));
}

function characterSelectField(key, label, values, placeholder = "Choose", config = {}) {
  const value = String(config.value ?? (characterState ? characterState[key] : "") ?? "");
  const options = normalizeCharacterSelectOptions(values).map(option => ({
    iconKey: option.iconKey || (option.sourceEdition === "5e" ? "source-5e" : option.sourceEdition === "5.5e" ? "source-5-5" : "sigil-custom"),
    ...option
  }));
  const dataAttrs = config.customData
    ? config.customData
    : config.multiclassIndex !== undefined
    ? `data-multiclass-field="${escapeHTML(key)}" data-multiclass-index="${escapeHTML(String(config.multiclassIndex))}"`
    : `data-character-field="${escapeHTML(key)}"`;
  return characterCustomSelectField(key, label, options, placeholder, value, dataAttrs);
}

function renderCharacterMulticlassSection() {
  const entries = Array.isArray(characterState.multiclasses) ? characterState.multiclasses : [];
  const levelOptions = getCharacterLevelDropdownOptions();
  return `
    <div class="character-multiclass-panel">
      <div class="character-multiclass-panel__head">
        <div>
          <strong>Multiclassing</strong>
          <div class="character-multiclass-summary">${renderCharacterMulticlassSummary()}</div>
        </div>
        <button id="characterAddMulticlass" class="button button--ghost" type="button">+ Add Multiclass</button>
      </div>
      ${entries.length ? `<div class="character-multiclass-list">
        ${entries.map((entry, index) => `<div class="character-multiclass-row" data-multiclass-row="${index}">
          ${characterSelectField("className", "Class", getCharacterClassOptions(), "Choose class", { multiclassIndex: index, value: entry.className })}
          ${characterSelectField("subclass", "Subclass", getCharacterSubclassOptions(entry.className), entry.className ? "Choose subclass" : "Choose class first", { multiclassIndex: index, value: entry.subclass })}
          ${characterSelectField("level", "Levels", levelOptions, null, { multiclassIndex: index, value: String(entry.level || 1) })}
          <button class="button button--ghost character-multiclass-remove" type="button" data-remove-multiclass="${index}">Remove</button>
        </div>`).join("")}
      </div>` : ""}
    </div>
  `;
}

function openCharacterBackgroundDetailsDialog() {
  const background = getCurrentBackgroundOption();
  if (!background || !characterState.background) {
    showToast("Choose a background first.");
    return;
  }
  const is2014 = getCharacterRulesVersion() === "2014";
  const sourceText = background.source || background.sourceEdition || "Custom";
  const summary = `Source: ${sourceText}. ASI: ${background.abilities || "None"}. Skills: ${background.skills || "Custom"}. Tool/Language: ${background.tools || "Custom"}. Origin Feat: ${background.feat || "None"}. ${is2014 ? "2014 background features and equipment vary by book; add table-specific details in Features & Traits." : getCharacterOriginFeatDetail(background.feat)}`;
  const dialog = document.createElement("dialog");
  dialog.className = "dialog character-background-dialog";
  dialog.innerHTML = `
    <form method="dialog">
      <div class="dialog-title-row">
        <h2><span class="character-dialog-title-icon" ${getCharacterIconStyle(background.iconKey)}>${getCharacterIconSvg(background.iconKey, background.label)}</span>${escapeHTML(background.label)} Background ${getCharacterOptionSourceBadge(background)}</h2>
        <button class="dialog-x-button" value="cancel" aria-label="Close">×</button>
      </div>
      <p>${escapeHTML(is2014 ? "These are pre-2024 background grants. Origin Feat is normally none unless your table adds one." : "These are the 2024 background grants applied to this character sheet.")}</p>
      <div class="character-background-detail-grid">
        ${renderCharacterBackgroundDetailCard(is2014 ? "Ability Scores" : "Ability Score Options", background.abilities, is2014 ? "2014 backgrounds normally do not grant ability score increases." : "Choose +2/+1 or +1/+1/+1 among these abilities.")}
        ${renderCharacterBackgroundDetailCard("Skill Proficiencies", background.skills)}
        ${renderCharacterBackgroundDetailCard("Tool / Language Proficiency", background.tools)}
        ${renderCharacterBackgroundDetailCard("Origin Feat", background.feat, is2014 ? "No Origin Feat by default in 2014 rules." : getCharacterOriginFeatDetail(background.feat))}
        <div class="character-background-detail-card character-background-detail-card--wide">
          <span>Background Summary</span>
          <strong>${escapeHTML(background.label)}</strong>
          <p>${escapeHTML(summary)}</p>
        </div>
      </div>
      <div class="dialog-actions"><button class="button" value="default">Close</button></div>
    </form>`;
  document.body.append(dialog);
  dialog.addEventListener("close", () => dialog.remove());
  dialog.addEventListener("click", event => { if (event.target === dialog) dialog.close(); });
  dialog.showModal();
}



