function toggleExportMenu() {
  const isOpen = els.exportMenu.classList.toggle("is-open");
  els.exportMenuButton.setAttribute("aria-expanded", String(isOpen));
}

function closeExportMenu() {
  els.exportMenu.classList.remove("is-open");
  els.exportMenuButton.setAttribute("aria-expanded", "false");
}

function toggleCharacterExportMenu() {
  if (!els.characterExportMenu || !els.characterExportMenuButton) return;
  const isOpen = els.characterExportMenu.classList.toggle("is-open");
  els.characterExportMenuButton.setAttribute("aria-expanded", String(isOpen));
}

function closeCharacterExportMenu() {
  if (!els.characterExportMenu || !els.characterExportMenuButton) return;
  els.characterExportMenu.classList.remove("is-open");
  els.characterExportMenuButton.setAttribute("aria-expanded", "false");
}

function createEmptyBuild(slot = "1") {
  return {
    name: `Build Slot ${slot}`,
    level: 6,
    selected: [],
    expandedDetails: [],
    viewMode: "simple"
  };
}

function createDefaultBuilds() {
  const slots = {};
  for (let slot = 1; slot <= SLOT_COUNT; slot += 1) {
    slots[String(slot)] = createEmptyBuild(String(slot));
  }
  return { activeSlot: "1", slots };
}

function normalizeBuild(build, slot = "1") {
  const fallback = createEmptyBuild(slot);
  return {
    ...fallback,
    ...(build || {}),
    level: Math.max(1, Math.min(20, Number(build?.level) || fallback.level)),
    selected: Array.isArray(build?.selected) ? build.selected.filter(id => tacticById[id]) : [],
    expandedDetails: Array.isArray(build?.expandedDetails) ? build.expandedDetails.filter(id => tacticById[id]) : [],
    viewMode: build?.viewMode === "detailed" ? "detailed" : "simple"
  };
}

function syncActiveBuild() {
  builds.slots[builds.activeSlot] = state;
}

function toggleBuildSlotMenu() {
  const isOpen = els.buildSlotPicker.classList.toggle("is-open");
  els.buildSlotButton.setAttribute("aria-expanded", String(isOpen));
}

function closeBuildSlotMenu() {
  els.buildSlotPicker.classList.remove("is-open");
  els.buildSlotButton.setAttribute("aria-expanded", "false");
}

function setBuildSlot(slot) {
  els.buildSlotSelect.value = slot;
  switchBuildSlot();
}

function switchBuildSlot() {
  syncActiveBuild();
  builds.activeSlot = els.buildSlotSelect.value;
  state = builds.slots[builds.activeSlot] || createEmptyBuild(builds.activeSlot);
  state = normalizeBuild(state, builds.activeSlot);
  syncActiveBuild();
  pruneInvalidSelections("Build slot cleaned up.");
  saveAndRender();
  showToast(`Loaded ${state.name}.`);
}

function clearCurrentSlot() {
  state = createEmptyBuild(builds.activeSlot);
  syncActiveBuild();
  saveAndRender();
  showToast(`Slot ${builds.activeSlot} cleared.`);
}

function setGlobalDescriptionMode(mode) {
  if (mode === "detailed") {
    state.viewMode = "detailed";
    state.expandedDetails = tactics.map(tactic => tactic.id);
  } else {
    state.viewMode = "simple";
    state.expandedDetails = [];
  }

  syncActiveBuild();
  saveAndRender();
}

function toggleCardDetails(tacticId) {
  const expanded = new Set(state.expandedDetails || []);

  if (expanded.has(tacticId)) expanded.delete(tacticId);
  else expanded.add(tacticId);

  state.expandedDetails = [...expanded];

  if (state.expandedDetails.length === 0) state.viewMode = "simple";
  else if (state.expandedDetails.length === tactics.length) state.viewMode = "detailed";
  else state.viewMode = "custom";

  syncActiveBuild();
  saveAndRender();
}

function isTacticExpanded(tacticId) {
  return (state.expandedDetails || []).includes(tacticId);
}

function setLevel(level) {
  const nextLevel = Math.max(1, Math.min(20, Number(level) || 1));
  if (state.level === nextLevel) {
    renderLevelPicker();
    return;
  }

  state.level = nextLevel;
  els.levelSelect.value = String(state.level);
  pruneInvalidSelections("Level changed. Locked or over-limit selections were removed.");
  saveAndRender();
}

function toggleLevelPicker() {
  const isOpen = els.levelPicker.classList.toggle("is-open");
  els.levelPickerButton.setAttribute("aria-expanded", String(isOpen));
}

function closeLevelPicker() {
  els.levelPicker.classList.remove("is-open");
  els.levelPickerButton.setAttribute("aria-expanded", "false");
}

function renderLevelPicker() {
  els.levelSelect.value = String(state.level);
  els.levelPickerLabel.textContent = getLevelLabel(state.level);
  els.levelPickerMeta.textContent = getLevelMeta(state.level);

  for (const option of els.levelPickerMenu.querySelectorAll(".level-picker__option")) {
    const isSelected = option.dataset.value === String(state.level);
    option.classList.toggle("is-selected", isSelected);
    option.setAttribute("aria-selected", String(isSelected));
  }
}

function getBudgets(level = state.level) {
  return {
    1: level >= 8 ? 3 : level >= 6 ? 2 : 0,
    2: level >= 12 ? 3 : level >= 10 ? 2 : 0,
    3: level >= 16 ? 3 : level >= 14 ? 2 : 0
  };
}

function getAutoTier(level = state.level) {
  if (level >= 14) return 3;
  if (level >= 10) return 2;
  if (level >= 6) return 1;
  return 0;
}

function getTierCap() {
  return getAutoTier();
}

function getSelectedSet() {
  return new Set(state.selected);
}

function getSelectedCounts() {
  const counts = { 1: 0, 2: 0, 3: 0 };
  for (const id of state.selected) {
    const tactic = tacticById[id];
    if (tactic) counts[tactic.tier] += 1;
  }
  return counts;
}

function missingPrereqs(tactic) {
  const selected = getSelectedSet();
  return tactic.prereqs.filter(prereqId => !selected.has(prereqId));
}

function getAvailability(tactic) {
  const selected = getSelectedSet();
  const counts = getSelectedCounts();
  const budgets = getBudgets();
  const cap = getTierCap();

  if (selected.has(tactic.id)) {
    return { status: "selected", label: "Selected", reason: "" };
  }

  if (tactic.tier > cap) {
    return { status: "locked", label: "Locked", reason: `${tierInfo[tactic.tier].label} unlocks at ${tierInfo[tactic.tier].unlockLevel}th level.` };
  }

  if (budgets[tactic.tier] <= 0) {
    return { status: "locked", label: "Locked", reason: `No ${tierInfo[tactic.tier].label} picks are available at this level.` };
  }

  const missing = missingPrereqs(tactic);
  if (missing.length > 0) {
    const names = missing.map(id => tacticById[id]?.name ?? id).join(", ");
    return { status: "locked", label: "Locked", reason: `Requires ${names}.` };
  }

  if (counts[tactic.tier] >= budgets[tactic.tier]) {
    return { status: "locked", label: "Locked", reason: `You have used all ${tierInfo[tactic.tier].label} picks.` };
  }

  return { status: "available", label: "Available", reason: "" };
}

function render() {
  renderLevelPicker();
  renderBuildControls();
  renderViewMode();
  renderSummary();
  renderTree();

  if (lastChangedId) {
    window.setTimeout(() => {
      const escapedId = window.CSS?.escape ? CSS.escape(lastChangedId) : String(lastChangedId).replace(/["\\]/g, "\\$&");
      const card = document.querySelector(`[data-id="${escapedId}"]`);
      card?.classList.remove("just-selected");
      lastChangedId = null;
    }, 1200);
  }
}

function renderBuildControls() {
  els.buildSlotSelect.value = builds.activeSlot;
  els.buildNameInput.value = state.name || `Build Slot ${builds.activeSlot}`;
  renderBuildSlotPicker();
}

function renderBuildSlotPicker() {
  const activeName = state.name || `Build Slot ${builds.activeSlot}`;
  els.buildSlotLabel.textContent = `Slot ${builds.activeSlot}`;
  els.buildSlotMeta.textContent = activeName;

  els.buildSlotMenu.querySelectorAll(".build-slot-picker__option").forEach(button => {
    const slot = button.dataset.slot;
    const build = builds.slots[slot] || createEmptyBuild(slot);
    const selectedCount = Array.isArray(build.selected) ? build.selected.length : 0;
    const isActive = slot === builds.activeSlot;

    button.classList.toggle("is-selected", isActive);
    button.setAttribute("aria-selected", String(isActive));
    button.innerHTML = `
      <span>
        <strong>Slot ${slot}</strong>
        <small>${escapeHTML(build.name || `Build Slot ${slot}`)}</small>
      </span>
      <em>${selectedCount} chosen</em>
    `;
  });
}

function renderViewMode() {
  document.body.classList.toggle("is-dm-editing", dmEditMode);
  if (els.dmEditToggle) {
    els.dmEditToggle.classList.toggle("is-active", dmEditMode);
    els.dmEditToggle.textContent = dmEditMode ? "Exit DM Mode" : "DM Mode";
  }

  const expandedCount = (state.expandedDetails || []).length;
  const allExpanded = expandedCount === tactics.length;
  const noneExpanded = expandedCount === 0;
  const mode = allExpanded ? "detailed" : noneExpanded ? "simple" : "custom";

  document.body.dataset.view = mode;
  els.detailedViewButton.classList.toggle("is-active", allExpanded);
  els.compactViewButton.classList.toggle("is-active", noneExpanded);
  els.detailedViewButton.textContent = "Detailed";
  els.compactViewButton.textContent = "Simple";
}

function renderTierStatus() {}

function renderSummary() {
  els.summary.innerHTML = "";
  const budgets = getBudgets();

  for (const tier of [1, 2, 3]) {
    const selectedInTier = state.selected
      .map(id => tacticById[id])
      .filter(Boolean)
      .filter(tactic => tactic.tier === tier);

    const row = document.createElement("div");
    row.className = `summary-row ${selectedInTier.length ? "has-selected" : ""}`;
    row.innerHTML = `<span>${tierInfo[tier].label}</span><strong>${selectedInTier.length} / ${budgets[tier]}</strong>`;
    els.summary.append(row);

    const list = document.createElement("div");
    list.className = "summary-list";
    if (selectedInTier.length > 0) {
      list.innerHTML = selectedInTier.map(tactic => `<div>${escapeHTML(tactic.name)}</div>`).join("");
    } else {
      list.innerHTML = `<div class="summary-empty">No selected tactics</div>`;
    }
    els.summary.append(list);
  }
}

function renderTree() {
  renderWarActiveFilters();
  const query = els.searchInput.value.trim().toLowerCase();
  const isFiltering = Boolean(query) || activeFilters.size > 0 || selectedOnlyFilter;
  els.tree.innerHTML = "";

  const pathsSection = document.createElement("section");
  pathsSection.className = "tree-section paths-section";
  pathsSection.innerHTML = `
    <div class="section-heading section-heading--compact">
      <div>
        <h2>Paths <span class="heading-parenthetical">(Upgradable Lines)</span></h2>
      </div>
    </div>
    <div class="tier-rail" aria-hidden="true"><span></span><strong>Tier I</strong><strong>Tier II</strong><strong>Tier III</strong></div>
  `;

  const pathsList = document.createElement("div");
  pathsList.className = "paths-list";
  let visiblePathRows = 0;

  for (const path of pathDefinitions) {
    const row = document.createElement("article");
    const selectedInPath = path.tacticIds.filter(id => id && state.selected.includes(id)).length;
    const pathTactics = path.tacticIds.map(id => id ? tacticById[id] : null).filter(Boolean);
    const pathMatches = !isFiltering || pathTactics.some(tactic => tacticMatchesSearch(tactic, query) && tacticMatchesFilters(tactic));
    const recommendedId = getRecommendedPathTactic(path);

    row.className = `path-row ${selectedInPath > 0 ? "is-active-path" : ""}`;
    row.dataset.path = path.id;

    const title = document.createElement("div");
    title.className = `path-title ${selectedInPath > 0 ? "is-lit" : ""}`;
    title.innerHTML = `<span class="path-title__icon">${getIconMarkup(pathAccentIcons[path.id] || "star")}</span><strong>${escapeHTML(path.label)}</strong>`;
    row.append(title);

    for (let index = 0; index < path.tacticIds.length; index += 1) {
      const id = path.tacticIds[index];
      const slot = document.createElement("div");
      slot.className = "path-slot";

      const currentSelected = id && state.selected.includes(id);
      const nextId = path.tacticIds[index + 1];
      const nextSelected = nextId && state.selected.includes(nextId);
      if (currentSelected && nextSelected) slot.classList.add("has-selected-connection");

      if (id && tacticById[id]) {
        const tactic = tacticById[id];
        const card = renderCard(tactic, query, { ignoreFilters: true, isRecommended: id === recommendedId });
        slot.append(card);
      } else {
        slot.innerHTML = `<div class="empty-slot"><span>No upgrade</span></div>`;
      }
      row.append(slot);
    }

    if (isFiltering && !pathMatches) row.classList.add("hidden-by-search");
    else visiblePathRows += 1;
    pathsList.append(row);
  }

  if (isFiltering && visiblePathRows === 0) {
    const empty = document.createElement("div");
    empty.className = "empty-results";
    empty.textContent = "No matching paths.";
    pathsList.append(empty);
  }

  pathsSection.append(pathsList);
  els.tree.append(pathsSection);

  const tacticsSection = document.createElement("section");
  tacticsSection.className = "tree-section tactics-section";
  tacticsSection.innerHTML = `
    <div class="section-heading section-heading--compact">
      <div>
        <h2>Tactics <span class="heading-parenthetical">(Standalone Options)</span></h2>
      </div>
    </div>
  `;

  const standaloneGrid = document.createElement("div");
  standaloneGrid.className = "standalone-grid";
  let visibleStandaloneCards = 0;

  for (const tier of [1, 2, 3]) {
    const column = document.createElement("section");
    column.className = "standalone-column";
    column.dataset.tier = String(tier);

    const header = document.createElement("div");
    header.className = "standalone-tier-header";
    header.innerHTML = `<h3>${tierInfo[tier].label}</h3><p>${tierInfo[tier].subtitle}</p>`;
    column.append(header);

    const tierTactics = standaloneTactics.filter(tactic => tactic.tier === tier);
    let visibleInTier = 0;
    for (const tactic of tierTactics) {
      const card = renderCard(tactic, query);
      column.append(card);
      if (!card.classList.contains("hidden-by-search")) visibleInTier += 1;
    }

    if (isFiltering && visibleInTier === 0) {
      const empty = document.createElement("div");
      empty.className = "empty-results";
      empty.textContent = "No matching tactics in this tier.";
      column.append(empty);
    } else {
      visibleStandaloneCards += visibleInTier;
    }

    standaloneGrid.append(column);
  }

  tacticsSection.append(standaloneGrid);
  els.tree.append(tacticsSection);
}

function tacticMatchesSearch(tactic, query) {
  if (!query) return true;

  const exactSearchable = [
    tactic.name,
    tactic.prereqText || "",
    ...(tactic.aliases || []),
    tactic.summary || "",
    ...(tacticActionTags[tactic.id] || []),
    ...(tacticCategories[tactic.id] || []),
    stripHTML(tactic.text)
  ].join(" ").toLowerCase();

  const normalizedQuery = normalizeSearchText(query);
  if (normalizeSearchText(exactSearchable).includes(normalizedQuery)) return true;

  const titleSearchable = [
    tactic.name,
    tactic.prereqText || "",
    ...(tactic.aliases || [])
  ].join(" ").toLowerCase();

  return fuzzyTitleMatch(titleSearchable, query);
}

function fuzzyTitleMatch(titleText, query) {
  const normalizedTitle = normalizeSearchText(titleText);
  const normalizedQuery = normalizeSearchText(query);
  if (!normalizedQuery) return true;
  if (normalizedTitle.includes(normalizedQuery)) return true;

  const titleWords = normalizedTitle.split(/\s+/).filter(Boolean);
  const queryWords = normalizedQuery.split(/\s+/).filter(Boolean);

  return queryWords.every(queryWord => {
    if (queryWord.length <= 2) {
      return titleWords.some(word => word.startsWith(queryWord));
    }

    return titleWords.some(word => {
      const limit = queryWord.length <= 5 ? 1 : 2;
      return levenshteinDistance(word, queryWord, limit) <= limit;
    });
  });
}

function normalizeSearchText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function levenshteinDistance(a, b, limit = 2) {
  if (Math.abs(a.length - b.length) > limit) return limit + 1;

  let previous = Array.from({ length: b.length + 1 }, (_, index) => index);

  for (let i = 1; i <= a.length; i += 1) {
    const current = [i];
    let rowMin = current[0];

    for (let j = 1; j <= b.length; j += 1) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      const value = Math.min(
        current[j - 1] + 1,
        previous[j] + 1,
        previous[j - 1] + cost
      );
      current[j] = value;
      rowMin = Math.min(rowMin, value);
    }

    if (rowMin > limit) return limit + 1;
    previous = current;
  }

  return previous[b.length];
}

function tacticMatchesFilters(tactic) {
  if (tacticFavoritesOnly && !isFavorite("tactic", tactic.id)) return false;
  if (selectedOnlyFilter && !state.selected.includes(tactic.id)) return false;
  if (activeFilters.size === 0) return true;

  const tacticTags = tacticCategories[tactic.id] || [];
  for (const tag of tacticTags) {
    if (activeFilters.has(tag)) return true;
  }

  return false;
}


function getRecommendedPathTactic(path) {
  if (!path.tacticIds.some(id => id && state.selected.includes(id))) return null;

  for (const id of path.tacticIds) {
    if (!id || state.selected.includes(id)) continue;
    const tactic = tacticById[id];
    if (tactic && getAvailability(tactic).status === "available") return id;
  }

  return null;
}

function shortenLockReason(reason) {
  return String(reason || "")
    .replace("Requires ", "Req: ")
    .replace("You have used all ", "Limit: ")
    .replace("No ", "No ")
    .replace(" picks are available at this level.", " picks")
    .replace(" unlocks at ", " @ ");
}

function renderActionTags(tactic) {
  const tags = tacticActionTags[tactic.id] || [];
  if (!tags.length) return "";
  return `<div class="tactic-tags">${tags.map(tag => `<span class="${getTagClass(tag)}">${escapeHTML(tag)}</span>`).join("")}</div>`;
}

function getTagClass(tag) {
  const normalized = normalizeSearchText(tag).replace(/\s+/g, "-");
  if (["short-rest", "long-rest"].includes(normalized)) return `tag tag--recharge`;
  if (["action", "bonus-action", "reaction"].includes(normalized)) return `tag tag--timing`;
  if (["passive"].includes(normalized)) return `tag tag--passive`;
  if (["active", "on-hit", "on-attack", "combat-start", "initiative"].includes(normalized)) return `tag tag--trigger`;
  if (["magic"].includes(normalized)) return `tag tag--magic`;
  return "tag tag--misc";
}

function requestDmModeAccess(onUnlocked) {
  if (dmModeUnlocked) {
    onUnlocked();
    return;
  }

  pendingDmModeUnlock = onUnlocked;
  els.dmCodeError.textContent = "";
  els.dmCodeInput.value = "";
  els.dmCodeDialog.showModal();
  setTimeout(() => els.dmCodeInput.focus(), 0);
}

function unlockDmModeFromDialog(event) {
  event.preventDefault();

  if (els.dmCodeInput.value.trim() !== DM_MODE_CODE) {
    els.dmCodeError.textContent = "Incorrect DM code.";
    els.dmCodeInput.select();
    return;
  }

  dmModeUnlocked = true;
  els.dmCodeDialog.close();
  const unlockAction = pendingDmModeUnlock;
  pendingDmModeUnlock = null;
  if (typeof unlockAction === "function") unlockAction();
}

function toggleDmEditMode() {
  if (dmEditMode) {
    dmEditMode = false;
    render();
    showToast("DM Mode disabled.");
    refreshGlobalDmButton();
    return;
  }

  requestDmModeAccess(() => {
    dmEditMode = true;
    render();
    showToast("DM Mode enabled.");
    refreshGlobalDmButton();
  });
}

function openDmEditDialog(tacticId) {
  const tactic = tacticById[tacticId];
  if (!tactic) return;

  els.dmEditId.value = tacticId;
  els.dmEditName.value = tactic.name;
  els.dmEditSummary.value = tactic.summary || "";
  els.dmEditTags.value = (tacticActionTags[tacticId] || []).join(", ");
  els.dmEditText.value = htmlToPlainText(tactic.text);
  els.dmEditDialog.showModal();
}

function saveEditedTactic(event) {
  event.preventDefault();

  const id = els.dmEditId.value;
  const tactic = tacticById[id];
  if (!tactic) return;

  const name = els.dmEditName.value.trim() || tactic.name;
  const summary = els.dmEditSummary.value.trim();
  const text = plainTextToHTML(els.dmEditText.value.trim());
  const tags = els.dmEditTags.value
    .split(",")
    .map(tag => tag.trim())
    .filter(Boolean);

  tactic.name = name;
  tactic.summary = summary;
  tactic.text = text;
  tacticActionTags[id] = tags;
  tacticEdits[id] = { name, summary, text, tags };

  saveTacticEdits();
  els.dmEditDialog.close();
  render();
  showToast(`${name} updated.`);
}

function resetEditedTactic() {
  const id = els.dmEditId.value;
  if (!id) return;

  delete tacticEdits[id];
  saveTacticEdits();
  location.reload();
}

function loadTacticEdits() {
  try {
    tacticEdits = JSON.parse(localStorage.getItem(TACTIC_EDITS_KEY)) || {};
  } catch {
    tacticEdits = {};
  }

  for (const [id, edit] of Object.entries(tacticEdits)) {
    const tactic = tacticById[id];
    if (!tactic) continue;
    if (edit.name) tactic.name = edit.name;
    if (edit.summary) tactic.summary = edit.summary;
    if (edit.text) tactic.text = edit.text;
    if (Array.isArray(edit.tags)) tacticActionTags[id] = edit.tags;
  }
}

function saveTacticEdits() {
  localStorage.setItem(TACTIC_EDITS_KEY, JSON.stringify(tacticEdits));
}

function plainTextToHTML(text) {
  if (!text) return "<p></p>";
  return text
    .split(/\n{2,}/)
    .map(paragraph => `<p>${escapeHTML(paragraph).replace(/\n/g, "<br>")}</p>`)
    .join("");
}

function htmlToPlainText(html) {
  const div = document.createElement("div");
  div.innerHTML = html || "";
  return div.textContent.trim();
}

function renderCard(tactic, query, options = {}) {
  const availability = getAvailability(tactic);
  const selected = availability.status === "selected";
  const available = availability.status === "available";
  const card = document.createElement("article");
  card.className = `card is-${availability.status}`;
  if (options.isRecommended) card.classList.add("is-recommended-next");
  if (availability.status === "selected" && tactic.id === lastChangedId) card.classList.add("just-selected");
  card.dataset.id = tactic.id;
  card.dataset.categories = (tacticCategories[tactic.id] || []).join(" ");

  if (!tacticMatchesSearch(tactic, query) || (!options.ignoreFilters && !tacticMatchesFilters(tactic))) card.classList.add("hidden-by-search");

  const prereq = tactic.prereqText || tactic.prereqs.map(id => tacticById[id]?.name).filter(Boolean).join(", ");
  const descriptionId = `desc-${tactic.id}`;

  const expanded = isTacticExpanded(tactic.id);

  const textBlock = expanded
    ? `<div id="${descriptionId}" class="card__description">${highlightGameTermsHTML(tactic.text)}</div>`
    : `<p id="${descriptionId}" class="card__summary">${highlightGameTerms(tactic.summary || "")}</p>`;

  const cardMeta = options.isRecommended
    ? `<div class="card__meta"><span class="recommendation">Recommended next upgrade</span></div>`
    : "";

  card.innerHTML = `
    <div class="card__top">
      <div class="card__title-wrap">
        <span class="card__icon" aria-hidden="true">${getIconMarkup(tacticIconKeys[tactic.id] || "star")}</span>
        <div class="card__title-text">
          <h3>${escapeHTML(tactic.name)}</h3>
          ${renderActionTags(tactic)}
        </div>
      </div>
      <div class="card__top-actions">
        ${createFavoriteButton("tactic", tactic.id, tactic.name)}
        <span class="badge badge--${availability.status}">${availability.label}</span>
      </div>
    </div>
    ${textBlock}
    ${cardMeta}
    <div class="card__footer">
      <button class="button card__button ${selected ? "button--danger" : available ? "button--primary" : ""}" type="button" ${!selected && !available ? "disabled" : ""}>${selected ? "Remove" : "Select"}</button>
      <button class="button button--ghost details-toggle" type="button" aria-expanded="${String(expanded)}" aria-controls="${descriptionId}">${expanded ? "Simple" : "Detailed"}</button>
      <button class="button button--ghost dm-edit-card-button" type="button">Edit</button>
    </div>
  `;

  const selectButton = card.querySelector(".card__button");
  selectButton.addEventListener("click", () => toggleTactic(tactic));

  const toggleButton = card.querySelector(".details-toggle");
  toggleButton.addEventListener("click", () => toggleCardDetails(tactic.id));

  const editButton = card.querySelector(".dm-edit-card-button");
  editButton.addEventListener("click", () => openDmEditDialog(tactic.id));

  bindFavoriteButtons(card);
  return card;
}

function toggleTactic(tactic) {
  const selected = getSelectedSet();

  if (selected.has(tactic.id)) {
    removeTacticAndDependents(tactic.id);
    saveAndRender();
    return;
  }

  const availability = getAvailability(tactic);
  if (availability.status !== "available") {
    showToast(availability.reason || "This tactic is locked.");
    return;
  }

  state.selected.push(tactic.id);
  lastChangedId = tactic.id;
  saveAndRender();
  showToast(`${tactic.name} selected.`);
}

function removeTacticAndDependents(id) {
  const toRemove = new Set([id]);
  let changed = true;

  while (changed) {
    changed = false;
    for (const selectedId of state.selected) {
      if (toRemove.has(selectedId)) continue;
      const tactic = tacticById[selectedId];
      if (tactic?.prereqs.some(prereqId => toRemove.has(prereqId))) {
        toRemove.add(selectedId);
        changed = true;
      }
    }
  }

  state.selected = state.selected.filter(selectedId => !toRemove.has(selectedId));
  const removedNames = [...toRemove].map(removedId => tacticById[removedId]?.name).filter(Boolean);
  showToast(`Removed: ${removedNames.join(", ")}.`);
}

function pruneInvalidSelections(message) {
  const original = [...state.selected];
  state.selected = original.filter(id => tacticById[id]);

  let changed = true;
  while (changed) {
    changed = false;
    const selected = getSelectedSet();
    const counts = { 1: 0, 2: 0, 3: 0 };
    const budgets = getBudgets();
    const cap = getTierCap();
    const next = [];

    for (const id of state.selected) {
      const tactic = tacticById[id];
      const hasPrereqs = tactic.prereqs.every(prereqId => selected.has(prereqId));
      const tierAllowed = tactic.tier <= cap;
      const hasBudget = counts[tactic.tier] < budgets[tactic.tier];

      if (hasPrereqs && tierAllowed && hasBudget) {
        next.push(id);
        counts[tactic.tier] += 1;
      } else {
        changed = true;
      }
    }
    state.selected = next;
  }

  if (original.join("|") !== state.selected.join("|")) showToast(message);
}

function saveAndRender() {
  syncActiveBuild();
  saveState();
  render();
}

function saveState() {
  syncActiveBuild();
  localStorage.setItem(BUILD_SLOTS_KEY, JSON.stringify(builds));
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

function loadState() {
  try {
    const savedBuilds = JSON.parse(localStorage.getItem(BUILD_SLOTS_KEY));
    if (savedBuilds?.slots) {
      builds = createDefaultBuilds();
      builds.activeSlot = String(savedBuilds.activeSlot || "1");
      if (!builds.slots[builds.activeSlot]) builds.activeSlot = "1";

      for (let slot = 1; slot <= SLOT_COUNT; slot += 1) {
        const key = String(slot);
        builds.slots[key] = normalizeBuild(savedBuilds.slots[key], key);
      }
    } else {
      const oldSaved = JSON.parse(localStorage.getItem(STORAGE_KEY));
      builds = createDefaultBuilds();
      if (oldSaved && typeof oldSaved === "object") {
        builds.slots["1"] = normalizeBuild({
          name: "Imported v4 Build",
          level: oldSaved.level,
          selected: oldSaved.selected
        }, "1");
      }
    }

    state = builds.slots[builds.activeSlot] || createEmptyBuild(builds.activeSlot);
    pruneInvalidSelections("Saved build was cleaned up.");
  } catch {
    builds = createDefaultBuilds();
    state = builds.slots[builds.activeSlot];
  }
}

function createExportPayload() {
  return {
    app: "War Tactics Skill Tree",
    version: 6,
    exportedAt: new Date().toISOString(),
    buildSlot: builds.activeSlot,
    buildName: state.name,
    level: state.level,
    viewMode: state.viewMode || "simple",
    expandedDetails: state.expandedDetails || [],
    selected: state.selected.map(id => ({
      id,
      name: tacticById[id]?.name,
      tier: tacticById[id]?.tier,
      categories: tacticCategories[id] || [],
      tags: tacticActionTags[id] || []
    }))
  };
}

function openBuildCodeDialog() {
  els.buildCodeText.value = encodeBuildCode(createExportPayload());
  els.buildCodeDialog.showModal();
  els.buildCodeText.focus();
  els.buildCodeText.select();
}

function encodeBuildCode(payload) {
  const json = JSON.stringify(payload);
  const bytes = new TextEncoder().encode(json);
  let binary = "";
  bytes.forEach(byte => binary += String.fromCharCode(byte));
  return `WTB1:${btoa(binary).replaceAll("+", "-").replaceAll("/", "_").replaceAll("=", "")}`;
}

function decodeBuildCode(code) {
  const trimmed = String(code || "").trim();
  if (!trimmed.startsWith("WTB1:")) throw new Error("Build code must start with WTB1:");

  let base64 = trimmed.slice(5).replaceAll("-", "+").replaceAll("_", "/");
  while (base64.length % 4) base64 += "=";

  const binary = atob(base64);
  const bytes = Uint8Array.from(binary, char => char.charCodeAt(0));
  const json = new TextDecoder().decode(bytes);
  return JSON.parse(json);
}

async function copyBuildCode() {
  try {
    await navigator.clipboard.writeText(els.buildCodeText.value);
    showToast("Build code copied.");
  } catch {
    els.buildCodeText.focus();
    els.buildCodeText.select();
    showToast("Select and copy the code manually.");
  }
}

function importBuildCodeFromDialog() {
  try {
    const imported = decodeBuildCode(els.buildCodeText.value);
    applyImportedBuild(imported);
    els.buildCodeDialog.close();
    showToast("Build code imported.");
  } catch (error) {
    showToast(error.message || "Invalid build code.");
  }
}

function applyImportedBuild(imported) {
  if (!imported || !Array.isArray(imported.selected)) {
    throw new Error("Invalid build data.");
  }

  const importedIds = imported.selected
    .map(item => typeof item === "string" ? item : item.id)
    .filter(id => tacticById[id]);

  state.name = imported.buildName || imported.name || state.name || `Build Slot ${builds.activeSlot}`;
  state.level = Number(imported.level) || state.level;
  state.level = Math.max(1, Math.min(20, state.level));
  state.viewMode = imported.viewMode === "detailed" ? "detailed" : "simple";
  state.expandedDetails = Array.isArray(imported.expandedDetails)
    ? imported.expandedDetails.filter(id => tacticById[id])
    : state.viewMode === "detailed" ? tactics.map(tactic => tactic.id) : [];
  state.selected = importedIds;
  syncActiveBuild();
  pruneInvalidSelections("Imported build had locked or invalid selections removed.");
  saveAndRender();
}

function exportBuild() {
  const payload = createExportPayload();

  downloadBlob(JSON.stringify(payload, null, 2), `war-tactics-${slugify(state.name || "build")}.json`, "application/json");
  showToast("Build exported as JSON.");
}

function importBuild(event) {
  const file = event.target.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const imported = JSON.parse(String(reader.result));
      const importedIds = Array.isArray(imported.selected)
        ? imported.selected.map(item => typeof item === "string" ? item : item.id).filter(id => tacticById[id])
        : [];
      applyImportedBuild({ ...imported, selected: importedIds });
      showToast("Build imported.");
    } catch {
      showToast("Could not import that JSON file.");
    } finally {
      event.target.value = "";
    }
  };
  reader.readAsText(file);
}

function resetBuild() {
  state.selected = [];
  syncActiveBuild();
  saveAndRender();
  showToast("Current slot reset.");
}

function getSelectedTactics() {
  return state.selected.map(id => tacticById[id]).filter(Boolean);
}

function exportBuildImage() {
  const selectedTactics = getSelectedTactics();
  const buildName = state.name || `Build Slot ${builds.activeSlot}`;
  const rows = selectedTactics.length ? selectedTactics : [{ name: "No tactics selected", tier: 0, summary: "Choose tactics to complete this build." }];
  const width = 1100;
  const rowHeight = 54;
  const height = 210 + rows.length * rowHeight;

  const rowMarkup = rows.map((tactic, index) => {
    const y = 170 + index * rowHeight;
    const tierLabel = tactic.tier ? tierInfo[tactic.tier].label : "—";
    const summary = tactic.summary || "";
    return `
      <text x="72" y="${y}" fill="#f2efe7" font-size="22" font-weight="700">${escapeXML(tactic.name)}</text>
      <text x="72" y="${y + 25}" fill="#bbb7aa" font-size="15">${escapeXML(tierLabel)} · ${escapeXML(summary)}</text>
      <line x1="60" x2="${width - 60}" y1="${y + 41}" y2="${y + 41}" stroke="rgba(255,255,255,0.14)" />
    `;
  }).join("");

  const svg = `
<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <defs>
    <linearGradient id="bg" x1="0" x2="1" y1="0" y2="1">
      <stop offset="0" stop-color="#0e1018"/>
      <stop offset="0.55" stop-color="#151824"/>
      <stop offset="1" stop-color="#0c0e14"/>
    </linearGradient>
    <radialGradient id="glow" cx="30%" cy="10%" r="80%">
      <stop offset="0" stop-color="#76b8ff" stop-opacity="0.28"/>
      <stop offset="0.45" stop-color="#d9ae5f" stop-opacity="0.12"/>
      <stop offset="1" stop-color="#0e1018" stop-opacity="0"/>
    </radialGradient>
  </defs>
  <rect width="100%" height="100%" rx="28" fill="url(#bg)"/>
  <rect width="100%" height="100%" rx="28" fill="url(#glow)"/>
  <rect x="34" y="34" width="${width - 68}" height="${height - 68}" rx="24" fill="rgba(255,255,255,0.045)" stroke="rgba(255,255,255,0.14)"/>
  <text x="60" y="82" fill="#d9ae5f" font-size="18" font-weight="800" letter-spacing="2">WAR TACTICS BUILD</text>
  <text x="60" y="122" fill="#f2efe7" font-size="42" font-weight="850">${escapeXML(buildName)}</text>
  <text x="60" y="150" fill="#bbb7aa" font-size="18">Martial Class Level ${state.level} · ${selectedTactics.length} selected tactics</text>
  ${rowMarkup}
</svg>`;

  downloadBlob(svg, `war-tactics-${slugify(buildName)}.svg`, "image/svg+xml");
  showToast("Build image exported as SVG.");
}

