function renderCharacterBackgroundBlockV574() {
  if (getCharacterRulesVersion() === "2014") {
    return characterSelectInfoRowV574("background", "Background", getCharacterBackgroundOptions(), "Choose background", "characterBackgroundDetailsButton", "Show background benefits");
  }
  return `${characterSelectField("background", "Background", getCharacterBackgroundOptions(), "Choose background")}<div class="character-background-grant-row character-background-grant-row--compact">${characterOriginFeatGrantField()}<label class="character-field character-field--detail-button"><span>Background Grants</span>${renderCharacterInfoButtonV574("characterBackgroundDetailsButton", "Show background benefits")}</label></div>`;
}

function renderCharacterIdentityPanelV574(pb) {
  const is2014 = getCharacterRulesVersion() === "2014";
  if (is2014) {
    return `<section class="character-panel character-panel--identity character-panel--identity-v574"><div class="character-panel__heading"><h3>Identity & Origin</h3><span>PB ${formatSigned(pb)}</span></div><div class="character-grid character-grid--identity character-grid--identity-v574 character-grid--identity-5e"><div class="character-identity-column">${characterField("name", "Character Name", "text", "Name")}${characterField("player", "Player Name", "text", "Player")}${characterSelectField("level", "Level", CHARACTER_LEVEL_OPTIONS, null)}</div><div class="character-identity-column character-identity-column--wide">${characterSelectInfoRowV574("species", "Race", getCharacterSpeciesOptions(), "Choose race", "characterSpeciesDetailsButton", "Show race benefits")}${renderCharacterBackgroundBlockV574()}${renderCharacterClassSubclassRowV574()}</div><div class="character-identity-column">${characterField("xp", "XP / Milestone", "text", "XP")}${characterSelectField("size", "Size", CHARACTER_SIZE_OPTIONS, null)}${characterSelectField("alignment", "Alignment", CHARACTER_ALIGNMENT_OPTIONS, "Choose alignment")}</div></div>${renderCharacterBackgroundNote()}${renderCharacterMulticlassSection()}</section>`;
  }
  return `<section class="character-panel character-panel--identity character-panel--identity-v574"><div class="character-panel__heading"><h3>Identity & Origin</h3><span>PB ${formatSigned(pb)}</span></div><div class="character-grid character-grid--identity character-grid--identity-v574 character-grid--identity-5-5e"><div class="character-identity-column">${characterField("name", "Character Name", "text", "Name")}${characterField("player", "Player Name", "text", "Player")}${characterSelectField("level", "Level", CHARACTER_LEVEL_OPTIONS, null)}</div><div class="character-identity-column">${characterSelectInfoRowV574("species", "Species", getCharacterSpeciesOptions(), "Choose species", "characterSpeciesDetailsButton", "Show species benefits")}${characterSelectField("className", "Class", getCharacterClassOptions(), "Choose class")}${characterSelectField("subclass", "Subclass", getCharacterSubclassOptions(characterState.className), characterState.className ? "Choose subclass" : "Choose class first")}</div><div class="character-identity-column">${renderCharacterBackgroundBlockV574()}</div><div class="character-identity-column">${characterField("xp", "XP / Milestone", "text", "XP")}${characterSelectField("size", "Size", CHARACTER_SIZE_OPTIONS, null)}${characterSelectField("alignment", "Alignment", CHARACTER_ALIGNMENT_OPTIONS, "Choose alignment")}</div></div>${renderCharacterBackgroundNote()}${renderCharacterMulticlassSection()}</section>`;
}

function renderChoiceDetailCardV574(label, value, description = "") {
  return `<div class="character-choice-detail-card"><span>${escapeHTML(label)}</span><strong>${escapeHTML(value || "None")}</strong>${description ? `<p>${escapeHTML(description)}</p>` : ""}</div>`;
}

function openCharacterSpeciesDetailsDialogV574() {
  const option = getCurrentSpeciesOptionV574();
  if (!option || !characterState.species) { showToast(getCharacterRulesVersion() === "2014" ? "Choose a race first." : "Choose a species first."); return; }
  const details = getRaceGrantDetailsV574(option);
  const label = getCharacterRulesVersion() === "2014" ? "Race" : "Species";
  const dialog = document.createElement("dialog");
  dialog.className = "dialog character-choice-details-dialog character-race-dialog";
  dialog.innerHTML = `<form method="dialog"><div class="dialog-title-row"><h2><span class="character-dialog-title-icon" ${getCharacterIconStyle(option.iconKey)}>${getCharacterIconSvg(option.iconKey, option.label)}</span>${escapeHTML(option.label || details.title)} ${label} ${getCharacterOptionSourceBadge(option)}</h2><button class="dialog-x-button" value="cancel" aria-label="Close">×</button></div><p>${escapeHTML(`Source: ${details.source}. Add any table-specific or subrace choices to Features & Traits.`)}</p><div class="character-choice-detail-grid">${renderChoiceDetailCardV574("Main Grants", details.grants)}${renderChoiceDetailCardV574("Movement", details.movement)}${renderChoiceDetailCardV574("Source", details.source, getCharacterSourceFullName(details.source))}<div class="character-choice-detail-card character-choice-detail-card--wide"><span>Notes</span><strong>${escapeHTML(details.title)}</strong><p>${escapeHTML(details.notes)}</p></div></div><div class="dialog-actions"><button class="button" value="default">Close</button></div></form>`;
  document.body.append(dialog);
  dialog.addEventListener("close", () => dialog.remove());
  dialog.addEventListener("click", event => { if (event.target === dialog) dialog.close(); });
  dialog.showModal();
}

const openCharacterBackgroundDetailsDialogV573 = openCharacterBackgroundDetailsDialog;
openCharacterBackgroundDetailsDialog = function() {
  const background = getCurrentBackgroundOption();
  if (!background || !characterState.background) { showToast("Choose a background first."); return; }
  const is2014 = getCharacterRulesVersion() === "2014";
  const sourceText = background.source || background.sourceEdition || "Custom";
  const summary = `Source: ${sourceText}. ASI: ${background.abilities || "None"}. Skills: ${background.skills || "Custom"}. Tool/Language: ${background.tools || "Custom"}. Origin Feat: ${background.feat || "None"}. ${is2014 ? "5e background features and equipment vary by book; add table-specific details in Features & Traits." : getCharacterOriginFeatDetail(background.feat)}`;
  const dialog = document.createElement("dialog");
  dialog.className = "dialog character-background-dialog character-background-dialog--v574 character-choice-details-dialog";
  dialog.innerHTML = `<form method="dialog"><div class="dialog-title-row"><h2><span class="character-dialog-title-icon" ${getCharacterIconStyle(background.iconKey)}>${getCharacterIconSvg(background.iconKey, background.label)}</span>${escapeHTML(background.label)} Background ${getCharacterOptionSourceBadge(background)}</h2><button class="dialog-x-button" value="cancel" aria-label="Close">×</button></div><p>${escapeHTML(is2014 ? "These are 5e background grants. Origin Feat is normally none unless your table adds one." : "These are the 5.5e background grants applied to this character sheet.")}</p><div class="character-background-detail-grid"><div class="character-background-detail-card"><span>Source Book</span><strong>${escapeHTML(sourceText)}</strong><p>${escapeHTML(getCharacterSourceFullName(sourceText))}</p></div>${renderCharacterBackgroundDetailCard(is2014 ? "Ability Scores" : "Ability Score Options", background.abilities, is2014 ? "5e backgrounds normally do not grant ability score increases." : "Choose +2/+1 or +1/+1/+1 among these abilities.")}${renderCharacterBackgroundDetailCard("Skill Proficiencies", background.skills)}${renderCharacterBackgroundDetailCard("Tool / Language Proficiency", background.tools)}${renderCharacterBackgroundDetailCard("Origin Feat", background.feat, is2014 ? "No Origin Feat by default in 5e backgrounds." : getCharacterOriginFeatDetail(background.feat))}<div class="character-background-detail-card character-background-detail-card--wide"><span>Background Summary</span><strong>${escapeHTML(background.label)}</strong><p>${escapeHTML(summary)}</p></div></div><div class="dialog-actions"><button class="button" value="default">Close</button></div></form>`;
  document.body.append(dialog);
  dialog.addEventListener("close", () => dialog.remove());
  dialog.addEventListener("click", event => { if (event.target === dialog) dialog.close(); });
  dialog.showModal();
};

const abilityCardV573 = abilityCard;
abilityCard = function(ability) {
  const score = Number(characterState.abilities[ability.key]) || 10;
  const mod = getAbilityModifier(score);
  const save = getSaveModifier(ability);
  const proficient = characterState.saveProficiencies.includes(ability.key);
  return `<article class="ability-card ability-card--${escapeHTML(ability.key)}"><label><span>${ability.short}</span><div class="character-stepper"><button class="character-stepper-button" type="button" data-ability-adjust="${ability.key}" data-step="-1" aria-label="Decrease ${escapeHTML(ability.label)}">−1</button><input type="number" data-ability-score="${ability.key}" min="1" max="30" value="${score}"><button class="character-stepper-button" type="button" data-ability-adjust="${ability.key}" data-step="1" aria-label="Increase ${escapeHTML(ability.label)}">+1</button></div></label><strong>${formatSigned(mod)}</strong><label class="character-checkbox character-checkbox--save" title="Adds your Proficiency Bonus to this ${escapeHTML(ability.label)} saving throw."><input type="checkbox" data-save-proficiency="${ability.key}" ${proficient ? "checked" : ""}><span class="character-checkbox-text">Save Proficiency <small>Adds PB · Total ${formatSigned(save)}</small></span></label></article>`;
};

const bindCharacterCreatorEventsV573 = bindCharacterCreatorEvents;
bindCharacterCreatorEvents = function() {
  bindCharacterCreatorEventsV573();
  const speciesDetailsButton = document.getElementById("characterSpeciesDetailsButton");
  if (speciesDetailsButton && !speciesDetailsButton.dataset.boundSpeciesInfo) {
    speciesDetailsButton.dataset.boundSpeciesInfo = "true";
    speciesDetailsButton.addEventListener("click", openCharacterSpeciesDetailsDialogV574);
  }
};

const renderCharacterCreatorV573 = renderCharacterCreator;
renderCharacterCreator = function() {
  if (!els.characterSheet) return;
  if (!characterState) characterState = createDefaultCharacter();
  ensureCharacterV573();
  characterState.expandedMaterial = false;
  characterState.expandedSubclasses = false;
  characterState.expandedLanguages = false;
  const pb = getCharacterProficiencyBonus();
  const rawInitiative = getAbilityModifier(characterState.abilities.dex) + (Number(characterState.initiativeBonus) || 0);
  const passivePerception = 10 + getSkillModifier({ name: "Perception", ability: "wis" });
  els.characterSheet.classList.toggle("character-sheet--rules-2014", getCharacterRulesVersion() === "2014");
  els.characterSheet.classList.toggle("character-sheet--rules-2024", getCharacterRulesVersion() === "2024");
  els.characterSheet.innerHTML = `${renderCharacterRulesPanel()}${renderCharacterIdentityPanelV574(pb)}<section class="character-panel"><div class="character-panel__heading character-panel__heading--actions"><h3>Ability Scores & Saving Throws</h3><div class="character-heading-actions"><button id="characterStatRollerButton" class="button button--ghost" type="button">Roll Stats</button><button id="characterApplyClassSaves" class="button button--ghost" type="button">Apply Class Saves</button></div></div><div class="ability-grid">${CHARACTER_ABILITIES.map(ability => abilityCard(ability)).join("")}</div></section><section class="character-panel"><div class="character-panel__heading"><h3>Skills</h3><span>Passive Perception ${passivePerception}</span></div><div class="skill-grid">${CHARACTER_SKILLS.map(skill => skillRow(skill)).join("")}</div></section>${renderCharacterCombatPanelV573(rawInitiative)}${renderCharacterSpellcastingPanelV573()}<section class="character-panel"><div class="character-panel__heading"><h3>Proficiencies, Features & Equipment</h3></div><div class="character-grid character-grid--textareas">${characterTextarea("senses", "Senses")}${characterAddableTextarea("languages", "Languages", getCharacterLanguageOptions(), "Add language")}${characterAddableTextarea("armorTraining", "Armor Proficiencies", CHARACTER_ARMOR_PROFICIENCY_OPTIONS, "Add armor")}${characterAddableTextarea("weaponTraining", "Weapon Proficiencies", CHARACTER_WEAPON_PROFICIENCY_OPTIONS, "Add weapon")}${characterAddableTextarea("toolTraining", "Tool Proficiencies", CHARACTER_TOOL_PROFICIENCY_OPTIONS, "Add tool")}${characterTextarea("features", "Features & Traits")}${characterTextarea("attacks", "Attacks / Actions")}${characterTextarea("equipment", "Equipment")}${renderCharacterCurrencyFields()}${characterTextarea("treasure", "Treasure")}${characterTextarea("backstory", "Backstory")}${characterTextarea("notes", "Notes")}</div></section>`;
  bindCharacterCreatorEvents();
  const spendButton = document.getElementById("characterHitDiceSpendButton");
  if (spendButton) spendButton.addEventListener("click", openCharacterHitDiceDialog);
};



/* v5.75: compact spell controls, half-step exhaustion, and stable Character Creator edits */
const CHARACTER_EXHAUSTION_VALUES_V575 = [0, 0.5, 1, 1.5, 2, 2.5, 3, 3.5, 4, 4.5, 5, 5.5, 6];
function clampCharacterExhaustionV575(value) {
  const numeric = Number(value) || 0;
  return Math.max(0, Math.min(6, Math.round(numeric * 2) / 2));
}
function formatExhaustionValueV575(value) {
  const numeric = clampCharacterExhaustionV575(value);
  return Number.isInteger(numeric) ? String(numeric) : numeric.toFixed(1);
}
function getCharacterExhaustionD20PenaltyV575(value = characterState?.exhaustionLevel) {
  return Math.round(clampCharacterExhaustionV575(value) * 2);
}
function getCharacterExhaustionSpeedPenaltyV575(value = characterState?.exhaustionLevel) {
  return Math.floor(clampCharacterExhaustionV575(value)) * 5;
}
CHARACTER_EXHAUSTION_OPTIONS_V573.splice(0, CHARACTER_EXHAUSTION_OPTIONS_V573.length, ...CHARACTER_EXHAUSTION_VALUES_V575.map(value => ({
  value: formatExhaustionValueV575(value),
  label: value === 0 ? "0 · No penalty" : `${formatExhaustionValueV575(value)} · D20 ${formatSigned(-getCharacterExhaustionD20PenaltyV575(value))}`,
  note: value === 0 ? "No d20 penalty" : `D20 ${formatSigned(-getCharacterExhaustionD20PenaltyV575(value))}`,
  iconKey: value ? "sigil-custom" : "source-5-5"
})));

ensureCharacterV573 = function() {
  if (!characterState) characterState = createDefaultCharacter();
  characterState.exhaustionLevel = clampCharacterExhaustionV575(characterState.exhaustionLevel);
  characterState.spellSaveBonus = Number(characterState.spellSaveBonus) || 0;
  characterState.spellAttackBonus = Number(characterState.spellAttackBonus) || 0;
  characterState.spellSlotUses = characterState.spellSlotUses && typeof characterState.spellSlotUses === "object" ? characterState.spellSlotUses : {};
  normalizeCharacterSpellSlotUsesV573();
};
getCharacterExhaustionLevelV573 = function() {
  return clampCharacterExhaustionV575(characterState?.exhaustionLevel);
};
getCharacterD20PenaltyV573 = function() {
  return getCharacterExhaustionD20PenaltyV575();
};
getCharacterSpeedPenaltyV573 = function() {
  return getCharacterExhaustionSpeedPenaltyV575();
};
getCharacterEffectiveSpeedV573 = function() {
  return Math.max(0, (Number(characterState?.speed) || 0) - getCharacterSpeedPenaltyV573());
};
getCharacterExhaustionSummaryV573 = function() {
  const level = getCharacterExhaustionLevelV573();
  const d20Penalty = getCharacterD20PenaltyV573();
  const speedPenalty = getCharacterSpeedPenaltyV573();
  if (!level) return `<div class="character-exhaustion-summary-v75"><span>No Exhaustion penalty active.</span></div>`;
  return `<div class="character-exhaustion-summary-v75"><span>Exhaustion ${escapeHTML(formatExhaustionValueV575(level))}</span><span>D20 ${formatSigned(-d20Penalty)}</span><span>Speed -${speedPenalty} ft.</span>${level >= 6 ? `<span>Death threshold</span>` : ""}</div>`;
};

function renderCharacterExhaustionFieldV575() {
  const selected = getCharacterExhaustionLevelV573();
  const selectedText = formatExhaustionValueV575(selected);
  const d20Penalty = getCharacterD20PenaltyV573();
  const halfOptions = [0.5, 1.5, 2.5, 3.5, 4.5, 5.5];
  const wholeOptions = [1, 2, 3, 4, 5, 6];
  const renderOption = value => {
    const text = formatExhaustionValueV575(value);
    const selectedClass = Number(selected) === Number(value) ? " is-selected" : "";
    return `<button class="character-exhaustion-option-v75${selectedClass}" type="button" data-exhaustion-option-v75="${escapeHTML(text)}"><span>${escapeHTML(text)}</span><small>D20 ${formatSigned(-getCharacterExhaustionD20PenaltyV575(value))}</small></button>`;
  };
  return `<label class="character-field character-exhaustion-field-v75" data-exhaustion-picker-v75>
    <span>Exhaustion</span>
    <input type="hidden" data-character-field="exhaustionLevel" value="${escapeHTML(selectedText)}">
    <div class="character-exhaustion-picker-row">
      <button class="character-exhaustion-toggle-v75" type="button" data-exhaustion-toggle-v75 aria-expanded="false">${escapeHTML(selectedText)}</button>
      <span class="character-exhaustion-penalty-badge">D20 ${formatSigned(-d20Penalty)}</span>
    </div>
    <div class="character-exhaustion-menu-v75 hidden" data-exhaustion-menu-v75>
      ${renderOption(0)}
      <div class="character-exhaustion-menu-columns-v75">
        <div class="character-exhaustion-menu-col-v75">${halfOptions.map(renderOption).join("")}</div>
        <div class="character-exhaustion-menu-col-v75">${wholeOptions.map(renderOption).join("")}</div>
      </div>
    </div>
  </label>`;
}

renderCharacterSpellBonusStepperV573 = function(key, label, total) {
  const value = Number(characterState[key]) || 0;
  return `<div class="character-spell-bonus-card character-spell-bonus-card--compact"><span>${escapeHTML(label)}</span><div class="character-spell-bonus-line"><strong>${escapeHTML(String(total))}</strong><div class="character-stepper character-stepper--spell character-stepper--compact"><button class="character-stepper-button" type="button" data-spell-bonus-adjust="${escapeHTML(key)}" data-step="-1" aria-label="Decrease ${escapeHTML(label)} bonus">−1</button><input class="character-spell-bonus-input" type="number" data-character-field="${escapeHTML(key)}" value="${escapeHTML(String(value))}" title="Manual ${escapeHTML(label)} bonus"><button class="character-stepper-button" type="button" data-spell-bonus-adjust="${escapeHTML(key)}" data-step="1" aria-label="Increase ${escapeHTML(label)} bonus">+1</button></div></div></div>`;
};
renderCharacterSpellcastingPanelV573 = function() {
  return `<section class="character-panel"><div class="character-panel__heading"><h3>Spellcasting</h3><span>Save DC ${getSpellSaveDc()} · Attack ${getSpellAttackBonus()}</span></div><div class="character-spell-total-row">${characterSelectField("spellcastingAbility", "Spellcasting Ability", [{ value: "", label: "None" }, ...CHARACTER_ABILITIES.map(ability => ({ value: ability.key, label: ability.label }))], null)}${renderCharacterSpellBonusStepperV573("spellSaveBonus", "Spell Save DC", getSpellSaveDc())}${renderCharacterSpellBonusStepperV573("spellAttackBonus", "Spell Attack Bonus", getSpellAttackBonus())}</div>${renderCharacterCasterSummaryV573()}${renderCharacterSpellSlotCheckboxesV573()}<div class="character-spell-filter-row">${characterSelectField("selectedSpellLevel", "Selected Spell Level", CHARACTER_SPELL_LEVEL_OPTIONS, null)}<div class="character-selected-spells-summary"><span>Filter selected spell notes by level so the sheet stays usable during play.</span><strong>${getSelectedSpellSummary()}</strong></div></div>${renderSelectedSpellLevelEditor()}<div class="character-grid character-grid--textareas character-grid--spell-notes">${characterTextarea("cantrips", "Cantrips / Always Prepared")}${characterTextarea("preparedSpells", "Prepared Spells Notes")}${characterTextarea("spellbook", "Spellbook / Known Spells Notes")}</div></section>`;
};
renderCharacterMaxHpFieldV573 = function() {
  return `<label class="character-field character-max-hp-field"><span>Max HP</span><div class="character-max-hp-row"><input type="number" data-character-field="maxHp" value="${escapeHTML(String(characterState.maxHp ?? 0))}" placeholder="0"><button id="characterHpRollerButton" class="button button--ghost character-max-hp-button" type="button">Roll HP</button></div></label>`;
};
renderCharacterCombatPanelV573 = function(initiative) {
  const d20Penalty = getCharacterD20PenaltyV573();
  const effectiveSpeed = getCharacterEffectiveSpeedV573();
  const speedPenalty = getCharacterSpeedPenaltyV573();
  return `<section class="character-panel"><div class="character-panel__heading character-panel__heading--actions"><h3>Combat & Health</h3><div class="character-heading-actions"><span>Initiative ${formatSigned(initiative - d20Penalty)}</span></div></div><div class="character-stat-strip"><div><span>AC</span><strong>${escapeHTML(characterState.armorClass || "10")}</strong></div><div><span>Initiative</span><strong>${formatSigned(initiative - d20Penalty)}</strong></div><div><span>Speed</span><strong>${effectiveSpeed} ft.${speedPenalty ? ` <small>(-${speedPenalty})</small>` : ""}</strong></div><div><span>HP</span><strong>${escapeHTML(characterState.currentHp || 0)} / ${escapeHTML(characterState.maxHp || 0)}</strong></div><div><span>Temp HP</span><strong>${escapeHTML(characterState.tempHp || 0)}</strong></div></div><div class="character-grid character-health-grid">${characterField("armorClass", "Armor Class", "number", "10")}${characterField("speed", "Base Speed", "number", "30")}${characterField("initiativeBonus", "Initiative Bonus", "number", "0")}${renderCharacterExhaustionFieldV575()}${renderCharacterMaxHpFieldV573()}${characterField("currentHp", "Current HP", "number", "0")}${characterField("tempHp", "Temp HP", "number", "0")}${renderCharacterHitDiceField()}${characterField("deathSaveSuccesses", "Death Save Successes", "number", "0", null, 0, 3)}${characterField("deathSaveFailures", "Death Save Failures", "number", "0", null, 0, 3)}</div>${getCharacterExhaustionSummaryV573()}<label class="character-checkbox character-checkbox--heroic"><input type="checkbox" data-character-field="heroicInspiration" ${characterState.heroicInspiration ? "checked" : ""}><span>Heroic Inspiration</span></label>${renderCharacterHpRollSummary()}</section>`;
};

const getCharacterFocusSnapshotV75 = () => {
  const active = document.activeElement;
  const root = els.characterSheet;
  const snapshot = { scrollX: window.scrollX, scrollY: window.scrollY, selector: "", start: null, end: null };
  if (!root || !active || !root.contains(active)) return snapshot;
  const esc = value => (window.CSS && CSS.escape ? CSS.escape(String(value)) : String(value).replace(/[^a-zA-Z0-9_-]/g, "\\$&"));
  if (active.id) snapshot.selector = `#${esc(active.id)}`;
  else if (active.dataset?.characterField) snapshot.selector = `[data-character-field="${esc(active.dataset.characterField)}"]`;
  else if (active.dataset?.abilityScore) snapshot.selector = `[data-ability-score="${esc(active.dataset.abilityScore)}"]`;
  else if (active.dataset?.skillBonus) snapshot.selector = `[data-skill-bonus="${esc(active.dataset.skillBonus)}"]`;
  else if (active.dataset?.selectedSpellsLevel) snapshot.selector = `[data-selected-spells-level="${esc(active.dataset.selectedSpellsLevel)}"]`;
  else if (active.dataset?.multiclassField && active.dataset?.multiclassIndex) snapshot.selector = `[data-multiclass-field="${esc(active.dataset.multiclassField)}"][data-multiclass-index="${esc(active.dataset.multiclassIndex)}"]`;
  else if (active.dataset?.characterSelectToggle) snapshot.selector = `[data-character-select-toggle]`;
  try {
    if (typeof active.selectionStart === "number") {
      snapshot.start = active.selectionStart;
      snapshot.end = active.selectionEnd;
    }
  } catch (_) {}
  return snapshot;
};
function restoreCharacterFocusSnapshotV75(snapshot) {
  requestAnimationFrame(() => {
    window.scrollTo(snapshot.scrollX || 0, snapshot.scrollY || 0);
    if (!snapshot.selector || !els.characterSheet) return;
    const target = els.characterSheet.querySelector(snapshot.selector);
    if (!target) return;
    try { target.focus({ preventScroll: true }); } catch (_) { try { target.focus(); } catch (__) {} }
    if (snapshot.start !== null && typeof target.setSelectionRange === "function") {
      try { target.setSelectionRange(snapshot.start, snapshot.end ?? snapshot.start); } catch (_) {}
    }
    window.scrollTo(snapshot.scrollX || 0, snapshot.scrollY || 0);
  });
}
const renderCharacterCreatorV75Base = renderCharacterCreator;
renderCharacterCreator = function(...args) {
  const snapshot = getCharacterFocusSnapshotV75();
  renderCharacterCreatorV75Base.apply(this, args);
  restoreCharacterFocusSnapshotV75(snapshot);
};

function saveCharacterFieldWithoutRerenderV75(input) {
  if (!characterState) characterState = createDefaultCharacter();
  if (input.matches("[data-ability-score]")) {
    characterState.abilities[input.dataset.abilityScore] = Math.max(1, Math.min(30, Number(input.value) || 10));
  } else if (input.matches("[data-skill-bonus]")) {
    const skill = input.dataset.skillBonus;
    characterState.skills[skill] = characterState.skills[skill] || { proficient: false, expertise: false, bonus: 0 };
    characterState.skills[skill].bonus = Number(input.value) || 0;
  } else if (input.matches("[data-character-field]")) {
    const key = input.dataset.characterField;
    if (key === "exhaustionLevel") input.value = formatExhaustionValueV575(input.value);
    setCharacterFieldFromInput(input);
    if (key === "exhaustionLevel") characterState.exhaustionLevel = clampCharacterExhaustionV575(input.value);
  }
  saveCharacterState();
}
const CHARACTER_STABLE_INPUT_FIELDS_V75 = new Set(["armorClass", "speed", "initiativeBonus", "maxHp", "currentHp", "tempHp", "deathSaveSuccesses", "deathSaveFailures", "spellSaveBonus", "spellAttackBonus", "exhaustionLevel"]);
function shouldGuardCharacterInputV75(input) {
  if (!input || !els.characterSheet || !els.characterSheet.contains(input)) return false;
  if (input.matches("[data-ability-score], [data-skill-bonus]")) return true;
  if (input.matches("[data-character-field]")) return CHARACTER_STABLE_INPUT_FIELDS_V75.has(input.dataset.characterField);
  return false;
}
function bindCharacterStableInteractionGuardsV75() {
  const root = els.characterSheet;
  if (!root || root.dataset.characterStableV75 === "true") return;
  root.dataset.characterStableV75 = "true";
  root.addEventListener("input", event => {
    const input = event.target;
    if (!shouldGuardCharacterInputV75(input)) return;
    event.stopImmediatePropagation();
    saveCharacterFieldWithoutRerenderV75(input);
  }, true);
  root.addEventListener("change", event => {
    const input = event.target;
    if (input?.matches?.("[data-spell-slot-use]")) {
      event.stopImmediatePropagation();
      normalizeCharacterSpellSlotUsesV573();
      const level = String(input.dataset.spellSlotUse);
      const index = Number(input.dataset.slotIndex) || 0;
      if (!Array.isArray(characterState.spellSlotUses[level])) characterState.spellSlotUses[level] = [];
      characterState.spellSlotUses[level][index] = input.checked;
      normalizeCharacterSpellSlotUsesV573();
      saveCharacterState();
      renderCharacterCreator();
      return;
    }
    if (!shouldGuardCharacterInputV75(input)) return;
    event.stopImmediatePropagation();
    saveCharacterFieldWithoutRerenderV75(input);
    renderCharacterCreator();
  }, true);
  root.addEventListener("click", event => {
    const button = event.target.closest("button");
    if (!button || !root.contains(button)) return;
    if (!button.getAttribute("type")) button.setAttribute("type", "button");
    if (button.type === "submit") event.preventDefault();
  }, true);
  document.addEventListener("click", event => {
    if (!event.target.closest("[data-exhaustion-picker-v75]")) {
      document.querySelectorAll("[data-exhaustion-menu-v75]").forEach(menu => menu.classList.add("hidden"));
      document.querySelectorAll("[data-exhaustion-toggle-v75]").forEach(toggle => toggle.setAttribute("aria-expanded", "false"));
    }
  });
}
function bindCharacterExhaustionPickerV75() {
  if (!els.characterSheet) return;
  els.characterSheet.querySelectorAll("[data-exhaustion-toggle-v75]").forEach(toggle => {
    if (toggle.dataset.boundV75 === "true") return;
    toggle.dataset.boundV75 = "true";
    toggle.addEventListener("click", event => {
      event.preventDefault();
      event.stopPropagation();
      const root = toggle.closest("[data-exhaustion-picker-v75]");
      const menu = root?.querySelector("[data-exhaustion-menu-v75]");
      if (!menu) return;
      const open = menu.classList.contains("hidden");
      document.querySelectorAll("[data-exhaustion-menu-v75]").forEach(item => { if (item !== menu) item.classList.add("hidden"); });
      menu.classList.toggle("hidden", !open);
      toggle.setAttribute("aria-expanded", open ? "true" : "false");
    });
  });
  els.characterSheet.querySelectorAll("[data-exhaustion-option-v75]").forEach(option => {
    if (option.dataset.boundV75 === "true") return;
    option.dataset.boundV75 = "true";
    option.addEventListener("click", event => {
      event.preventDefault();
      event.stopPropagation();
      const value = formatExhaustionValueV575(option.dataset.exhaustionOptionV75 || "0");
      const root = option.closest("[data-exhaustion-picker-v75]");
      const hidden = root?.querySelector('[data-character-field="exhaustionLevel"]');
      if (!hidden) return;
      hidden.value = value;
      hidden.dispatchEvent(new Event("input", { bubbles: true }));
      hidden.dispatchEvent(new Event("change", { bubbles: true }));
      root.querySelector("[data-exhaustion-menu-v75]")?.classList.add("hidden");
    });
  });
}
const bindCharacterCreatorEventsV75Base = bindCharacterCreatorEvents;
bindCharacterCreatorEvents = function() {
  bindCharacterCreatorEventsV75Base();
  bindCharacterStableInteractionGuardsV75();
  bindCharacterExhaustionPickerV75();
};


