function ensureCharacterSpellBoxesV577() {
  if (!characterState) characterState = createDefaultCharacter();
  characterState.selectedSpellsByLevel = { ...createDefaultSelectedSpellsByLevel(), ...(characterState.selectedSpellsByLevel || {}) };
  characterState.spellExtraBoxesByLevel = characterState.spellExtraBoxesByLevel && typeof characterState.spellExtraBoxesByLevel === "object" ? characterState.spellExtraBoxesByLevel : {};
  CHARACTER_SPELL_LEVEL_OPTIONS.forEach(option => {
    const key = String(option.value);
    characterState.selectedSpellsByLevel[key] = String(characterState.selectedSpellsByLevel[key] || "");
    characterState.spellExtraBoxesByLevel[key] = Array.isArray(characterState.spellExtraBoxesByLevel[key]) ? characterState.spellExtraBoxesByLevel[key].map(value => String(value || "")) : [];
  });
}

function getCharacterSpellLevelLabelV577(level) {
  return String(level) === "0" ? "Cantrips" : `Level ${level}`;
}

function getCharacterMaxSpellLevelForEntryV577(entry) {
  const klass = normalizeSearchText(entry.className || "");
  const subclass = normalizeSearchText(entry.subclass || "");
  const level = Math.max(1, Math.min(20, Number(entry.level) || 1));
  const fullLevel = () => level >= 17 ? 9 : level >= 15 ? 8 : level >= 13 ? 7 : level >= 11 ? 6 : level >= 9 ? 5 : level >= 7 ? 4 : level >= 5 ? 3 : level >= 3 ? 2 : 1;
  if (CHARACTER_FULL_CASTERS_V573.has(klass)) return fullLevel();
  if (klass === "warlock") return level >= 9 ? 5 : level >= 7 ? 4 : level >= 5 ? 3 : level >= 3 ? 2 : 1;
  if (CHARACTER_HALF_CASTERS_V573.has(klass)) return level >= 17 ? 5 : level >= 13 ? 4 : level >= 9 ? 3 : level >= 5 ? 2 : level >= 2 ? 1 : 0;
  if (klass === "artificer") return level >= 17 ? 5 : level >= 13 ? 4 : level >= 9 ? 3 : level >= 5 ? 2 : 1;
  if ((klass === "fighter" && subclass.includes("eldritch knight")) || (klass === "rogue" && subclass.includes("arcane trickster"))) return level >= 19 ? 4 : level >= 13 ? 3 : level >= 7 ? 2 : level >= 3 ? 1 : 0;
  return 0;
}

function getCharacterAvailableSpellLevelsV577() {
  ensureCharacterSpellBoxesV577();
  const levels = new Set();
  const entries = typeof getCharacterSpellcastingEntriesV573 === "function" ? getCharacterSpellcastingEntriesV573() : [];
  if (entries.length || characterState.spellcastingAbility) levels.add("0");
  entries.forEach(entry => {
    const max = getCharacterMaxSpellLevelForEntryV577(entry);
    if (max > 0) levels.add("0");
    for (let level = 1; level <= max; level += 1) levels.add(String(level));
  });
  const data = typeof getCharacterCasterDataV573 === "function" ? getCharacterCasterDataV573() : { slots: [] };
  (data.slots || []).forEach((count, index) => { if (count > 0) levels.add(String(index + 1)); });
  getCharacterAutoGrantedSpellsV577().forEach(item => levels.add(String(item.level)));
  return [...levels].sort((a, b) => Number(a) - Number(b));
}

function getCharacterAutoGrantedSpellsV577() {
  const entries = typeof getCharacterSpellcastingEntriesV573 === "function" ? getCharacterSpellcastingEntriesV573() : [];
  const spells = [];
  entries.forEach(entry => {
    const subclassKey = normalizeSearchText(entry.subclass || "");
    const grants = CHARACTER_SUBCLASS_GRANTED_SPELLS_V577[subclassKey] || [];
    const classLevel = Math.max(1, Math.min(20, Number(entry.level) || 1));
    grants.forEach(grant => {
      if (classLevel >= Number(grant.unlock || 1)) {
        spells.push({ ...grant, source: entry.subclass || entry.className || "Subclass", className: entry.className || "" });
      }
    });
  });
  return spells;
}

function getCharacterSpellOptionsForLevelV577(level) {
  const target = Number(level) || 0;
  const entries = typeof getCharacterSpellcastingEntriesV573 === "function" ? getCharacterSpellcastingEntriesV573() : [];
  const classKeys = new Set(entries.map(entry => normalizeSearchText(entry.className || "")).filter(Boolean));
  const options = new Map();
  const addOption = (spell, source = "Class List") => {
    const name = String(spell || "").trim();
    if (!name) return;
    const key = normalizeSearchText(name);
    if (!options.has(key)) options.set(key, { value: name, label: name, note: source, iconKey: "sigil-custom" });
  };
  if (target === 0) {
    classKeys.forEach(classKey => (CHARACTER_CANTRIP_LISTS_V577[classKey] || []).forEach(spell => addOption(spell, "Cantrip List")));
  }
  if (Array.isArray(window.spellsRebalanced)) {
    window.spellsRebalanced.forEach(spell => {
      if (Number(spell.level) !== target) return;
      const lists = Array.isArray(spell.classLists) ? spell.classLists : [];
      if (lists.some(name => classKeys.has(normalizeSearchText(name)))) addOption(spell.name, lists.join(", "));
    });
  } else if (typeof spellsRebalanced !== "undefined" && Array.isArray(spellsRebalanced)) {
    spellsRebalanced.forEach(spell => {
      if (Number(spell.level) !== target) return;
      const lists = Array.isArray(spell.classLists) ? spell.classLists : [];
      if (lists.some(name => classKeys.has(normalizeSearchText(name)))) addOption(spell.name, lists.join(", "));
    });
  }
  getCharacterAutoGrantedSpellsV577().filter(item => Number(item.level) === target).forEach(item => addOption(item.spell, `${item.source} granted`));
  return [...options.values()].sort((a, b) => a.label.localeCompare(b.label));
}

function renderCharacterGrantedSpellsForLevelV577(level) {
  const grants = getCharacterAutoGrantedSpellsV577().filter(item => String(item.level) === String(level));
  if (!grants.length) return "";
  return `<div class="character-granted-spells-v77" aria-label="Automatically granted spells">${grants.map(item => `<span class="character-granted-spell-v77"><strong>${escapeHTML(item.spell)}</strong><small>${escapeHTML(item.source)}</small></span>`).join("")}</div>`;
}

function renderCharacterSpellAddControlV577(level) {
  const options = getCharacterSpellOptionsForLevelV577(level);
  if (!options.length) return `<div class="character-no-spell-options-v77">No spells from the selected class/subclass list for this level in the app database.</div>`;
  return `<div class="character-spell-add-row-v77">${characterSelectField(`spellPick${level}`, "Class / Subclass Spell List", [{ value: "", label: "Choose spell" }, ...options], null, { value: "", customData: `data-spell-pick-v77="${escapeHTML(String(level))}"` })}<button class="character-spell-add-button-v77" type="button" data-add-spell-v77="${escapeHTML(String(level))}" title="Add selected spell">+</button></div>`;
}

function renderCharacterSpellTextBoxesV577(level) {
  ensureCharacterSpellBoxesV577();
  const key = String(level);
  const label = getCharacterSpellLevelLabelV577(key);
  const extras = characterState.spellExtraBoxesByLevel[key] || [];
  const boxes = [`<div class="character-spell-box-v77"><div class="character-spell-box-v77__head"><span>${escapeHTML(label)} Box 1</span></div><textarea data-selected-spells-level="${escapeHTML(key)}" rows="4" placeholder="Add selected ${escapeHTML(label.toLowerCase())}, one spell per line.">${escapeHTML(characterState.selectedSpellsByLevel[key] || "")}</textarea></div>`]
    .concat(extras.map((value, index) => `<div class="character-spell-box-v77"><div class="character-spell-box-v77__head"><span>${escapeHTML(label)} Box ${index + 2}</span><button class="character-spell-box-remove-v77" type="button" data-remove-spell-box-v77="${escapeHTML(key)}" data-spell-box-index-v77="${index}">Remove</button></div><textarea data-spell-extra-level-v77="${escapeHTML(key)}" data-spell-extra-index-v77="${index}" rows="4" placeholder="Extra ${escapeHTML(label.toLowerCase())} notes.">${escapeHTML(value || "")}</textarea></div>`));
  return `<div class="character-spell-box-list-v77">${boxes.join("")}<button class="character-spell-box-add-v77" type="button" data-add-spell-box-v77="${escapeHTML(key)}">+ Add Text Box</button></div>`;
}

function renderCharacterSpellLevelPanelsV577() {
  ensureCharacterSpellBoxesV577();
  const levels = getCharacterAvailableSpellLevelsV577();
  if (!levels.length) return `<div class="character-no-slots">Choose a spellcasting class, subclass, or spellcasting ability to show spell-level fields.</div>`;
  return `<div class="character-spellbook-levels-v77">${levels.map(level => `<article class="character-spell-level-card-v77"><div class="character-spell-level-head-v77"><div class="character-spell-level-title-v77"><span>Spell Level</span><strong>${escapeHTML(getCharacterSpellLevelLabelV577(level))}</strong></div>${renderCharacterSpellAddControlV577(level)}</div>${renderCharacterGrantedSpellsForLevelV577(level)}${renderCharacterSpellTextBoxesV577(level)}</article>`).join("")}</div>`;
}

getSelectedSpellSummary = function() {
  ensureCharacterSpellBoxesV577();
  const levels = getCharacterAvailableSpellLevelsV577();
  const filled = levels.filter(level => String(characterState.selectedSpellsByLevel?.[level] || "").trim() || (characterState.spellExtraBoxesByLevel?.[level] || []).some(value => String(value || "").trim()) || getCharacterAutoGrantedSpellsV577().some(item => String(item.level) === String(level))).length;
  return `${filled}/${levels.length || 0} available levels filled`;
};

renderCharacterSpellcastingPanelV573 = function() {
  ensureCharacterV573();
  ensureCharacterSpellBoxesV577();
  return `<section class="character-panel character-panel--spellcasting-v77"><div class="character-panel__heading"><h3>Spellcasting</h3><span>Save DC ${getSpellSaveDc()} · Attack ${getSpellAttackBonus()}</span></div><div class="character-spell-total-row">${characterSelectField("spellcastingAbility", "Spellcasting Ability", [{ value: "", label: "None" }, ...CHARACTER_ABILITIES.map(ability => ({ value: ability.key, label: ability.label }))], null)}${renderCharacterSpellBonusStepperV573("spellSaveBonus", "Spell Save DC", getSpellSaveDc())}${renderCharacterSpellBonusStepperV573("spellAttackBonus", "Spell Attack Bonus", getSpellAttackBonus())}</div>${renderCharacterCasterSummaryV573()}${renderCharacterSpellSlotCheckboxesV573()}${renderCharacterSpellLevelPanelsV577()}<details class="character-spellcasting-legacy-v77"><summary>Legacy freeform spell notes</summary><div class="character-grid character-grid--textareas character-grid--spell-notes">${characterTextarea("cantrips", "Cantrips / Always Prepared")}${characterTextarea("preparedSpells", "Prepared Spells Notes")}${characterTextarea("spellbook", "Spellbook / Known Spells Notes")}</div></details></section>`;
};

function addCharacterSpellToLevelV577(level, spellName) {
  ensureCharacterSpellBoxesV577();
  const key = String(level);
  const clean = String(spellName || "").trim();
  if (!clean) { showToast("Choose a spell first."); return; }
  const lines = String(characterState.selectedSpellsByLevel[key] || "").split(/\n+/).map(line => line.trim()).filter(Boolean);
  if (!lines.some(line => normalizeSearchText(line) === normalizeSearchText(clean))) lines.push(clean);
  characterState.selectedSpellsByLevel[key] = lines.join("\n");
  saveCharacterState();
  renderCharacterCreator();
  showToast(`${clean} added to ${getCharacterSpellLevelLabelV577(key)}.`);
}

const collectCharacterFormV577Base = collectCharacterForm;
collectCharacterForm = function() {
  collectCharacterFormV577Base();
  ensureCharacterSpellBoxesV577();
  if (!els.characterSheet) return;
  els.characterSheet.querySelectorAll("[data-spell-extra-level-v77]").forEach(input => {
    const level = String(input.dataset.spellExtraLevelV77);
    const index = Number(input.dataset.spellExtraIndexV77) || 0;
    characterState.spellExtraBoxesByLevel[level] = characterState.spellExtraBoxesByLevel[level] || [];
    characterState.spellExtraBoxesByLevel[level][index] = input.value;
  });
};

const bindCharacterCreatorEventsV577Base = bindCharacterCreatorEvents;
bindCharacterCreatorEvents = function() {
  bindCharacterCreatorEventsV577Base();
  if (!els.characterSheet || !characterState) return;
  els.characterSheet.querySelectorAll("[data-add-spell-v77]").forEach(button => {
    if (button.dataset.boundV77 === "true") return;
    button.dataset.boundV77 = "true";
    button.addEventListener("click", event => {
      event.preventDefault();
      const level = String(button.dataset.addSpellV77);
      const picker = els.characterSheet.querySelector(`[data-spell-pick-v77="${level}"]`);
      addCharacterSpellToLevelV577(level, picker?.value || "");
    });
  });
  els.characterSheet.querySelectorAll("[data-add-spell-box-v77]").forEach(button => {
    if (button.dataset.boundV77 === "true") return;
    button.dataset.boundV77 = "true";
    button.addEventListener("click", event => {
      event.preventDefault();
      ensureCharacterSpellBoxesV577();
      const level = String(button.dataset.addSpellBoxV77);
      characterState.spellExtraBoxesByLevel[level] = characterState.spellExtraBoxesByLevel[level] || [];
      characterState.spellExtraBoxesByLevel[level].push("");
      saveCharacterState();
      renderCharacterCreator();
    });
  });
  els.characterSheet.querySelectorAll("[data-remove-spell-box-v77]").forEach(button => {
    if (button.dataset.boundV77 === "true") return;
    button.dataset.boundV77 = "true";
    button.addEventListener("click", event => {
      event.preventDefault();
      ensureCharacterSpellBoxesV577();
      const level = String(button.dataset.removeSpellBoxV77);
      const index = Number(button.dataset.spellBoxIndexV77) || 0;
      characterState.spellExtraBoxesByLevel[level] = (characterState.spellExtraBoxesByLevel[level] || []).filter((_, itemIndex) => itemIndex !== index);
      saveCharacterState();
      renderCharacterCreator();
    });
  });
  els.characterSheet.querySelectorAll("[data-spell-extra-level-v77]").forEach(input => {
    if (input.dataset.boundV77 === "true") return;
    input.dataset.boundV77 = "true";
    input.addEventListener("input", () => {
      ensureCharacterSpellBoxesV577();
      const level = String(input.dataset.spellExtraLevelV77);
      const index = Number(input.dataset.spellExtraIndexV77) || 0;
      characterState.spellExtraBoxesByLevel[level] = characterState.spellExtraBoxesByLevel[level] || [];
      characterState.spellExtraBoxesByLevel[level][index] = input.value;
      saveCharacterState();
    });
  });
};



