function characterBenefitCardV578(kicker, title, text, tone = "feature") {
  return `<div class="character-benefit-card-v78" data-tone="${escapeHTML(tone)}"><span class="character-benefit-kicker-v78">${escapeHTML(kicker)}</span><strong>${escapeHTML(title || "None")}</strong><p>${escapeHTML(text || "No extra detail listed.")}</p></div>`;
}
function characterBenefitSummaryCardV578(title, text) {
  return `<div class="character-benefit-card-v78 character-benefit-card-v78--wide" data-tone="source"><span class="character-benefit-kicker-v78">Summary</span><strong>${escapeHTML(title || "Notes")}</strong><p>${escapeHTML(text || "Add table-specific notes in Features & Traits.")}</p></div>`;
}
function getRaceBenefitDataV578(option) {
  const name = option?.value || option?.label || characterState?.species || "Custom / Other";
  return CHARACTER_RACE_BENEFIT_DETAILS_V578[name] || CHARACTER_RACE_BENEFIT_DETAILS_V578[option?.label] || CHARACTER_RACE_BENEFIT_DETAILS_V578["Custom / Other"];
}
function getRaceFeaturesV578(option) {
  const detail = getRaceBenefitDataV578(option);
  const is2014 = getCharacterRulesVersion() === "2014";
  return is2014 ? (detail.features2014 || detail.features2024 || []) : (detail.features2024 || detail.features2014 || []);
}
function getRaceStatBenefitV578(option) {
  const detail = getRaceBenefitDataV578(option);
  if (getCharacterRulesVersion() === "2014") return detail.abilityScores2014 || "Source dependent";
  return "Species do not set ability scores by default in 2024; use Background ability score options.";
}

openCharacterSpeciesDetailsDialogV574 = function() {
  const option = getCurrentSpeciesOptionV574();
  if (!option || !characterState.species) { showToast(getCharacterRulesVersion() === "2014" ? "Choose a race first." : "Choose a species first."); return; }
  const label = getCharacterRulesVersion() === "2014" ? "Race" : "Species";
  const source = option.source || option.sourceEdition || "Custom";
  const data = getRaceBenefitDataV578(option);
  const features = getRaceFeaturesV578(option);
  const dialog = document.createElement("dialog");
  dialog.className = "dialog character-choice-details-dialog character-race-dialog character-benefit-dialog-v78";
  dialog.innerHTML = `<form method="dialog"><div class="dialog-title-row"><h2><span class="character-dialog-title-icon" ${getCharacterIconStyle(option.iconKey)}>${getCharacterIconSvg(option.iconKey, option.label)}</span>${escapeHTML(option.label || characterState.species)} ${label} ${getCharacterOptionSourceBadge(option)}</h2><button class="dialog-x-button" value="cancel" aria-label="Close">×</button></div><p class="character-benefit-intro-v78">${escapeHTML(data.intro || `Benefits granted by this ${label.toLowerCase()}.`)}</p><div class="character-benefit-grid-v78">${characterBenefitCardV578(getCharacterRulesVersion() === "2014" ? "2014 Stat Benefit" : "Ability Scores", getRaceStatBenefitV578(option), getCharacterRulesVersion() === "2014" ? "Apply this ability score increase according to the race/subrace option your table uses." : "In 2024, ability score increases normally come from Background, not Species.", "ability")}${characterBenefitCardV578("Source", source, getCharacterSourceFullName(source), "source")}${features.map(([title, text, tone]) => characterBenefitCardV578("Feature", title, text, tone || "feature")).join("")}${characterBenefitSummaryCardV578("How to use", "Treat these as concise play aids. Add exact subrace, lineage, or table-specific choices to Features & Traits if needed.")}</div><div class="dialog-actions"><button class="button" value="default">Close</button></div></form>`;
  document.body.append(dialog);
  dialog.addEventListener("close", () => dialog.remove());
  dialog.addEventListener("click", event => { if (event.target === dialog) dialog.close(); });
  dialog.showModal();
};

openCharacterBackgroundDetailsDialog = function() {
  const background = getCurrentBackgroundOption();
  if (!background || !characterState.background) { showToast("Choose a background first."); return; }
  const is2014 = getCharacterRulesVersion() === "2014";
  const sourceText = background.source || background.sourceEdition || "Custom";
  const feature = CHARACTER_BACKGROUND_FEATURES_2014_V578[background.value] || CHARACTER_BACKGROUND_FEATURES_2014_V578[background.label] || CHARACTER_BACKGROUND_FEATURES_2014_V578["Custom / Other"];
  const originTitle = is2014 ? "No Origin Feat" : (background.feat || "Origin Feat");
  const originText = is2014 ? "2014 backgrounds do not grant an Origin Feat by default unless your table adds one." : getCharacterOriginFeatDetail(background.feat);
  const dialog = document.createElement("dialog");
  dialog.className = "dialog character-background-dialog character-choice-details-dialog character-background-dialog--v576 character-benefit-dialog-v78";
  dialog.innerHTML = `<form method="dialog"><div class="dialog-title-row"><h2><span class="character-dialog-title-icon" ${getCharacterIconStyle(background.iconKey)}>${getCharacterIconSvg(background.iconKey, background.label)}</span>${escapeHTML(background.label)} Background ${getCharacterOptionSourceBadge(background)}</h2><button class="dialog-x-button" value="cancel" aria-label="Close">×</button></div><p class="character-benefit-intro-v78">${escapeHTML(is2014 ? "2014 backgrounds focus on skills, tools/languages, equipment, and a narrative feature." : "2024 backgrounds grant ability score options, skills, a tool proficiency, equipment, and an Origin Feat.")}</p><div class="character-benefit-grid-v78">${characterBenefitCardV578(is2014 ? "Origin Feat" : "Origin Feat", originTitle, originText, "origin")}${characterBenefitCardV578(is2014 ? "Ability Scores" : "Ability Score Options", background.abilities || "None", is2014 ? "2014 backgrounds normally do not grant ability score increases." : "Choose +2/+1 or +1/+1/+1 among these listed abilities.", "ability")}${characterBenefitCardV578("Skill Proficiencies", background.skills || "Custom", "Add these skills as proficient on the sheet if your DM uses this background as written.", "skill")}${characterBenefitCardV578("Tool / Language", background.tools || "Custom", "Add the listed tool or language proficiency to the Proficiencies section.", "tool")}${characterBenefitCardV578("Background Feature", is2014 ? feature[0] : (background.feat || "Origin Feat"), is2014 ? feature[1] : "The Origin Feat is the main mechanical feature granted by a 2024 background.", "feature")}${characterBenefitCardV578("Source Book", sourceText, getCharacterSourceFullName(sourceText), "source")}${characterBenefitSummaryCardV578("Background Summary", `Skills: ${background.skills || "Custom"}. Tool/Language: ${background.tools || "Custom"}. ${is2014 ? `Feature: ${feature[0]}.` : `Origin Feat: ${background.feat || "Custom"}.`}`)}</div><div class="dialog-actions"><button class="button" value="default">Close</button></div></form>`;
  document.body.append(dialog);
  dialog.addEventListener("close", () => dialog.remove());
  dialog.addEventListener("click", event => { if (event.target === dialog) dialog.close(); });
  dialog.showModal();
};

renderCharacterCombatPanelV573 = function(initiative) {
  const d20Penalty = getCharacterD20PenaltyV573();
  const effectiveSpeed = getCharacterEffectiveSpeedV573();
  const speedPenalty = getCharacterSpeedPenaltyV573();
  return `<section class="character-panel"><div class="character-panel__heading character-panel__heading--actions"><h3>Combat & Health</h3></div><div class="character-stat-strip"><div><span>AC</span><strong>${escapeHTML(characterState.armorClass || "10")}</strong></div><div><span>Initiative</span><strong>${formatSigned(initiative - d20Penalty)}</strong></div><div><span>Speed</span><strong>${effectiveSpeed} ft.${speedPenalty ? ` <small>(-${speedPenalty})</small>` : ""}</strong></div><div><span>HP</span><strong>${escapeHTML(characterState.currentHp || 0)} / ${escapeHTML(characterState.maxHp || 0)}</strong></div><div><span>Temp HP</span><strong>${escapeHTML(characterState.tempHp || 0)}</strong></div></div><div class="character-grid character-health-grid">${characterField("armorClass", "Armor Class", "number", "10")}${characterField("speed", "Base Speed", "number", "30")}${characterField("initiativeBonus", "Initiative Bonus", "number", "0")}${renderCharacterExhaustionFieldV575()}${renderCharacterMaxHpFieldV573()}${characterField("currentHp", "Current HP", "number", "0")}${characterField("tempHp", "Temp HP", "number", "0")}${renderCharacterHitDiceField()}${characterField("deathSaveSuccesses", "Death Save Successes", "number", "0", null, 0, 3)}${characterField("deathSaveFailures", "Death Save Failures", "number", "0", null, 0, 3)}</div>${getCharacterExhaustionSummaryV573()}<label class="character-checkbox character-checkbox--heroic"><input type="checkbox" data-character-field="heroicInspiration" ${characterState.heroicInspiration ? "checked" : ""}><span>Heroic Inspiration</span></label>${renderCharacterHpRollSummary()}</section>`;
};

init();



