  function getSelectedCharacterSpellSourcesV81(){ return typeof getSelectedCharacterMaterialSources === "function" ? getSelectedCharacterMaterialSources() : new Set(["5.5e PHB","5e PHB","XGE","TCE"]); }
  function getCharacterSpellSourcesV81(spell){ return Array.isArray(spell.sources) ? spell.sources : (spell.source ? [spell.source] : []); }
