  function h(value){ return typeof escapeHTML === "function" ? escapeHTML(value) : String(value ?? "").replace(/[&<>\"']/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c])); }
  function signed(n){ n = Number(n)||0; return n >= 0 ? `+${n}` : String(n); }
