    characterState.actionEconomy = { action:false, bonusAction:false, reaction:false, movement:false, freeObject:false, ...(characterState.actionEconomy || {}) };
    characterState.attackName ??= ""; characterState.attackAbility ??= "str"; characterState.attackProficient ??= true;
    characterState.attackAdvantage ??= "normal"; characterState.attackBonus ??= 0; characterState.damageDice ??= "1d8";
    characterState.damageAbility ??= ""; characterState.damageBonus ??= 0; characterState.damageType ??= "Slashing";
