    delete characterState.visibleChapters.abilities; delete characterState.visibleChapters.skills; delete characterState.visibleChapters.levelup; delete characterState.visibleChapters.prepared;
    characterState.actionEconomy = { action:false, bonusAction:false, reaction:false, movement:false, freeObject:false, ...(characterState.actionEconomy || {}) };
