    characterState.attackAdvantage ??= "normal"; characterState.attackBonus ??= 0; characterState.damageDice ??= "1d8";
    characterState.damageAbility ??= ""; characterState.damageBonus ??= 0; characterState.damageType ??= "Slashing";
