    { id:"prone", name:"Prone", category:"Official", roles:["Official","Movement","Defense"], mechanics:["Crawl","Melee Advantage","Ranged Disadvantage"], duration:"Until standing", intro:"The creature is lying on the ground.", summary:"Movement is limited; melee attackers gain advantage and ranged attackers usually have disadvantage.", rules:["Can crawl or stand up by spending movement.", "Melee attacks within 5 feet have advantage; farther attacks have disadvantage."] },
    { id:"restrained", name:"Restrained", category:"Official", roles:["Official","Control","Debuff"], mechanics:["Speed 0","Attack Disadvantage","Dex Save Disadvantage"], duration:"Varies", intro:"The creature is held back by bindings or force.", summary:"Speed 0; attacks suffer disadvantage; attacks against it have advantage; DEX saves have disadvantage.", rules:["Speed becomes 0.", "Attack rolls against it have advantage, and its attacks have disadvantage.", "Disadvantage on Dexterity saving throws."] },
    { id:"stunned", name:"Stunned", category:"Official", roles:["Official","Control"], mechanics:["Incapacitated","Auto-Fail Saves"], duration:"Varies", intro:"The creature is briefly overwhelmed.", summary:"Incapacitated, cannot move, speaks falteringly, and fails STR/DEX saves.", rules:["Incapacitated, cannot move, and can speak only falteringly.", "Automatically fails Strength and Dexterity saving throws.", "Attack rolls against it have advantage."] },
    { id:"unconscious", name:"Unconscious", category:"Official", roles:["Official","Control","Critical Setup"], mechanics:["Incapacitated","Prone","Auto-Fail Saves","Critical Hits"], duration:"Varies", intro:"The creature is unaware and helpless.", summary:"Incapacitated, prone, fails STR/DEX saves, and nearby hits are critical.", rules:["Incapacitated, cannot move or speak, and is unaware of surroundings.", "Drops what it is holding and falls prone.", "Automatically fails Strength and Dexterity saves; nearby hits are critical."] }
