    if (condition?.table && Array.isArray(condition.table)) return condition.table.map(row => ({ value:String(row[0]), label:String(row[0]) }));
    if ((condition?.roles || []).some(role => norm(role) === "tiered")) return ["I","II","III","IV","V","VI","VII","VIII"].map(x => ({value:x,label:x}));
    return [];
