      getCharacterAutoGrantedSpellsV577().filter(item => Number(item.level) === target).forEach(item => add(item.spell, item.source || 'Subclass', `${item.source || 'Subclass'} granted`, inferSpellMeta({name:item.spell}, metaMap)));
