      const key=norm(entry.className);
      const subInfo=subclassFeatureListFor(entry.subclass, entry.level);
      const subChips=subInfo.unlocked.length || subInfo.next ? `<div class="character-feature-chip-list-v91">${subInfo.unlocked.slice(-8).map(name=>`<span class="character-feature-chip-v91 character-feature-chip-v91--sub">${h(name)}</span>`).join('')}${subInfo.next?`<span class="character-feature-chip-v91 character-feature-chip-v91--next">Next Sub L${h(subInfo.next[0])}: ${h(subInfo.next[1])}</span>`:''}</div>` : '';
      return `<article class="character-feature-entry-v91"><div class="character-feature-entry-v91__head"><div><strong>${h(entry.className || 'Class')}${entry.subclass?` · ${h(entry.subclass)}`:''}</strong><small>${entry.primary?'Main class':'Multiclass'} · ${h(CLASS_NOTES[key] || 'Track the features granted by your class levels.')}</small></div><span class="character-feature-level-v91">Level ${h(entry.level)}</span></div><div class="character-feature-chip-list-v91">${info.unlocked.slice(-10).map(name=>`<span class="character-feature-chip-v91">${h(name)}</span>`).join('')}${info.next?`<span class="character-feature-chip-v91 character-feature-chip-v91--next">Next L${h(info.next[0])}: ${h(info.next[1])}</span>`:''}</div>${subChips}<p class="character-feature-note-v91"><span class="character-feature-chip-v91 character-feature-chip-v91--sub">Subclass</span> ${h(subclassNote(entry.subclass))}</p></article>`;
