    st.multiclasses[idx] = st.multiclasses[idx] || { className:'', subclass:'', level:1 };
    st.multiclasses[idx][key] = key === 'level' ? (Number(hidden.value) || 1) : hidden.value;
    if (key === 'className') st.multiclasses[idx].subclass = '';
