    const rogue=classLevel('rogue'); if(rogue) out.push(card('Sneak Attack', `${sneakDice(rogue)} · Rogue ${rogue}`, '', `<div class="character-tool-actions-v96"><button class="button button--ghost" type="button" data-v96-roll="sneak">Roll ${sneakDice(rogue)}</button><span class="character-tool-result-v96" data-v96-result="sneak">${h(getState()?.lastSneakAttackV96||'')}</span></div><div class="character-feature-pill-row-v96">${rogue>=2?pill('Cunning Action'):''}${rogue>=5?pill('Uncanny Dodge'):''}${rogue>=7?pill('Evasion'):''}</div>`));
