    const war=classLevel('warlock'); if(war){ const pact=pactMagic(war); out.push(card('Pact Magic', `${pact.slots} slot${pact.slots===1?'':'s'} · Slot Level ${pact.slotLevel} · Warlock ${war}`, boxes('pactSlots', pact.slots, 'Pact Magic slots'), `<div class="character-feature-pill-row-v96">${pill('Eldritch Invocations')}${mysticArcanum(war).map(x=>pill(`${x} Arcanum`)).join('')}</div>`)); }
