    const sorc=classLevel('sorcerer'); if(hasSub('sorcerer','wild magic') && sorc>=1){ out.push(`<article class="character-subclass-tool-v96"><h5>Wild Magic Surge</h5><small>Roll d100, then use the result with your chosen Wild Magic Surge source table.</small><div class="character-tool-actions-v96"><button class="button button--ghost" type="button" data-v96-roll="wild">Roll d100</button><span class="character-tool-result-v96" data-v96-result="wild">${h(getState()?.lastWildMagicV96||'No surge rolled.')}</span></div>${wildTable()}</article>`); }
    const wiz=classLevel('wizard'); if(hasSub('wizard','divin') && wiz>=2){ const count=wiz>=14?3:2; out.push(`<article class="character-subclass-tool-v96"><h5>Portent</h5><small>${count} d20 rolls to record after a long rest.</small>${boxes('portentDice',count,'Portent dice')}<div class="character-tool-actions-v96"><button class="button button--ghost" type="button" data-v96-roll="portent">Roll Portents</button><span class="character-tool-result-v96" data-v96-result="portent">${h(getState()?.lastPortentV96||'')}</span></div></article>`); }
    if(hasSub('wizard','abjur') && wiz>=2){ out.push(`<article class="character-subclass-tool-v96"><h5>Arcane Ward</h5><small>Ward HP estimate: ${Math.max(0,wiz*2+abilityMod('intelligence'))}.</small><div class="character-feature-pill-row-v96">${pill('2 × Wizard level + INT mod','character-feature-pill-v96--sub')}</div></article>`); }
    const rogue=classLevel('rogue'); if(hasSub('rogue','soulknife') && rogue>=3){ out.push(`<article class="character-subclass-tool-v96"><h5>Soulknife</h5><small>Psionic Energy dice pool shown from proficiency bonus.</small>${boxes('soulknifeDice',pb()*2,'Soulknife Psionic Energy dice')}<div class="character-feature-pill-row-v96">${pill('Psychic Blades','character-feature-pill-v96--sub')}</div></article>`); }
