  function withPanel(fn){ return function(){ const out=fn.apply(this,arguments); try{ enhancePanel(); }catch(e){ console.error('V96 class feature panel failed',e); } return out; }; }
  const base=typeof window.renderCharacterCreator==='function'?window.renderCharacterCreator:(typeof renderCharacterCreator==='function'?renderCharacterCreator:null);
  if(base && !base.__v96ClassFeaturePanel){ const wrapped=withPanel(base); wrapped.__v96ClassFeaturePanel=true; try{ window.renderCharacterCreator=wrapped; renderCharacterCreator=wrapped; }catch(_){ window.renderCharacterCreator=wrapped; } }
  document.addEventListener('change',function(event){ const input=event.target.closest?.('#characterSheet [data-v96-resource]'); if(!input) return; const st=getState(); if(!st) return; const state=resourceState(); const key=input.dataset.v96Resource; const idx=Number(input.dataset.v96Index)||0; state[key]=Array.isArray(state[key])?state[key]:[]; state[key][idx]=input.checked; save(); },true);
  document.addEventListener('click',function(event){ const btn=event.target.closest?.('#characterSheet [data-v96-roll]'); if(!btn) return; event.preventDefault(); event.stopPropagation(); const st=getState(); if(!st) return; const type=btn.dataset.v96Roll; let text=''; if(type==='sneak'){ const r=rollFormula(sneakDice(classLevel('rogue'))); text=`${r.total} (${r.detail})`; st.lastSneakAttackV96=text; }
    if(type==='superiority'){ const bm=bmDice(classLevel('fighter')); const r=rollFormula(bm?bm.die:'1d8'); text=`${r.total} (${r.detail})`; st.lastSuperiorityV96=text; }
    if(type==='wild'){ const roll=rollDie(100); const band=Math.ceil(roll/10)*10; text=`d100 ${String(roll).padStart(2,'0')} · ${band-9}-${band===100?'00':band} band`; st.lastWildMagicV96=text; }
    if(type==='portent'){ const count=classLevel('wizard')>=14?3:2; const rolls=Array.from({length:count},()=>rollDie(20)); text=rolls.join(', '); st.lastPortentV96=text; }
    save(); const result=document.querySelector(`#characterSheet [data-v96-result="${CSS.escape(type)}"]`); if(result) result.textContent=text; },true);
