  function addHistory(title,total,detail){ const item={t:Date.now(),title:String(title||'Roll'),total:String(total||''),detail:String(detail||'').replace(/\s+/g,' ').slice(0,160)}; const list=[item,...loadHistory()].slice(0,12); saveHistory(list); renderHistory(); }
  function renderHistory(){ const tray=document.querySelector('#characterDiceTrayV102 .character-dice-tray-v102'); if(!tray) return; let box=tray.querySelector('#characterRollHistoryV114'); if(!box){ tray.insertAdjacentHTML('beforeend','<div class="character-roll-history-v114" id="characterRollHistoryV114"><div class="character-roll-history-v114__head"><span>Roll History</span><button class="button button--ghost" type="button" data-v114-history-clear>Clear</button></div><div class="character-roll-history-v114__list"></div></div>'); box=tray.querySelector('#characterRollHistoryV114'); } const list=loadHistory(); const target=box.querySelector('.character-roll-history-v114__list'); target.innerHTML=list.length?list.map(i=>`<div class="character-roll-history-v114__item"><strong>${esc(i.total)}</strong><span>${esc(i.title)}</span><small>${esc(new Date(i.t).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}))}</small></div>`).join(''):'<div class="character-roll-history-v114__item"><span>No rolls yet.</span></div>'; }
  function presetStrip(){ const tray=document.querySelector('#characterDiceTrayV102 .character-dice-tray-v102'); if(!tray||tray.querySelector('#characterDicePresetsV114')) return; const explain=tray.querySelector('[data-v102-explain]'); const html='<div class="character-dice-presets-v114" id="characterDicePresetsV114"><button class="character-dice-preset-v114" data-v114-dice-preset="attack">Attack</button><button class="character-dice-preset-v114" data-v114-dice-preset="damage">Damage</button><button class="character-dice-preset-v114" data-v114-dice-preset="skill">Skill</button><button class="character-dice-preset-v114" data-v114-dice-preset="save">Save</button><button class="character-dice-preset-v114" data-v114-dice-preset="hp">HP</button><button class="character-dice-preset-v114" data-v114-dice-preset="hitdice">Hit Dice</button></div>'; if(explain) explain.insertAdjacentHTML('afterend',html); }
