  function openPreset(type){ const map={attack:'#characterRollAttackV82',damage:'#characterRollDamageV82',hp:'#characterHpRollerButton',hitdice:'#characterHitDiceSpendButton'}; const sel=map[type]; const tray=document.getElementById('characterDiceTrayV102'); if(tray) tray.classList.remove('is-visible'); setTimeout(()=>{ if(sel && document.querySelector(sel)){ document.querySelector(sel).click(); return; } if(type==='skill') genericPreset('Roll 1d20 skill check'); else if(type==='save') genericPreset('Roll 1d20 saving throw'); },40); }
  let resultWatchBound=false,lastResultSig='';
  function patchDiceTray(){ const tray=document.querySelector('#characterDiceTrayV102 .character-dice-tray-v102'); if(!tray) return; presetStrip(); renderHistory(); if(resultWatchBound) return; const results=tray.querySelector('[data-v102-results]'); const total=tray.querySelector('[data-v102-total]'); const title=tray.querySelector('[data-v102-title]'); if(results){ new MutationObserver(()=>{ const sig=(total?.textContent||'')+'|'+(results.textContent||''); if(!/Total\s+\d+/i.test(total?.textContent||'') || !results.textContent.trim() || sig===lastResultSig) return; lastResultSig=sig; addHistory(title?.textContent||'Roll',total?.textContent||'',results.textContent||''); }).observe(results,{childList:true,subtree:true,characterData:true}); resultWatchBound=true; } }
