  if(baseRender && !baseRender.__v114TablePolish){ const wrapped=function(){ const out=baseRender.apply(this,arguments); setTimeout(postProcess,0); return out; }; wrapped.__v114TablePolish=true; try{ window.renderCharacterCreator=wrapped; renderCharacterCreator=wrapped; }catch(_){ window.renderCharacterCreator=wrapped; } }
  document.addEventListener('input',e=>{ const g=e.target.closest?.('[data-v114-feature-group]'); if(g&&cs()){ featureGroups()[g.dataset.v114FeatureGroup]=g.value; save(); return; } const lf=e.target.closest?.('[data-v114-limited-field]'); if(lf&&cs()){ const row=lf.closest('[data-v114-limited-row]'); const item=limitedUses()[Number(row?.dataset.v114LimitedRow)]; if(item){ const key=lf.dataset.v114LimitedField; item[key]=/current|max/.test(key)?Math.max(0,Number(lf.value)||0):lf.value; save(); } } },true);
  document.addEventListener('change',e=>{ const lf=e.target.closest?.('[data-v114-limited-field]'); if(lf&&cs()){ const row=lf.closest('[data-v114-limited-row]'); const item=limitedUses()[Number(row?.dataset.v114LimitedRow)]; if(item){ const key=lf.dataset.v114LimitedField; item[key]=/current|max/.test(key)?Math.max(0,Number(lf.value)||0):lf.value; save(); } } },true);
  document.addEventListener('click',e=>{ if(e.target.closest?.('[data-v114-limited-add]')){ e.preventDefault(); limitedUses().push({name:'New Feature',current:0,max:1,reset:'Long Rest'}); save(); try{renderCharacterCreator();}catch(_){postProcess();} return; } const row=e.target.closest?.('[data-v114-limited-row]'); if(row&&e.target.closest?.('[data-v114-limited-remove]')){ e.preventDefault(); limitedUses().splice(Number(row.dataset.v114LimitedRow),1); save(); try{renderCharacterCreator();}catch(_){postProcess();} return; } if(row&&e.target.closest?.('[data-v114-limited-step]')){ e.preventDefault(); const item=limitedUses()[Number(row.dataset.v114LimitedRow)]; if(item){ const step=Number(e.target.closest('[data-v114-limited-step]').dataset.v114LimitedStep)||0; item.current=Math.max(0,Math.min(Number(item.max)||99,(Number(item.current)||0)+step)); save(); try{renderCharacterCreator();}catch(_){postProcess();} } return; } if(e.target.closest?.('[data-v114-attack-edit]')){ e.preventDefault(); e.target.closest('.v114-attack-card')?.classList.toggle('is-editing'); return; } if(e.target.closest?.('[data-v114-spell-toggle]')){ e.preventDefault(); const card=e.target.closest('.character-spell-level-card-v77'); card?.classList.toggle('is-expanded'); e.target.textContent=card?.classList.contains('is-expanded')?'Hide':'Details'; return; } const preset=e.target.closest?.('[data-v114-dice-preset]'); if(preset){ e.preventDefault(); openPreset(preset.dataset.v114DicePreset); return; } if(e.target.closest?.('[data-v114-history-clear]')){ e.preventDefault(); saveHistory([]); renderHistory(); return; } },true);
  function boot(){ postProcess(); setTimeout(postProcess,400); setTimeout(postProcess,1200); }
